const COUNTRY_NAME_FALLBACKS = Object.freeze((() => {
  const entries = {};
  for (const meta of Object.values(CF_COLO_META)) {
    const code = String(meta?.countryCode || "").trim().toUpperCase();
    const name = String(meta?.countryName || "").trim();
    if (!code || !name || entries[code]) continue;
    entries[code] = name;
  }
  entries.CN = entries.CN || "中国";
  entries.HK = entries.HK || "中国香港";
  entries.MO = entries.MO || "中国澳门";
  entries.TW = entries.TW || "中国台湾";
  return entries;
})());
let countryDisplayNamesZhCn = null;

function isValidIpv4Address(value = "") {
  const text = String(value || "").trim();
  if (!text || !/^(?:\d{1,3}\.){3}\d{1,3}$/.test(text)) return false;
  const parts = text.split(".");
  return parts.length === 4 && parts.every(part => {
    const num = Number(part);
    return Number.isInteger(num) && num >= 0 && num <= 255;
  });
}

function isPrivateIpv4Address(value = "") {
  if (!isValidIpv4Address(value)) return false;
  const parts = String(value || "").trim().split(".").map(part => Number(part));
  const [first = 0, second = 0] = parts;
  if (first === 10 || first === 127) return true;
  if (first === 169 && second === 254) return true;
  if (first === 172 && second >= 16 && second <= 31) return true;
  return first === 192 && second === 168;
}

function isValidIpv6Address(value = "") {
  const text = String(value || "").trim();
  if (!text || !text.includes(":") || /\s/.test(text)) return false;
  try {
    new URL(`http://[${text}]/`);
    return true;
  } catch {
    return false;
  }
}

function normalizeIpType(value = "") {
  if (String(value || "").trim().toUpperCase() === "IPV6") return "IPv6";
  return "IPv4";
}

function detectIpType(value = "") {
  if (isValidIpv6Address(value)) return "IPv6";
  return isValidIpv4Address(value) ? "IPv4" : "";
}

function extractIpListFromText(value = "", options = {}) {
  const text = String(value || "");
  const seen = new Set();
  const items = [];
  const limitValue = Number(options?.limit);
  const limit = Number.isFinite(limitValue) && limitValue > 0
    ? Math.max(1, Math.floor(limitValue))
    : Number.POSITIVE_INFINITY;
  const pushIp = (ip) => {
    const normalizedIp = String(ip || "").trim();
    if (!normalizedIp) return false;
    const type = detectIpType(normalizedIp);
    if (!type) return false;
    const key = normalizedIp.toLowerCase();
    if (seen.has(key)) return false;
    seen.add(key);
    items.push({ ip: normalizedIp, ipType: type });
    return items.length >= limit;
  };
  IP_TEXT_CANDIDATE_REGEX.lastIndex = 0;
  let match = null;
  while ((match = IP_TEXT_CANDIDATE_REGEX.exec(text)) !== null) {
    if (pushIp(match[0])) break;
  }
  return items;
}

function extractIpListFromDnsAnswers(payload = null) {
  const answers = Array.isArray(payload?.Answer) ? payload.Answer : [];
  const seen = new Set();
  const items = [];
  for (const answer of answers) {
    const ip = String(answer?.data || "").trim();
    const ipType = detectIpType(ip);
    if (!ipType) continue;
    const key = ip.toLowerCase();
    if (seen.has(key)) continue;
    seen.add(key);
    items.push({ ip, ipType });
  }
  return items;
}

function decodeHtmlCandidateEntities(value = "") {
  return String(value || "")
    .replace(/&nbsp;/gi, " ")
    .replace(/&amp;/gi, "&")
    .replace(/&lt;/gi, "<")
    .replace(/&gt;/gi, ">")
    .replace(/&quot;/gi, "\"")
    .replace(/&#39;/gi, "'");
}

function extractIpAddressValuesFromText(text = "") {
  const candidates = new Map();
  const source = String(text || "");
  const bracketIpv6Matches = source.match(/\[[0-9a-f:]{2,}\]/gi) || [];
  for (const bracketValue of bracketIpv6Matches) {
    const normalized = String(bracketValue || "").replace(/^\[|\]$/g, "").trim();
    const ipType = detectIpType(normalized);
    if (!ipType) continue;
    candidates.set(normalized.toLowerCase(), normalized);
  }
  const matches = source.match(IP_TEXT_CANDIDATE_REGEX) || [];
  for (const rawMatch of matches) {
    const normalized = String(rawMatch || "").trim();
    const ipType = detectIpType(normalized);
    if (!ipType) continue;
    candidates.set(normalized.toLowerCase(), normalized);
  }
  return [...candidates.values()];
}

function normalizeDnsIpPoolCarrierFilterType(value = "") {
  const normalized = String(value || "").trim().toLowerCase();
  if (normalized === "联通") return "联通";
  if (normalized === "电信") return "电信";
  if (normalized === "移动") return "移动";
  if (normalized === "多线") return "多线";
  if (normalized === "ipv6") return "ipv6";
  return "";
}

function matchesDnsIpPoolCarrierFilter(lineLabel = "", requestedType = "") {
  const filterType = normalizeDnsIpPoolCarrierFilterType(requestedType);
  if (!filterType) return true;
  return String(lineLabel || "").trim().toLowerCase() === filterType.toLowerCase();
}

function extractStructuredDnsIpCandidatesFromCarrierHtml(text = "", requestedType = "") {
  const deduped = new Map();
  const addStructuredCandidate = (ipValue, lineLabel = "") => {
    const ip = String(ipValue || "").trim();
    const ipType = detectIpType(ip);
    if (!ipType || isPrivateIpv4Address(ip)) return;
    const key = ip.toLowerCase();
    const normalizedLineLabel = normalizeDnsIpPoolLineLabel(lineLabel);
    const existing = deduped.get(key);
    if (!existing) {
      deduped.set(key, { ip, ipType, lineLabel: normalizedLineLabel });
      return;
    }
    if (!normalizeDnsIpPoolLineLabel(existing?.lineLabel) && normalizedLineLabel) {
      deduped.set(key, { ...existing, lineLabel: normalizedLineLabel });
    }
  };
  const source = String(text || "");
  const rows = source.match(/<tr\b[^>]*>[\s\S]*?<\/tr>/gi) || [];
  for (const row of rows) {
    const cells = row.match(/<t[dh]\b[^>]*>[\s\S]*?<\/t[dh]>/gi) || [];
    if (cells.length < 3) continue;
    const lineLabel = decodeHtmlCandidateEntities(String(cells[1] || "").replace(/<[^>]+>/g, " "))
      .replace(/\s+/g, " ")
      .trim();
    if (!matchesDnsIpPoolCarrierFilter(lineLabel, requestedType)) continue;
    const ipCellText = decodeHtmlCandidateEntities(String(cells[2] || "").replace(/<[^>]+>/g, " "));
    const ip = extractIpAddressValuesFromText(ipCellText).find(candidate => detectIpType(candidate)) || "";
    if (!ip) continue;
    addStructuredCandidate(ip, lineLabel);
  }
  if (!deduped.size) {
    const visibleText = decodeHtmlCandidateEntities(source.replace(/<[^>]+>/g, "\n"));
    const regex = /(?:^|\n)\s*(?:\d+\s+)?(电信|联通|移动|多线|ipv6)\s+((?:(?:25[0-5]|2[0-4]\d|[01]?\d\d?)\.){3}(?:25[0-5]|2[0-4]\d|[01]?\d\d?)|(?:[a-f0-9]{1,4}:){2,}[a-f0-9:]{1,39})/gi;
    let match = null;
    while ((match = regex.exec(visibleText)) !== null) {
      if (!matchesDnsIpPoolCarrierFilter(match[1], requestedType)) continue;
      addStructuredCandidate(match[2], match[1]);
    }
  }
  return [...deduped.values()];
}

function extractDnsIpCandidatesFromTopListText(text = "", options = {}) {
  return extractIpListFromText(text, options);
}

function normalizeCfColoMeta(code = "") {
  const normalizedCode = String(code || "").trim().toUpperCase();
  const meta = CF_COLO_META[normalizedCode];
  if (!normalizedCode) {
    return {
      coloCode: "",
      cityName: "",
      countryCode: "UNKNOWN",
      countryName: "未知"
    };
  }
  if (!meta) {
    return {
      coloCode: normalizedCode,
      cityName: normalizedCode,
      countryCode: "UNKNOWN",
      countryName: "未知"
    };
  }
  return {
    coloCode: normalizedCode,
    cityName: String(meta.cityName || normalizedCode),
    countryCode: String(meta.countryCode || "UNKNOWN"),
    countryName: String(meta.countryName || "未知")
  };
}

function resolveCountryNameFromCode(code = "") {
  const normalizedCode = String(code || "").trim().toUpperCase();
  if (!normalizedCode || normalizedCode === "UNKNOWN") return "未知";
  if (COUNTRY_NAME_FALLBACKS[normalizedCode]) return COUNTRY_NAME_FALLBACKS[normalizedCode];
  try {
    if (countryDisplayNamesZhCn === null) {
      countryDisplayNamesZhCn = typeof Intl?.DisplayNames === "function"
        ? new Intl.DisplayNames(["zh-CN"], { type: "region" })
        : false;
    }
    if (countryDisplayNamesZhCn && typeof countryDisplayNamesZhCn.of === "function") {
      const localizedName = String(countryDisplayNamesZhCn.of(normalizedCode) || "").trim();
      if (localizedName) return localizedName;
    }
  } catch {}
  return normalizedCode;
}

function extractColoCodeFromCfRay(value = "") {
  const text = String(value || "").trim();
  if (!text) return "";
  const matched = text.match(/-([A-Za-z]{3,4})$/);
  return matched ? String(matched[1] || "").trim().toUpperCase() : "";
}

function getCorsHeadersForResponse(env, request, originOverride = null) {
  const reqOrigin = request.headers.get("Origin");
  const reqHeaders = request.headers.get("Access-Control-Request-Headers") || corsHeaders["Access-Control-Allow-Headers"];
  const allowOrigin = originOverride || reqOrigin || corsHeaders["Access-Control-Allow-Origin"];
  return {
    "Access-Control-Allow-Origin": allowOrigin,
    "Access-Control-Allow-Methods": corsHeaders["Access-Control-Allow-Methods"],
    "Access-Control-Allow-Headers": reqHeaders,
    "Access-Control-Expose-Headers": "Content-Length, Content-Range",
    "Access-Control-Max-Age": "86400"
  };
}

function safeDecodeSegment(segment = "") {
  if (!segment) return "";
  try { return decodeURIComponent(segment); } catch { return segment; }
}

function sanitizeProxyPath(path) {
  let raw = typeof path === "string" ? path : "/";
  if (!raw) return "/";
  if (!raw.startsWith("/")) raw = "/" + raw;
  raw = raw.replace(/^\/+/, "/");
  return raw;
}

function encodeBase64UrlUtf8(value = "") {
  const text = String(value || "");
  const bytes = new TextEncoder().encode(text);
  let binary = "";
  for (const byte of bytes) binary += String.fromCharCode(byte);
  return btoa(binary).replace(/\+/g, "-").replace(/\//g, "_").replace(/=+$/g, "");
}

function decodeBase64UrlUtf8(value = "") {
  const normalized = String(value || "").trim().replace(/-/g, "+").replace(/_/g, "/");
  if (!normalized) return "";
  const padding = normalized.length % 4;
  const padded = normalized + (padding ? "=".repeat(4 - padding) : "");
  const binary = atob(padded);
  const bytes = Uint8Array.from(binary, char => char.charCodeAt(0));
  return new TextDecoder().decode(bytes);
}

function normalizeAdminPath(value) {
  const fallback = "/admin";
  const raw = String(value || "").trim();
  if (!raw) return fallback;
  let normalized = sanitizeProxyPath(raw);
  normalized = normalized.replace(/\/{2,}/g, "/");
  if (normalized.length > 1) normalized = normalized.replace(/\/+$/, "");
  if (!normalized || normalized === "/" || normalized.toLowerCase().startsWith("/api")) return fallback;
  return normalized;
}

function pathnameMatchesPrefix(pathname, prefix) {
  const safePath = sanitizeProxyPath(pathname || "/");
  const safePrefix = sanitizeProxyPath(prefix || "/");
  return safePath === safePrefix || safePath.startsWith(safePrefix + "/");
}

function pathnameMatchesExactOrTrailingSlash(pathname, targetPath) {
  const safePath = sanitizeProxyPath(pathname || "/");
  const safeTargetPath = sanitizeProxyPath(targetPath || "/");
  if (!safeTargetPath || safeTargetPath === "/") return safePath === safeTargetPath;
  return safePath === safeTargetPath || safePath === `${safeTargetPath}/`;
}

function getAdminPath(env) {
  return normalizeAdminPath(env?.ADMIN_PATH);
}

function getAdminLoginPath(env) {
  const adminPath = getAdminPath(env);
  return adminPath === "/" ? "/login" : `${adminPath}/login`;
}

function getReservedNodeNameEntries(env) {
  const adminPath = getAdminPath(env);
  const normalizedAdminPath = sanitizeProxyPath(adminPath).toLowerCase();
  const entries = [];
  const segments = normalizedAdminPath.split("/").filter(Boolean).map(segment => safeDecodeSegment(segment).toLowerCase());
  if (segments.length === 1 && segments[0]) {
    entries.push({
      name: segments[0],
      reservedBy: adminPath,
      reason: "admin_path"
    });
  }
  if (normalizedAdminPath === "/admin") {
    entries.push({
      name: "api",
      reservedBy: "/api/auth/login",
      reason: "legacy_admin_login"
    });
  }
  return entries;
}

function getReservedNodeNameConflict(name, env) {
  const normalizedName = String(name || "").trim().toLowerCase();
  if (!normalizedName) return null;
  return getReservedNodeNameEntries(env).find(entry => entry.name === normalizedName) || null;
}

function isPersistableNodeInput(node = {}) {
  if (!String(node?.name || "").trim()) return false;
  if (String(node?.target || "").trim()) return true;
  return Array.isArray(node?.lines) && node.lines.length > 0;
}

function findReservedNodeNameConflict(nodes, env) {
  const list = Array.isArray(nodes) ? nodes : [nodes];
  for (const node of list) {
    if (!isPersistableNodeInput(node)) continue;
    if (isHostPrefixEntryMode(node?.entryMode)) continue;
    const conflict = getReservedNodeNameConflict(node?.name, env);
    if (!conflict) continue;
    return {
      ...conflict,
      name: String(node?.name || "").trim().toLowerCase()
    };
  }
  return null;
}

function getHostPrefixNodeValidationError(node = {}, env = null) {
  if (!isHostPrefixEntryMode(node?.entryMode)) return null;
  const name = String(node?.name || "").trim().toLowerCase();
  if (!name) {
    return {
      code: "HOST_PREFIX_REQUIRED",
      message: "域名前缀不能为空",
      name
    };
  }
  if (!isValidDnsLabelForHostPrefix(name)) {
    return {
      code: "HOST_PREFIX_INVALID",
      message: "域名前缀仅支持小写字母、数字、连字符，且不能以下划线、点或连字符结尾",
      name
    };
  }
  const legacyHostReservation = getLegacyHostPrefixReservation(env);
  if (legacyHostReservation && legacyHostReservation.name === name) {
    return {
      code: "HOST_PREFIX_RESERVED_BY_LEGACY_HOST",
      message: "该域名前缀已被旧部署子域兼容入口保留，请更换后重试",
      name,
      reservedBy: legacyHostReservation.reservedBy,
      reason: legacyHostReservation.reason,
      legacyHost: legacyHostReservation.legacyHost,
      host: legacyHostReservation.host
    };
  }
  return null;
}

function findHostPrefixNodeValidationError(nodes, env = null) {
  const list = Array.isArray(nodes) ? nodes : [nodes];
  for (const node of list) {
    if (!isPersistableNodeInput(node)) continue;
    const error = getHostPrefixNodeValidationError(node, env);
    if (error) return error;
  }
  return null;
}

function getAdminCookiePath(env) {
  const adminPath = getAdminPath(env);
  return adminPath === "/" ? "/" : adminPath;
}

function escapeHtml(value) {
  return String(value ?? "")
    .replace(/&/g, "&amp;")
    .replace(/</g, "&lt;")
    .replace(/>/g, "&gt;")
    .replace(/"/g, "&quot;")
    .replace(/'/g, "&#39;");
}

function serializeInlineJson(value) {
  return JSON.stringify(value)
    .replace(/</g, "\\u003c")
    .replace(/>/g, "\\u003e")
    .replace(/&/g, "\\u0026")
    .replace(/\u2028/g, "\\u2028")
    .replace(/\u2029/g, "\\u2029");
}

function buildInitHealth(env) {
  const missing = [];
  if (!env?.JWT_SECRET) missing.push("JWT_SECRET");
  if (!env?.ADMIN_PASS) missing.push("ADMIN_PASS");
  const adminPath = getAdminPath(env);
  const loginPath = getAdminLoginPath(env);
  return {
    ok: missing.length === 0,
    missing,
    adminPath,
    loginPath,
    message: missing.length
      ? `系统未初始化：缺少 ${missing.join("、")}。`
      : "系统初始化检查通过。"
  };
}

function warnInitHealthOnce(env) {
  const health = buildInitHealth(env);
  if (health.ok) return health;
  const fingerprint = health.missing.join("|") || "unknown";
  if (!GLOBALS.InitCheckWarnedFingerprints.has(fingerprint)) {
    GLOBALS.InitCheckWarnedFingerprints.add(fingerprint);
    console.warn(`[Init Check] ${health.message} 管理入口: ${health.adminPath}`);
  }
  return health;
}

function buildInitHealthBannerHtml(initHealth) {
  if (!initHealth || initHealth.ok) return "";
  const missingText = Array.isArray(initHealth.missing) && initHealth.missing.length
    ? initHealth.missing.map(item => `<code class="rounded bg-amber-100/80 px-1.5 py-0.5 text-[11px] font-semibold text-amber-700">${escapeHtml(item)}</code>`).join(" ")
    : `<code class="rounded bg-amber-100/80 px-1.5 py-0.5 text-[11px] font-semibold text-amber-700">UNKNOWN</code>`;
  return `<div id="init-health-banner" class="mx-4 mt-4 rounded-2xl border border-amber-200 bg-amber-50/95 px-4 py-3 text-sm text-amber-900 shadow-sm"><div class="flex flex-col gap-1 md:flex-row md:items-center md:justify-between"><div class="font-semibold">系统未初始化</div><div class="text-xs text-amber-700">管理入口：${escapeHtml(initHealth.adminPath || "/admin")}</div></div><p class="mt-2 leading-6">检测到关键环境变量缺失：${missingText}</p><p class="mt-1 text-xs leading-5 text-amber-700">请先在 Cloudflare Worker 环境变量中补齐后再使用管理台登录与敏感操作。</p></div>`;
}

function escapeSqlLike(value) {
  return String(value || "").replace(/[\\%_]/g, "\\$&");
}

function isLikelyIpAddress(value) {
  const text = String(value || "").trim();
  if (!text) return false;
  if (/^(?:\d{1,3}\.){3}\d{1,3}$/.test(text)) return true;
  return /^[0-9a-f:]+$/i.test(text) && text.includes(":");
}

function isLikelyColoCode(value) {
  const text = String(value || "").trim();
  if (!text) return false;
  return /^[a-z]{3,4}$/i.test(text);
}

function resolveRequestColoCode(request) {
  const text = String(request?.cf?.colo || "").trim().toUpperCase();
  return text || "UNKNOWN";
}

function resolveResponseColoCode(response) {
  const cfRay = String(response?.headers?.get?.("CF-RAY") || response?.headers?.get?.("cf-ray") || "").trim();
  return extractColoCodeFromCfRay(cfRay);
}

function resolveRequestCountryCode(request) {
  const text = String(request?.cf?.country || "").trim().toUpperCase();
  return text || "UNKNOWN";
}

function resolveRequestCountryMeta(request) {
  const countryCode = resolveRequestCountryCode(request);
  return {
    countryCode,
    countryName: resolveCountryNameFromCode(countryCode)
  };
}

function normalizeTargetBasePath(pathname = "/") {
  const safePath = sanitizeProxyPath(pathname || "/");
  if (safePath === "/") return "";
  return safePath.replace(/\/+$/, "");
}

/**
 * @param {any} targetInput
 * @returns {TargetRecord | null}
 */
function createTargetRecord(targetInput) {
  try {
    const targetUrl = targetInput instanceof URL ? targetInput : new URL(String(targetInput || ""));
    if (!["http:", "https:"].includes(targetUrl.protocol)) return null;
    const originText = String(targetUrl.origin || "").trim();
    if (!originText) return null;
    const normalizedBasePath = normalizeTargetBasePath(targetUrl.pathname);
    return {
      targetUrl,
      originText,
      normalizedBasePath,
      absoluteBasePrefix: `${originText}${normalizedBasePath}`
    };
  } catch {
    return null;
  }
}

function buildTargetRecordKey(targetRecord) {
  if (!isTargetRecord(targetRecord)) return "";
  return String(targetRecord.absoluteBasePrefix || targetRecord.originText || "").trim();
}

function buildOrderedTargetSignatureFromRecords(targetRecords = []) {
  const targetKeys = (Array.isArray(targetRecords) ? targetRecords : [])
    .map(record => buildTargetRecordKey(record))
    .filter(Boolean);
  return hashStableText(serializeConfigValue(targetKeys));
}

function countDistinctTargetRecordKeys(targetRecords = []) {
  return new Set(
    (Array.isArray(targetRecords) ? targetRecords : [])
      .map(record => buildTargetRecordKey(record))
      .filter(Boolean)
  ).size;
}

function normalizeHedgeProbePath(value = "", fallback = DEFAULT_HEDGE_PROBE_PATH) {
  const rawValue = String(value || fallback || "").trim() || String(fallback || "/emby/system/ping").trim() || "/emby/system/ping";
  try {
    const probeUrl = new URL(rawValue, "https://hedge-probe.invalid");
    return sanitizeProxyPath(probeUrl.pathname || "/");
  } catch {
    return sanitizeProxyPath(rawValue);
  }
}

function normalizeNodeHedgeProbePath(value = "") {
  const rawValue = String(value || "").trim();
  if (!rawValue) return "";
  return normalizeHedgeProbePath(rawValue, DEFAULT_HEDGE_PROBE_PATH);
}

function normalizeNodeLineHeadProbePath(value = "", fallback = DEFAULT_NODE_LINE_HEAD_PROBE_PATH) {
  const rawValue = String(value || fallback || "").trim() || String(fallback || DEFAULT_NODE_LINE_HEAD_PROBE_PATH).trim() || DEFAULT_NODE_LINE_HEAD_PROBE_PATH;
  try {
    const probeUrl = new URL(rawValue, "https://node-head-probe.invalid");
    return sanitizeProxyPath(probeUrl.pathname || "/");
  } catch {
    return sanitizeProxyPath(rawValue);
  }
}

/**
 * @param {any} candidate
 * @returns {candidate is TargetRecord}
 */
function isTargetRecord(candidate) {
  return !!candidate
    && typeof candidate === "object"
    && candidate.targetUrl instanceof URL
    && typeof candidate.originText === "string"
    && typeof candidate.normalizedBasePath === "string"
    && typeof candidate.absoluteBasePrefix === "string";
}

function normalizeSearchText(search = "") {
  const text = String(search || "");
  if (!text) return "";
  return text.startsWith("?") ? text : `?${text}`;
}

function shouldUseSegmentFastUpstreamBuilder(method = "GET", requestTraits = {}, options = {}) {
  const normalizedMethod = String(method || "GET").toUpperCase();
  if (normalizedMethod !== "GET" && normalizedMethod !== "HEAD") return false;
  if (requestTraits?.isSegment !== true) return false;
  if (requestTraits?.isWsUpgrade === true) return false;
  if (options.playbackRelayTargetUrl instanceof URL) return false;
  if (options.protocolFallbackRetry === true) return false;
  if (options.isExternalRedirect === true) return false;
  return true;
}

function normalizeNodeMediaAuthMode(value = "") {
  const normalized = String(value || "").trim().toLowerCase();
  if (normalized === "inherit") return "inherit";
  if (normalized === "emby") return "emby";
  if (normalized === "jellyfin") return "jellyfin";
  if (normalized === "passthrough") return "passthrough";
  return "auto";
}

function normalizeNodeRealClientIpMode(value = "") {
  const normalized = String(value || "").trim().toLowerCase();
  if (normalized === "inherit") return "inherit";
  if (normalized === "forward") return "forward";
  if (normalized === "strip") return "strip";
  if (normalized === "disable" || normalized === "none") return "disable";
  return "forward";
}

function normalizeNodePlaybackInfoMode(value = "") {
  const normalized = String(value || "").trim().toLowerCase();
  if (normalized === "inherit") return "inherit";
  if (normalized === "rewrite") return "rewrite";
  if (normalized === "passthrough") return "passthrough";
  return "inherit";
}

function normalizeNodeEntryMode(value = "") {
  return String(value || "").trim().toLowerCase() === "host_prefix"
    ? "host_prefix"
    : "kv_route";
}

function isHostPrefixEntryMode(value = "") {
  return normalizeNodeEntryMode(value) === "host_prefix";
}

function normalizeDefaultMediaAuthMode(value = "") {
  const normalized = String(value || "").trim().toLowerCase();
  if (normalized === "emby") return "emby";
  if (normalized === "jellyfin") return "jellyfin";
  if (normalized === "passthrough") return "passthrough";
  return "auto";
}

function normalizeDefaultPlaybackInfoMode(value = "") {
  return String(value || "").trim().toLowerCase() === "rewrite"
    ? "rewrite"
    : DEFAULT_PLAYBACK_INFO_MODE;
}

function normalizeDefaultRealClientIpMode(value = "") {
  const normalized = String(value || "").trim().toLowerCase();
  if (normalized === "strip") return "strip";
  if (normalized === "disable" || normalized === "none") return "disable";
  return "forward";
}

function normalizeScheduleUtcOffsetMinutes(value) {
  return clampIntegerConfig(value, Config.Defaults.ScheduleUtcOffsetMinutes, -12 * 60, 14 * 60);
}

function normalizeScheduleClockTime(value = "", fallback = "00:00") {
  const fallbackText = String(fallback || "00:00").trim() || "00:00";
  const text = String(value || "").trim();
  const matched = text.match(/^(\d{1,2}):(\d{1,2})$/);
  if (!matched) return fallbackText;
  const hour = Number(matched[1]);
  const minute = Number(matched[2]);
  if (!Number.isInteger(hour) || hour < 0 || hour > 23) return fallbackText;
  if (!Number.isInteger(minute) || minute < 0 || minute > 59) return fallbackText;
  return `${String(hour).padStart(2, "0")}:${String(minute).padStart(2, "0")}`;
}

function normalizeScheduleClockTimeList(value = [], fallback = []) {
  const rawValues = Array.isArray(value)
    ? value
    : String(value || "").split(/[\r\n,]+/);
  const result = [];
  const seen = new Set();
  for (const item of rawValues) {
    const normalized = normalizeScheduleClockTime(item, "");
    if (!normalized || seen.has(normalized)) continue;
    seen.add(normalized);
    result.push(normalized);
  }
  result.sort((left, right) => scheduleClockTimeToMinuteOfDay(left) - scheduleClockTimeToMinuteOfDay(right));
  if (result.length) return result;
  const fallbackValues = Array.isArray(fallback) ? fallback : [fallback];
  return [...new Set(fallbackValues
    .map(item => normalizeScheduleClockTime(item, ""))
    .filter(Boolean))]
    .sort((left, right) => scheduleClockTimeToMinuteOfDay(left) - scheduleClockTimeToMinuteOfDay(right));
}

function normalizeScheduleIntervalMinutes(value, fallback = 60) {
  return clampIntegerConfig(value, fallback, 1, 24 * 60);
}

function scheduleClockTimeToMinuteOfDay(clockTime = "") {
  const normalized = normalizeScheduleClockTime(clockTime, "");
  if (!normalized) return -1;
  const [hourText, minuteText] = normalized.split(":");
  return ((Number(hourText) || 0) * 60) + (Number(minuteText) || 0);
}

function splitScheduleSlotKey(slotKey = "") {
  const text = String(slotKey || "").trim();
  const matched = text.match(/^(\d{4}-\d{2}-\d{2})\s+(\d{2}:\d{2})$/);
  if (!matched) return { dateKey: "", clockTime: "" };
  return {
    dateKey: matched[1],
    clockTime: normalizeScheduleClockTime(matched[2], "")
  };
}

function buildScheduleLocalIsoFromShiftedDate(shiftedDate, utcOffsetMinutes = Config.Defaults.ScheduleUtcOffsetMinutes) {
  const offsetMinutes = normalizeScheduleUtcOffsetMinutes(utcOffsetMinutes);
  const year = shiftedDate.getUTCFullYear();
  const month = String(shiftedDate.getUTCMonth() + 1).padStart(2, "0");
  const day = String(shiftedDate.getUTCDate()).padStart(2, "0");
  const hour = String(shiftedDate.getUTCHours()).padStart(2, "0");
  const minute = String(shiftedDate.getUTCMinutes()).padStart(2, "0");
  const second = String(shiftedDate.getUTCSeconds()).padStart(2, "0");
  const millisecond = String(shiftedDate.getUTCMilliseconds()).padStart(3, "0");
  const sign = offsetMinutes >= 0 ? "+" : "-";
  const absoluteMinutes = Math.abs(offsetMinutes);
  const offsetHour = String(Math.floor(absoluteMinutes / 60)).padStart(2, "0");
  const offsetMinute = String(absoluteMinutes % 60).padStart(2, "0");
  return `${year}-${month}-${day}T${hour}:${minute}:${second}.${millisecond}${sign}${offsetHour}:${offsetMinute}`;
}

/**
 * @param {Date | number | string} [now]
 * @param {number} [utcOffsetMinutes]
 */
function buildScheduleLocalContext(now = new Date(), utcOffsetMinutes = Config.Defaults.ScheduleUtcOffsetMinutes) {
  const offsetMinutes = normalizeScheduleUtcOffsetMinutes(utcOffsetMinutes);
  const offsetMs = offsetMinutes * 60 * 1000;
  const baseDate = now instanceof Date ? new Date(now.getTime()) : new Date(now);
  const shiftedMs = baseDate.getTime() + offsetMs;
  const shiftedDate = new Date(shiftedMs);
  const year = shiftedDate.getUTCFullYear();
  const monthText = String(shiftedDate.getUTCMonth() + 1).padStart(2, "0");
  const dayText = String(shiftedDate.getUTCDate()).padStart(2, "0");
  const hourText = String(shiftedDate.getUTCHours()).padStart(2, "0");
  const minuteText = String(shiftedDate.getUTCMinutes()).padStart(2, "0");
  const secondText = String(shiftedDate.getUTCSeconds()).padStart(2, "0");
  const millisecondText = String(shiftedDate.getUTCMilliseconds()).padStart(3, "0");
  const hour = Number(hourText);
  const minute = Number(minuteText);
  return {
    now: baseDate,
    shiftedDate,
    utcOffsetMinutes: offsetMinutes,
    offsetLabel: formatUtcOffsetMinutesLabel(offsetMinutes),
    dateKey: `${year}-${monthText}-${dayText}`,
    clockTime: `${hourText}:${minuteText}`,
    hour,
    minute,
    second: Number(secondText),
    millisecond: Number(millisecondText),
    minuteOfDay: (hour * 60) + minute,
    localIso: buildScheduleLocalIsoFromShiftedDate(shiftedDate, offsetMinutes)
  };
}

function buildScheduleLocalIso(now = new Date(), utcOffsetMinutes = Config.Defaults.ScheduleUtcOffsetMinutes) {
  return buildScheduleLocalContext(now, utcOffsetMinutes).localIso;
}

/**
 * @param {Date | number | string} [now]
 * @param {number} [utcOffsetMinutes]
 */
function buildOffsetClockParts(now = new Date(), utcOffsetMinutes = Config.Defaults.ScheduleUtcOffsetMinutes) {
  return buildScheduleLocalContext(now, utcOffsetMinutes);
}

function buildOffsetDayWindow(now = new Date(), utcOffsetMinutes = Config.Defaults.ScheduleUtcOffsetMinutes, clockTime = "") {
  const context = buildScheduleLocalContext(now, utcOffsetMinutes);
  const normalizedClockTime = normalizeScheduleClockTime(clockTime || context.clockTime, context.clockTime);
  const plannedMinuteOfDay = scheduleClockTimeToMinuteOfDay(normalizedClockTime);
  const startTs = Date.UTC(
    context.shiftedDate.getUTCFullYear(),
    context.shiftedDate.getUTCMonth(),
    context.shiftedDate.getUTCDate()
  ) - context.utcOffsetMinutes * 60 * 1000;
  const endTs = startTs + 24 * 60 * 60 * 1000 - 1;
  const plannedTs = startTs + Math.max(0, plannedMinuteOfDay) * 60 * 1000;
  return {
    ...context,
    normalizedClockTime,
    plannedMinuteOfDay,
    plannedTs,
    plannedSlotKey: `${context.dateKey} ${normalizedClockTime}`,
    startTs,
    endTs
  };
}

function buildScheduleWindowContext(now = new Date(), utcOffsetMinutes = Config.Defaults.ScheduleUtcOffsetMinutes, startClockTime = "00:00", endClockTime = "23:59") {
  const context = buildScheduleLocalContext(now, utcOffsetMinutes);
  const normalizedStartClockTime = normalizeScheduleClockTime(startClockTime, "00:00");
  const normalizedEndClockTime = normalizeScheduleClockTime(endClockTime, "23:59");
  const startMinuteOfDay = Math.max(0, scheduleClockTimeToMinuteOfDay(normalizedStartClockTime));
  const endMinuteOfDay = Math.max(0, scheduleClockTimeToMinuteOfDay(normalizedEndClockTime));
  const crossesMidnight = startMinuteOfDay > endMinuteOfDay;
  const isWithinWindow = crossesMidnight
    ? (context.minuteOfDay >= startMinuteOfDay || context.minuteOfDay <= endMinuteOfDay)
    : (context.minuteOfDay >= startMinuteOfDay && context.minuteOfDay <= endMinuteOfDay);
  return {
    ...context,
    normalizedStartClockTime,
    normalizedEndClockTime,
    startMinuteOfDay,
    endMinuteOfDay,
    crossesMidnight,
    isWithinWindow
  };
}

function normalizeDnsIpSourceIpLimit(value) {
  return clampIntegerConfig(value, Config.Defaults.DnsIpSourceIpLimit, 1, 1000);
}

function normalizeNodeMainVideoStreamMode(value = "") {
  const normalized = String(value || "").trim().toLowerCase();
  if (normalized === "direct") return "direct";
  if (normalized === "proxy") return "proxy";
  return "inherit";
}

function readNodeMainVideoStreamMode(node = {}) {
  return normalizeNodeMainVideoStreamMode(node?.mainVideoStreamMode ?? node?.wangpanDirectMode ?? node?.wangpanMode);
}

const NODE_LEGACY_DIRECT_MODE_KEYS = ["proxyMode", "mode"];
const NODE_LEGACY_DIRECT_BOOLEAN_KEYS = ["direct", "sourceDirect", "directSource", "direct2xx"];
const NODE_LEGACY_METADATA_KEYS = ["wangpanMode", "videoThrottling", "interceptMs"];
const PLAYBACK_RELAY_SEGMENT = "__playback-relay";
const PLAYBACK_RELAY_QUERY_PARAM = "__pb_target";
const PLAYBACK_ABSOLUTE_FALLBACK_QUERY_PARAM = "__pb_abs";
const PLAYBACK_ABSOLUTE_FALLBACK_QUERY_VALUE = "1";
const PROXY_LINK_VARIANT_SEGMENTS = Object.freeze({
  main: "",
  proxy_a: "__proxy-a",
  proxy_b: "__proxy-b"
});
const NODE_LEGACY_FIELD_KEYS = [
  ...NODE_LEGACY_DIRECT_MODE_KEYS,
  ...NODE_LEGACY_DIRECT_BOOLEAN_KEYS,
  ...NODE_LEGACY_METADATA_KEYS
];

function collectLegacyNodeState(node = {}) {
  const rawNode = /** @type {Record<string, any>} */ (
    node && typeof node === "object" && !Array.isArray(node) ? node : {}
  );
  const legacyKeysPresent = [];
  let shouldAddToSourceDirectNodes = false;
  const topLevelPort = normalizePortText(rawNode.port);
  const linePortCount = Array.isArray(rawNode.lines)
    ? rawNode.lines.reduce((count, line) => count + (normalizePortText(line?.port) ? 1 : 0), 0)
    : 0;
  const defaultPortLineCount = Array.isArray(rawNode.lines) && rawNode.lines.length
    ? rawNode.lines.reduce((count, line) => {
      const linePort = normalizePortText(line?.port);
      if (linePort || topLevelPort) return count;
      return count + (targetNeedsDefaultPortCanonicalization(line?.target) ? 1 : 0);
    }, 0)
    : (
      topLevelPort
        ? 0
        : String(rawNode.target || "")
          .split(",")
          .map(item => item.trim())
          .filter(Boolean)
          .reduce((count, target) => count + (targetNeedsDefaultPortCanonicalization(target) ? 1 : 0), 0)
    );

  for (const key of NODE_LEGACY_DIRECT_MODE_KEYS) {
    if (!Object.prototype.hasOwnProperty.call(rawNode, key)) continue;
    legacyKeysPresent.push(key);
    const normalizedMode = String(rawNode[key] || "").trim().toLowerCase();
    if (["direct", "source-direct", "origin-direct", "node-direct"].includes(normalizedMode)) {
      shouldAddToSourceDirectNodes = true;
    }
  }

  for (const key of NODE_LEGACY_DIRECT_BOOLEAN_KEYS) {
    if (!Object.prototype.hasOwnProperty.call(rawNode, key)) continue;
    legacyKeysPresent.push(key);
    if (rawNode[key] === true) shouldAddToSourceDirectNodes = true;
  }

  for (const key of NODE_LEGACY_METADATA_KEYS) {
    if (!Object.prototype.hasOwnProperty.call(rawNode, key)) continue;
    legacyKeysPresent.push(key);
  }

  return {
    legacyKeysPresent: normalizeDistinctConfigKeyList(legacyKeysPresent),
    shouldAddToSourceDirectNodes,
    topLevelPortPresent: topLevelPort !== null && topLevelPort !== "",
    linePortCount,
    defaultPortNodePresent: defaultPortLineCount > 0,
    defaultPortLineCount
  };
}

function resolveNodeVideoStreamPolicy(node, currentConfig = {}) {
  const mode = readNodeMainVideoStreamMode(node);
  return {
    mode,
    forceVideoDirect: mode === "direct",
    forceVideoProxy: mode === "proxy"
  };
}

function resolveDefaultNodeMediaAuthMode(currentConfig = {}) {
  return normalizeDefaultMediaAuthMode(currentConfig?.defaultMediaAuthMode);
}

function resolveDefaultPlaybackInfoModeFromLegacyConfig(config = {}) {
  if (hasOwnConfigKey(config, "defaultPlaybackInfoMode")) {
    return normalizeDefaultPlaybackInfoMode(config?.defaultPlaybackInfoMode);
  }
  if (Reflect.get(config, "playbackInfoAutoProxy") !== undefined) {
    return Reflect.get(config, "playbackInfoAutoProxy") !== false ? "rewrite" : "passthrough";
  }
  if (Reflect.get(config, "playbackInfoBlockWangpanProxy") !== undefined) {
    return "rewrite";
  }
  return DEFAULT_PLAYBACK_INFO_MODE;
}

function resolveDefaultNodePlaybackInfoMode(currentConfig = {}) {
  return normalizeDefaultPlaybackInfoMode(resolveDefaultPlaybackInfoModeFromLegacyConfig(currentConfig));
}

function resolveDefaultNodeRealClientIpMode(currentConfig = {}) {
  return normalizeDefaultRealClientIpMode(currentConfig?.defaultRealClientIpMode);
}

function resolveEffectiveNodeMediaAuthMode(node = {}, currentConfig = {}) {
  const typedNode = /** @type {{ mediaAuthMode?: string }} */ (node || {});
  const hasNodeMode = !!node && typeof node === "object" && Object.prototype.hasOwnProperty.call(node, "mediaAuthMode");
  const nodeMode = hasNodeMode
    ? normalizeNodeMediaAuthMode(typedNode.mediaAuthMode)
    : "auto";
  return nodeMode === "inherit" ? resolveDefaultNodeMediaAuthMode(currentConfig) : nodeMode;
}

function resolveEffectiveNodePlaybackInfoMode(node = {}, currentConfig = {}) {
  const typedNode = /** @type {{ playbackInfoMode?: string }} */ (node || {});
  const hasNodeMode = !!node && typeof node === "object" && Object.prototype.hasOwnProperty.call(node, "playbackInfoMode");
  const nodeMode = hasNodeMode
    ? normalizeNodePlaybackInfoMode(typedNode.playbackInfoMode)
    : "inherit";
  return nodeMode === "inherit" ? resolveDefaultNodePlaybackInfoMode(currentConfig) : nodeMode;
}

function resolveEffectiveNodeRealClientIpMode(node = {}, currentConfig = {}) {
  const typedNode = /** @type {{ realClientIpMode?: string }} */ (node || {});
  const hasNodeMode = !!node && typeof node === "object" && Object.prototype.hasOwnProperty.call(node, "realClientIpMode");
  const nodeMode = hasNodeMode
    ? normalizeNodeRealClientIpMode(typedNode.realClientIpMode)
    : "forward";
  return nodeMode === "inherit" ? resolveDefaultNodeRealClientIpMode(currentConfig) : nodeMode;
}

function resolveEffectiveNodeHedgeProbePath(node = {}, currentConfig = {}) {
  const typedNode = /** @type {{ hedgeProbePath?: string }} */ (node || {});
  const hasNodeProbePath = !!node && typeof node === "object" && Object.prototype.hasOwnProperty.call(node, "hedgeProbePath");
  const nodeProbePath = hasNodeProbePath
    ? normalizeNodeHedgeProbePath(typedNode.hedgeProbePath)
    : "";
  return nodeProbePath || normalizeHedgeProbePath(currentConfig?.hedgeProbePath, DEFAULT_HEDGE_PROBE_PATH);
}

function getRealClientIpHeaderMode(modeOrNode) {
  const rawMode = typeof modeOrNode === "string"
    ? modeOrNode
    : modeOrNode?.realClientIpMode;
  const nodeMode = normalizeDefaultRealClientIpMode(rawMode);
  if (nodeMode === "forward") return "full";
  if (nodeMode === "strip") return "real-ip-only";
  if (nodeMode === "disable") return "none";
  return "full";
}

function createWorkerScriptQuickUpdateState() {
  return {
    fileName: "",
    scriptContent: "",
    fileSize: 0,
    syntax: "",
    submitting: false,
    error: "",
    uploadedFileName: "",
    uploadedSyntax: "",
    uploadedModifiedOn: "",
    uploadedEtag: "",
    uploadedHandlers: [],
    uploadedHasModules: false
  };
}

function normalizeProxyLinkVariant(value = "") {
  const normalized = String(value || "").trim().toLowerCase();
  if (normalized === "proxy_a" || normalized === "__proxy-a") return "proxy_a";
  if (normalized === "proxy_b" || normalized === "__proxy-b") return "proxy_b";
  return "main";
}

function getProxyLinkVariantSegment(linkVariant = "main") {
  const normalizedVariant = normalizeProxyLinkVariant(linkVariant);
  return PROXY_LINK_VARIANT_SEGMENTS[normalizedVariant] || "";
}

function parseProxyLinkVariantSegment(segment = "") {
  const normalized = String(segment || "").trim().toLowerCase();
  if (!normalized) return "main";
  if (normalized === PROXY_LINK_VARIANT_SEGMENTS.proxy_a) return "proxy_a";
  if (normalized === PROXY_LINK_VARIANT_SEGMENTS.proxy_b) return "proxy_b";
  return "main";
}

function consumeProxyLinkVariantPrefix(rawPath = "") {
  const text = String(rawPath || "");
  if (!text) {
    return {
      linkVariant: "main",
      remaining: "",
      needsTrailingSlashRedirect: false
    };
  }
  const withLeadingSlash = text.startsWith("/") ? text : ("/" + text);
  const pathParts = withLeadingSlash.split("/");
  const firstSegment = safeDecodeSegment(pathParts[1] || "");
  const linkVariant = parseProxyLinkVariantSegment(firstSegment);
  if (linkVariant === "main") {
    return {
      linkVariant,
      remaining: sanitizeProxyPath(withLeadingSlash),
      needsTrailingSlashRedirect: false
    };
  }
  const remaining = sanitizeProxyPath("/" + pathParts.slice(2).join("/"));
  return {
    linkVariant,
    remaining,
    needsTrailingSlashRedirect: pathParts.length === 2 && !withLeadingSlash.endsWith("/")
  };
}

// 保留节点 target 自带的子路径，避免 /node/foo 被错误拼到源站根目录。
function buildUpstreamProxyUrl(targetBase, proxyPath = "/") {
  const baseUrl = isTargetRecord(targetBase)
    ? new URL(targetBase.targetUrl.toString())
    : (targetBase instanceof URL ? new URL(targetBase.toString()) : new URL(String(targetBase || "")));
  const basePath = isTargetRecord(targetBase)
    ? targetBase.normalizedBasePath
    : normalizeTargetBasePath(baseUrl.pathname);
  const safeProxyPath = sanitizeProxyPath(proxyPath);
  const resolvedPath = safeProxyPath === "/"
    ? (basePath ? `${basePath}/` : "/")
    : `${basePath}${safeProxyPath}`;
  baseUrl.pathname = resolvedPath || "/";
  baseUrl.search = "";
  baseUrl.hash = "";
  return baseUrl;
}

function buildFastSegmentUpstreamUrlText(targetRecord, proxyPath = "/", search = "") {
  if (!isTargetRecord(targetRecord)) {
    const legacyUrl = buildUpstreamProxyUrl(targetRecord, proxyPath);
    legacyUrl.search = normalizeSearchText(search);
    return legacyUrl.toString();
  }
  const safeProxyPath = sanitizeProxyPath(proxyPath);
  const safeSearch = normalizeSearchText(search);
  const resolvedPrefix = targetRecord.absoluteBasePrefix || targetRecord.originText;
  const resolvedPath = safeProxyPath === "/"
    ? `${resolvedPrefix}/`
    : `${resolvedPrefix}${safeProxyPath}`;
  return `${resolvedPath || `${targetRecord.originText}/`}${safeSearch}`;
}

function resolveProxyRelativePathFromUpstreamUrl(upstreamUrl, activeTargetBase) {
  try {
    const resolvedUrl = upstreamUrl instanceof URL ? new URL(upstreamUrl.toString()) : new URL(String(upstreamUrl || ""));
    const targetBase = activeTargetBase instanceof URL ? new URL(activeTargetBase.toString()) : new URL(String(activeTargetBase || ""));
    if (resolvedUrl.origin !== targetBase.origin) {
      return { resolvedUrl, proxyPath: null };
    }
    const basePath = normalizeTargetBasePath(targetBase.pathname);
    let proxyPath = resolvedUrl.pathname || "/";
    if (basePath) {
      if (proxyPath === basePath || proxyPath === `${basePath}/`) proxyPath = "/";
      else if (proxyPath.startsWith(`${basePath}/`)) proxyPath = proxyPath.slice(basePath.length);
      else return { resolvedUrl, proxyPath: null };
    }
    return {
      resolvedUrl,
      proxyPath: sanitizeProxyPath(proxyPath)
    };
  } catch {
    return { resolvedUrl: null, proxyPath: null };
  }
}

function translateUpstreamUrlToProxyLocation(upstreamUrl, activeTargetBase, name, key, options = {}) {
  try {
    const { resolvedUrl, proxyPath } = resolveProxyRelativePathFromUpstreamUrl(upstreamUrl, activeTargetBase);
    if (!resolvedUrl) return null;
    if (!proxyPath) return resolvedUrl.toString();
    return `${buildProxyPrefix(name, key, options)}${proxyPath === "/" ? "/" : proxyPath}${resolvedUrl.search}${resolvedUrl.hash}`;
  } catch {
    return null;
  }
}

function extractPlaybackInfoVisiblePrefix(proxyPath = "") {
  const safePath = sanitizeProxyPath(proxyPath);
  const lowerPath = safePath.toLowerCase();
  let cutIndex = -1;
  for (const marker of ["/items/", "/videos/", "/audio/", "/livetv/"]) {
    const index = lowerPath.indexOf(marker);
    if (index > 0 && (cutIndex === -1 || index < cutIndex)) cutIndex = index;
  }
  if (cutIndex <= 0) return "";
  return normalizeTargetBasePath(safePath.slice(0, cutIndex));
}

function isSmartStrmMediaProxyPath(proxyPath = "") {
  return /(?:^|\/)smartstrm(?:$|[/?])/i.test(String(proxyPath || ""));
}

function isPlaybackInfoMediaProxyPath(proxyPath = "") {
  return isPlaybackCriticalProxyPath(proxyPath)
    || /\/audio\/[^/]+(?:\/|$)/i.test(String(proxyPath || ""))
    || /\/livetv\/[^/]+(?:\/|$)/i.test(String(proxyPath || ""))
    || isSmartStrmMediaProxyPath(proxyPath);
}

function isAbsoluteHttpLikeUrl(value = "") {
  const text = String(value || "").trim();
  return /^[a-z][a-z0-9+.-]*:/i.test(text) || text.startsWith("//");
}

function stripProxyPathPrefixCaseInsensitive(proxyPath = "", prefix = "") {
  const safeProxyPath = sanitizeProxyPath(proxyPath);
  const safePrefix = normalizeTargetBasePath(prefix);
  if (!safePrefix) return safeProxyPath;
  const lowerProxyPath = safeProxyPath.toLowerCase();
  const lowerPrefix = safePrefix.toLowerCase();
  if (lowerProxyPath === lowerPrefix) return "/";
  if (lowerProxyPath.startsWith(`${lowerPrefix}/`)) {
    return sanitizeProxyPath(safeProxyPath.slice(safePrefix.length) || "/");
  }
  return safeProxyPath;
}

function stripPlaybackInfoLeadingPrefix(candidatePath = "", prefix = "") {
  const safePrefix = normalizeTargetBasePath(prefix);
  if (!safePrefix) return sanitizeProxyPath(candidatePath);
  let currentPath = sanitizeProxyPath(candidatePath);
  while (true) {
    if (currentPath === safePrefix || currentPath === `${safePrefix}/`) return "/";
    if (!currentPath.startsWith(`${safePrefix}/`)) return currentPath;
    currentPath = sanitizeProxyPath(currentPath.slice(safePrefix.length) || "/");
  }
}

function stripPlaybackInfoKnownBasePaths(candidatePath = "", activeTargetBase = null, proxyPrefix = "") {
  let normalizedPath = sanitizeProxyPath(candidatePath);
  normalizedPath = stripPlaybackInfoLeadingPrefix(normalizedPath, proxyPrefix);
  normalizedPath = stripPlaybackInfoLeadingPrefix(
    normalizedPath,
    activeTargetBase instanceof URL ? activeTargetBase.pathname : "/"
  );
  return normalizedPath;
}

function resolvePlaybackInfoRelativeMediaProxyTarget(candidateUrl = "", requestProxyPath = "", activeTargetBase = null, requestBaseUrl = null, proxyPrefix = "") {
  const rawCandidate = String(candidateUrl || "").trim();
  if (!rawCandidate) return null;
  let localBaseUrl = null;
  if (requestBaseUrl) {
    try {
      localBaseUrl = requestBaseUrl instanceof URL
        ? new URL(requestBaseUrl.toString())
        : new URL(String(requestBaseUrl || ""));
    } catch {
      localBaseUrl = null;
    }
  }
  let parsedCandidateUrl;
  try {
    if (isAbsoluteHttpLikeUrl(rawCandidate)) {
      parsedCandidateUrl = new URL(rawCandidate, localBaseUrl || "https://playback-info.local/");
      const protocol = String(parsedCandidateUrl.protocol || "").toLowerCase();
      const localOrigin = String(localBaseUrl?.origin || "").trim().toLowerCase();
      if (!["http:", "https:"].includes(protocol) || !localOrigin || parsedCandidateUrl.origin.toLowerCase() !== localOrigin) {
        return null;
      }
    } else {
      // 相对播放路径统一按可见代理根解析，避免挂到 PlaybackInfo 当前目录下。
      parsedCandidateUrl = new URL(rawCandidate, "https://playback-info.local/");
    }
  } catch {
    return null;
  }
  const normalizedCandidatePath = stripPlaybackInfoKnownBasePaths(
    parsedCandidateUrl.pathname || "/",
    activeTargetBase,
    proxyPrefix
  );
  const candidateVisiblePrefix = extractPlaybackInfoVisiblePrefix(normalizedCandidatePath);
  const candidateMediaPath = stripProxyPathPrefixCaseInsensitive(
    normalizedCandidatePath,
    candidateVisiblePrefix
  );
  if (!isPlaybackInfoMediaProxyPath(candidateMediaPath)) return null;
  return {
    proxyPath: sanitizeProxyPath(candidateMediaPath),
    search: parsedCandidateUrl.search || "",
    hash: parsedCandidateUrl.hash || ""
  };
}

function normalizePlaybackInfoProxyPath(proxyPath = "", requestProxyPath = "", activeTargetBase = null) {
  let normalizedProxyPath = sanitizeProxyPath(proxyPath);
  const visiblePrefix = extractPlaybackInfoVisiblePrefix(requestProxyPath);
  if (visiblePrefix) {
    const strippedVisiblePrefixPath = stripPlaybackInfoLeadingPrefix(normalizedProxyPath, visiblePrefix);
    if (strippedVisiblePrefixPath !== normalizedProxyPath && isPlaybackInfoMediaProxyPath(strippedVisiblePrefixPath)) {
      normalizedProxyPath = strippedVisiblePrefixPath;
    }
  }
  const targetBasePath = normalizeTargetBasePath(activeTargetBase instanceof URL ? activeTargetBase.pathname : "/");
  if (!visiblePrefix || !targetBasePath) return normalizedProxyPath;

  const duplicatePrefix = `${visiblePrefix}${targetBasePath}`;
  const lowerProxyPath = normalizedProxyPath.toLowerCase();
  const lowerDuplicatePrefix = duplicatePrefix.toLowerCase();
  if (lowerProxyPath !== lowerDuplicatePrefix && !lowerProxyPath.startsWith(`${lowerDuplicatePrefix}/`)) {
    return normalizedProxyPath;
  }

  const collapsedProxyPath = sanitizeProxyPath(`${visiblePrefix}${normalizedProxyPath.slice(duplicatePrefix.length) || "/"}`);
  return isPlaybackInfoMediaProxyPath(collapsedProxyPath) ? collapsedProxyPath : normalizedProxyPath;
}

function resolvePlaybackInfoRewriteUrlMode(playbackInfoMode = "") {
  if (normalizeDefaultPlaybackInfoMode(playbackInfoMode) !== "rewrite") return "relative";
  return "relative";
}

function sanitizeSyntheticRedirectHeaders(headers) {
  [
    "Age",
    "Accept-Ranges",
    "Content-Disposition",
    "Content-Encoding",
    "Content-Language",
    "Content-Length",
    "Content-Location",
    "Content-Range",
    "Content-Type",
    "ETag",
    "Expires",
    "Last-Modified",
    "Set-Cookie",
    "Transfer-Encoding"
  ].forEach(header => headers.delete(header));
}

function markPlaybackAbsoluteProxyUrl(url) {
  const absoluteUrl = url instanceof URL ? new URL(url.toString()) : new URL(String(url || ""));
  absoluteUrl.searchParams.set(PLAYBACK_ABSOLUTE_FALLBACK_QUERY_PARAM, PLAYBACK_ABSOLUTE_FALLBACK_QUERY_VALUE);
  return absoluteUrl;
}

function buildPlaybackAbsoluteFallbackRelativeLocation(proxyPath = "/", requestUrl = null) {
  const safeProxyPath = sanitizeProxyPath(
    requestUrl instanceof URL ? requestUrl.pathname : proxyPath
  );
  const fallbackSearchParams = new URLSearchParams(
    requestUrl instanceof URL ? requestUrl.search : String(requestUrl || "")
  );
  while (fallbackSearchParams.has(PLAYBACK_ABSOLUTE_FALLBACK_QUERY_PARAM)) {
    fallbackSearchParams.delete(PLAYBACK_ABSOLUTE_FALLBACK_QUERY_PARAM);
  }
  const fallbackQuery = fallbackSearchParams.toString();
  return `${safeProxyPath}${fallbackQuery ? `?${fallbackQuery}` : ""}`;
}

function buildProxyPrefix(name, key, options = {}) {
  const variantSegment = getProxyLinkVariantSegment(options?.linkVariant);
  const variantPath = variantSegment ? ("/" + encodeURIComponent(variantSegment)) : "";
  if (isHostPrefixEntryMode(options?.entryMode)) return variantPath;
  const encodedName = encodeURIComponent(String(name || ""));
  const encodedSecret = key ? ("/" + encodeURIComponent(String(key))) : "";
  return "/" + encodedName + encodedSecret + variantPath;
}

function buildAbsoluteProxyUrl(requestUrl, name, key, proxyPath = "/", options = {}) {
  const baseUrl = requestUrl instanceof URL ? new URL(requestUrl.toString()) : new URL(String(requestUrl || ""));
  const safeProxyPath = sanitizeProxyPath(proxyPath);
  const absoluteProxyUrl = new URL(baseUrl.origin);
  absoluteProxyUrl.pathname = `${buildProxyPrefix(name, key, {
    linkVariant: options.linkVariant,
    entryMode: options.entryMode
  })}${safeProxyPath === "/" ? "/" : safeProxyPath}`;
  absoluteProxyUrl.search = String(options.search || "");
  absoluteProxyUrl.hash = String(options.hash || "");
  return absoluteProxyUrl;
}

function buildPlaybackRelayProxyUrl(requestUrl, name, key, targetUrl, options = {}) {
  const absoluteTargetUrl = targetUrl instanceof URL ? new URL(targetUrl.toString()) : new URL(String(targetUrl || ""));
  const relayUrl = new URL(requestUrl instanceof URL ? requestUrl.origin : String(requestUrl || ""));
  relayUrl.pathname = `${buildProxyPrefix(name, key, {
    linkVariant: options.linkVariant,
    entryMode: options.entryMode
  })}/${PLAYBACK_RELAY_SEGMENT}${absoluteTargetUrl.pathname || "/"}`;
  relayUrl.search = absoluteTargetUrl.search || "";
  relayUrl.searchParams.append(PLAYBACK_RELAY_QUERY_PARAM, encodeBase64UrlUtf8(absoluteTargetUrl.toString()));
  relayUrl.hash = "";
  return relayUrl;
}

function buildPlaybackRelayProxyLocation(name, key, targetUrl, options = {}) {
  return serializeRelativeUrlLocation(buildPlaybackRelayProxyUrl(
    options.requestUrl || "https://playback-relay.local/",
    name,
    key,
    targetUrl,
    options
  ));
}

function stripPlaybackInfoClientVisibleProxyRoot(proxyPath = "", name = "", key = "", options = {}) {
  let normalizedPath = sanitizeProxyPath(proxyPath);
  const safeName = String(name || "").trim();
  if (!safeName && !isHostPrefixEntryMode(options?.entryMode)) return normalizedPath;
  const candidatePrefixes = [...new Set(
    ["proxy_a", "proxy_b", "main"]
      .map(linkVariant => buildProxyPrefix(safeName, key, {
        linkVariant,
        entryMode: options.entryMode
      }))
      .filter(prefix => prefix && prefix !== "/")
  )].sort((left, right) => right.length - left.length);
  if (!candidatePrefixes.length) return normalizedPath;
  let changed = true;
  while (changed) {
    changed = false;
    for (const prefix of candidatePrefixes) {
      const strippedPath = stripProxyPathPrefixCaseInsensitive(normalizedPath, prefix);
      if (strippedPath === normalizedPath) continue;
      normalizedPath = strippedPath;
      changed = true;
      break;
    }
  }
  return normalizedPath;
}

function resolvePlaybackInfoCompatVisiblePrefix(execution = null) {
  const routeKind = String(execution?.routeContextDiagnostics?.routeKind || "").trim();
  if (routeKind !== "host_prefix_path_compat" && routeKind !== "legacy_host_prefix_path_compat") {
    return "";
  }
  return buildProxyPrefix(
    execution?.nodeName,
    execution?.nodeKey,
    {
      linkVariant: execution?.linkVariant,
      entryMode: "kv_route"
    }
  );
}

function prependPlaybackInfoCompatVisiblePrefix(proxyPath = "", compatPrefix = "") {
  const normalizedPath = sanitizeProxyPath(proxyPath);
  const normalizedPrefix = normalizeTargetBasePath(compatPrefix);
  if (!normalizedPrefix || normalizedPrefix === "/") return normalizedPath;
  const lowerPath = normalizedPath.toLowerCase();
  const lowerPrefix = normalizedPrefix.toLowerCase();
  if (lowerPath === lowerPrefix || lowerPath.startsWith(`${lowerPrefix}/`)) {
    return normalizedPath;
  }
  return `${normalizedPrefix}${normalizedPath === "/" ? "/" : normalizedPath}`;
}

function resolvePlaybackRelayRequest(proxyPath = "", requestUrl = null) {
  const safeProxyPath = sanitizeProxyPath(proxyPath);
  const relayPrefix = `/${PLAYBACK_RELAY_SEGMENT}`;
  if (!safeProxyPath.startsWith(relayPrefix)) return null;
  const targetParam = requestUrl instanceof URL
    ? [...requestUrl.searchParams.getAll(PLAYBACK_RELAY_QUERY_PARAM)].pop() || ""
    : "";
  if (!targetParam) return { error: "missing_target" };
  let targetUrl;
  try {
    targetUrl = new URL(decodeBase64UrlUtf8(targetParam));
  } catch {
    return { error: "invalid_target" };
  }
  if (!["http:", "https:"].includes(String(targetUrl.protocol || "").toLowerCase())) {
    return { error: "unsupported_target" };
  }
  return {
    targetUrl,
    visibleProxyPath: sanitizeProxyPath(safeProxyPath.slice(relayPrefix.length) || "/")
  };
}

function tryNormalizeEmbeddedSameOriginPlaybackProxyPath(proxyPath = "", requestUrl = null, routePrefix = "") {
  const safeProxyPath = sanitizeProxyPath(proxyPath);
  const absoluteIndex = safeProxyPath.search(/https?:\/\//i);
  if (absoluteIndex <= 0) return null;
  let localRequestUrl;
  try {
    localRequestUrl = requestUrl instanceof URL
      ? new URL(requestUrl.toString())
      : new URL(String(requestUrl || ""));
  } catch {
    return null;
  }
  let embeddedUrl;
  try {
    embeddedUrl = new URL(safeProxyPath.slice(absoluteIndex));
  } catch {
    return null;
  }
  if (String(embeddedUrl.origin || "").toLowerCase() !== String(localRequestUrl.origin || "").toLowerCase()) {
    return null;
  }
  const safeRoutePrefix = normalizeTargetBasePath(routePrefix);
  const embeddedPath = sanitizeProxyPath(embeddedUrl.pathname || "/");
  const strippedEmbeddedPath = safeRoutePrefix
    ? stripProxyPathPrefixCaseInsensitive(embeddedPath, safeRoutePrefix)
    : embeddedPath;
  if (safeRoutePrefix && strippedEmbeddedPath === embeddedPath && embeddedPath.toLowerCase() !== safeRoutePrefix.toLowerCase()) {
    return null;
  }
  const prefixBeforeAbsolute = sanitizeProxyPath(safeProxyPath.slice(0, absoluteIndex) || "/");
  const candidatePaths = [strippedEmbeddedPath];
  if (prefixBeforeAbsolute !== "/") {
    const lowerPrefix = prefixBeforeAbsolute.toLowerCase();
    const lowerCandidate = strippedEmbeddedPath.toLowerCase();
    if (lowerCandidate !== lowerPrefix && !lowerCandidate.startsWith(`${lowerPrefix}/`)) {
      candidatePaths.unshift(sanitizeProxyPath(`${prefixBeforeAbsolute}${strippedEmbeddedPath === "/" ? "/" : strippedEmbeddedPath}`));
    }
  }
  for (const candidatePath of candidatePaths) {
    const linkVariantState = consumeProxyLinkVariantPrefix(candidatePath);
    const visiblePlaybackPath = sanitizeProxyPath(linkVariantState.remaining || candidatePath);
    if (!isPlaybackInfoMediaProxyPath(visiblePlaybackPath)) continue;
    return {
      kind: "embedded_absolute",
      originalPath: safeProxyPath,
      normalizedPath: sanitizeProxyPath(candidatePath),
      embeddedUrl: embeddedUrl.toString()
    };
  }
  return null;
}

function normalizePrewarmDepth(value) {
  const normalized = String(value || "").trim().toLowerCase().replace(/[\s-]+/g, "_");
  return normalized === "poster_manifest" ? "poster_manifest" : "poster";
}

function normalizeLogSearchMode(value) {
  const normalized = String(value || "").trim().toLowerCase();
  if (normalized === "fts") return "fts";
  if (normalized === "like") return "like";
  return Config.Defaults.LogSearchMode;
}

function normalizeLogWriteMode(value) {
  const normalized = String(value || "").trim().toLowerCase();
  if (normalized === "error") return "error";
  return Config.Defaults.LogWriteMode;
}

function normalizeLogRequestGroupFilter(value) {
  const normalized = String(value || "").trim().toLowerCase().replace(/[\s-]+/g, "_");
  if (normalized === "playback" || normalized === "playback_info") return "playback_info";
  if (normalized === "image") return "image";
  if (normalized === "api") return "api";
  if (normalized === "auth") return "auth";
  return "";
}

function normalizeLogStatusGroupFilter(value) {
  const normalized = String(value || "").trim().toLowerCase().replace(/[\s-]+/g, "_");
  if (normalized === "4xx" || normalized === "status_4xx") return "4xx";
  if (normalized === "5xx" || normalized === "status_5xx") return "5xx";
  return "";
}

function normalizeLogDeliveryModeFilter(value) {
  const normalized = String(value || "").trim().toLowerCase().replace(/[\s-]+/g, "_");
  if (normalized === "direct") return "direct";
  if (normalized === "proxy" || normalized === "proxied") return "proxy";
  return "";
}

function normalizeProtocolFailureReason(value = "") {
  const normalized = String(value || "").trim().toLowerCase().replace(/[\s-]+/g, "_");
  if (normalized === "connect_timeout") return "connect_timeout";
  if (normalized === "idle_timeout") return "idle_timeout";
  if (normalized === "tls_handshake_failed") return "tls_handshake_failed";
  if (normalized === "http_version_fallback") return "http_version_fallback";
  if (normalized === "redirect_loop") return "redirect_loop";
  if (normalized === "redirect_limit_exceeded") return "redirect_limit_exceeded";
  if (normalized === "range_unsatisfied") return "range_unsatisfied";
  if (normalized === "upstream_4xx") return "upstream_4xx";
  if (normalized === "upstream_5xx") return "upstream_5xx";
  if (normalized === "unknown_fetch_error") return "unknown_fetch_error";
  return "";
}

const HTTP_STATUS_REASON_META = Object.freeze({
  400: Object.freeze({ code: "bad_request", text: "请求格式无效或参数不符合上游要求" }),
  401: Object.freeze({ code: "unauthorized", text: "请求缺少有效身份凭证，或当前登录态已失效" }),
  403: Object.freeze({ code: "forbidden", text: "请求已被识别，但当前账号、策略或源站规则拒绝访问" }),
  404: Object.freeze({ code: "not_found", text: "请求路径或目标资源不存在" }),
  405: Object.freeze({ code: "method_not_allowed", text: "当前请求方法不被目标接口允许" }),
  429: Object.freeze({ code: "too_many_requests", text: "请求频率超过当前限流阈值，服务暂时拒绝继续处理" }),
  500: Object.freeze({ code: "internal_server_error", text: "源站或代理在处理请求时发生内部错误" }),
  501: Object.freeze({ code: "not_implemented", text: "源站或上游链路尚未实现当前请求所需能力" }),
  502: Object.freeze({ code: "bad_gateway", text: "网关无法从上游获得有效响应，或源站当前不可达" }),
  503: Object.freeze({ code: "service_unavailable", text: "源站暂时不可用，可能处于维护、重启或过载状态" }),
  504: Object.freeze({ code: "gateway_timeout", text: "网关等待上游响应超时" }),
  505: Object.freeze({ code: "http_version_not_supported", text: "目标链路不支持当前请求所使用的 HTTP 版本" }),
  520: Object.freeze({ code: "cf_unknown_origin_error", text: "Cloudflare 已到达源站，但源站返回了无法归类的异常响应" }),
  521: Object.freeze({ code: "cf_web_server_down", text: "Cloudflare 已到达源站网络，但源站拒绝连接或未监听目标端口" }),
  522: Object.freeze({ code: "cf_connection_timed_out", text: "Cloudflare 与源站建立连接超时" }),
  523: Object.freeze({ code: "cf_origin_unreachable", text: "Cloudflare 无法路由到源站网络，或源站 DNS/网络不可达" }),
  524: Object.freeze({ code: "cf_origin_timeout", text: "Cloudflare 已与源站建立连接，但源站在超时窗口内未返回完整响应" }),
  525: Object.freeze({ code: "cf_ssl_handshake_failed", text: "Cloudflare 与源站的 TLS 握手失败" }),
  526: Object.freeze({ code: "cf_invalid_ssl_certificate", text: "Cloudflare 校验源站证书时判定该证书无效" }),
  530: Object.freeze({ code: "cf_origin_dns_error", text: "源站 DNS 解析或 Cloudflare 到源站的访问链路存在致命错误" })
});

function resolveHttpStatusReasonMeta(statusCode) {
  const normalizedStatus = Math.trunc(Number(statusCode) || 0);
  if (!Number.isFinite(normalizedStatus) || normalizedStatus <= 0) {
    return { code: null, text: null };
  }
  const meta = HTTP_STATUS_REASON_META[normalizedStatus];
  return meta
    ? { code: meta.code, text: meta.text }
    : { code: null, text: null };
}

function looksLikeFtsExpression(value) {
  const text = String(value || "").trim();
  if (!text) return false;
  if (/\b(?:AND|OR|NOT|NEAR)\b/i.test(text)) return true;
  if (/(?:^|\s)(?:node_name|request_path|user_agent|error_detail)\s*:/i.test(text)) return true;
  if (/(?:^|\s)[^\s"]+\*/.test(text)) return true;
  return /^"(?:[^"]|"")+"$/.test(text);
}

function quoteFtsTerm(term) {
  return `"${String(term || "").replace(/"/g, '""')}"`;
}

function quoteFtsPrefixTerm(term) {
  return `${quoteFtsTerm(term)}*`;
}

function normalizeFtsExpression(text) {
  return String(text || "").replace(
    /(^|\s)((?:node_name|request_path|user_agent|error_detail)\s*:\s*)([^"\s()]+)(?=\s|$)/gi,
    (match, lead, prefix, value) => `${lead}${prefix}${quoteFtsTerm(value)}`
  );
}

function buildFtsMatchQuery(value) {
  const text = String(value || "").trim();
  if (!text) return "";
  if (looksLikeFtsExpression(text)) return normalizeFtsExpression(text);
  return text
    .split(/\s+/)
    .filter(Boolean)
    .map(token => quoteFtsPrefixTerm(token))
    .join(" AND ");
}

function normalizeLogPageCursor(value = null) {
  if (!value || typeof value !== "object") return null;
  const timestamp = Math.floor(Number(value.timestamp));
  const id = Math.floor(Number(value.id));
  if (!Number.isFinite(timestamp) || !Number.isFinite(id) || timestamp < 0 || id < 0) return null;
  return { timestamp, id };
}

function buildLogPageCursorFromRow(row = null) {
  return normalizeLogPageCursor({
    timestamp: Number(row?.timestamp),
    id: Number(row?.id)
  });
}

function normalizeRegionCodeCsv(value = "") {
  return [...new Set(
    String(value || "")
      .split(",")
      .map(item => item.trim().toUpperCase())
      .filter(Boolean)
  )].join(",");
}

function quoteSqlIdentifier(name) {
  return `"${String(name || "").replace(/"/g, '""')}"`;
}

function normalizeSqlIdentifierSearchText(sql) {
  return String(sql || "")
    .toLowerCase()
    .replace(/["`\[\]]/g, "")
    .replace(/\s+/g, " ")
    .trim();
}

function parseContentLengthHeader(value) {
  const raw = String(value || "").trim();
  if (!/^\d+$/.test(raw)) return null;
  const parsed = Number(raw);
  return Number.isFinite(parsed) ? parsed : null;
}

function getDefaultCacheHandle() {
  try {
    /** @type {unknown} */
    const globalObject = globalThis;
    /** @type {WorkerGlobalWithCachesLike | null | undefined} */
    const runtimeGlobals = globalObject;
    return runtimeGlobals?.caches?.default ?? null;
  } catch {
    return null;
  }
}

const WORKER_CACHE_DROP_QUERY_PARAMS = new Set([
  "apikey",
  "accesstoken",
  "token",
  "authorization",
  "xembytoken",
  "xembyauthorization",
  "xmediabrowsertoken",
  "xmediabrowserauthorization",
  "deviceid",
  "xembydeviceid",
  "xembydevicename",
  "xembyclient",
  "xembyclientversion",
  "xmediabrowserdeviceid",
  "xmediabrowserdevicename",
  "xmediabrowserclient",
  "xmediabrowserclientversion",
  "client",
  "clientid",
  "devicename",
  "userid",
  "playsessionid",
  "sessionid"
]);
const WORKER_METADATA_MANIFEST_ALLOWED_PATHS = [
  /^\/Videos\/[^/]+\/(?:main|master|stream)\.m3u8$/i,
  /^\/Videos\/[^/]+\/(?:manifest|main|master|stream)\.mpd$/i,
  /^\/Audio\/[^/]+\/(?:main|master|stream)\.m3u8$/i
];
const WORKER_METADATA_MANIFEST_ALLOWED_PARAMS = new Set([
  "mediasourceid",
  "static",
  "tag",
  "audiostreamindex",
  "subtitlestreamindex",
  "subtitlemethod",
  "starttimeticks"
]);

function normalizeWorkerCacheParamName(name = "") {
  return String(name || "").trim().toLowerCase().replace(/[^a-z0-9]+/g, "");
}

function shouldStripWorkerCacheQueryParam(name = "") {
  return WORKER_CACHE_DROP_QUERY_PARAMS.has(normalizeWorkerCacheParamName(name));
}

function normalizeWorkerCacheUrl(url) {
  const normalizedUrl = url instanceof URL ? new URL(url.toString()) : new URL(String(url || ""));
  normalizedUrl.hash = "";
  const keptParams = [];
  for (const [key, value] of normalizedUrl.searchParams.entries()) {
    if (shouldStripWorkerCacheQueryParam(key)) continue;
    keptParams.push([key, value]);
  }
  keptParams.sort((a, b) => {
    const keyDiff = a[0].localeCompare(b[0]);
    if (keyDiff !== 0) return keyDiff;
    return String(a[1]).localeCompare(String(b[1]));
  });
  normalizedUrl.search = "";
  for (const [key, value] of keptParams) normalizedUrl.searchParams.append(key, value);
  return normalizedUrl;
}

function normalizeMetadataCachePath(pathname = "") {
  const rawPath = String(pathname || "");
  const match = /\/(?:Videos|Audio)\/.+$/i.exec(rawPath);
  return match ? match[0] : rawPath;
}

function buildWorkerCacheKey(url) {
  try {
    return new Request(normalizeWorkerCacheUrl(url).toString(), { method: "GET" });
  } catch {
    return null;
  }
}

function buildOrderedNodeTargetList(nodeData = {}) {
  const lines = Array.isArray(nodeData?.lines) ? nodeData.lines.slice() : [];
  if (lines.length > 1) {
    const activeLineId = String(nodeData?.activeLineId || "").trim();
    if (activeLineId) {
      const activeIndex = lines.findIndex(line => String(line?.id || "").trim() === activeLineId);
      if (activeIndex > 0) {
        const [activeLine] = lines.splice(activeIndex, 1);
        lines.unshift(activeLine);
      }
    }
  }
  if (lines.length > 0) {
    return lines
      .map(line => String(line?.target || "").trim())
      .filter(Boolean);
  }
  return String(nodeData?.target || "")
    .split(",")
    .map(item => item.trim())
    .filter(Boolean);
}

function buildNodeDerivedCacheRevision(nodeName = "", nodeData = {}) {
  const normalizedName = String(nodeName || "").trim().toLowerCase();
  const normalizedEntryMode = normalizeNodeEntryMode(nodeData?.entryMode);
  const headerEntries = normalizeLooseHeaderEntries(nodeData?.headers)
    .map(([rawName, rawValue]) => [String(rawName || "").trim().toLowerCase(), String(rawValue ?? "").trim()])
    .filter(([headerName]) => !!headerName)
    .sort((left, right) => {
      const nameDiff = left[0].localeCompare(right[0]);
      if (nameDiff !== 0) return nameDiff;
      return left[1].localeCompare(right[1]);
    });
  const payload = {
    nodeName: normalizedName,
    entryMode: normalizedEntryMode,
    secret: normalizedEntryMode === "host_prefix" ? "" : String(nodeData?.secret || "").trim(),
    activeLineId: String(nodeData?.activeLineId || "").trim(),
    orderedTargets: buildOrderedNodeTargetList(nodeData),
    headers: headerEntries,
    playbackInfoMode: String(nodeData?.playbackInfoMode || "").trim().toLowerCase(),
    mediaAuthMode: String(nodeData?.mediaAuthMode || "").trim().toLowerCase(),
    realClientIpMode: String(nodeData?.realClientIpMode || "").trim().toLowerCase(),
    routingDecisionMode: String(nodeData?.routingDecisionMode || "").trim().toLowerCase(),
    mainVideoStreamMode: String(nodeData?.mainVideoStreamMode || nodeData?.wangpanDirectMode || nodeData?.wangpanMode || "").trim().toLowerCase()
  };
  return hashStableText(serializeConfigValue(payload));
}

function normalizeNodeNameSet(nodeNames = []) {
  const names = new Set();
  for (const rawName of Array.isArray(nodeNames) ? nodeNames : [nodeNames]) {
    const normalized = String(rawName || "").trim().toLowerCase();
    if (normalized) names.add(normalized);
  }
  return names;
}

function invalidatePlaybackInfoResponseCacheForNodes(nodeNames = []) {
  const normalizedNames = normalizeNodeNameSet(nodeNames);
  if (!normalizedNames.size) return;
  const cache = GLOBALS.PlaybackInfoResponseCache;
  if (!(cache instanceof Map) || cache.size <= 0) return;
  for (const [cacheKey, entry] of cache.entries()) {
    const entryNodeName = String(entry?.nodeName || "").trim().toLowerCase();
    if (!entryNodeName || !normalizedNames.has(entryNodeName)) continue;
    cache.delete(cacheKey);
  }
}

function invalidatePlaybackProgressRelayForNodes(nodeNames = []) {
  const normalizedNames = normalizeNodeNameSet(nodeNames);
  if (!normalizedNames.size) return;
  const relayMap = GLOBALS.PlaybackProgressRelay;
  if (!(relayMap instanceof Map) || relayMap.size <= 0) return;
  for (const [sessionKey, entry] of relayMap.entries()) {
    const entryNodeName = String(entry?.nodeName || entry?.pendingSnapshot?.nodeName || "").trim().toLowerCase();
    if (!entryNodeName || !normalizedNames.has(entryNodeName)) continue;
    relayMap.delete(sessionKey);
  }
}

function buildCanonicalWorkerMetadataCacheKey(requestUrl, name, key, proxyPath = "/", options = {}) {
  try {
    const baseUrl = requestUrl instanceof URL ? new URL(requestUrl.toString()) : new URL(String(requestUrl || ""));
    const safeProxyPath = sanitizeProxyPath(proxyPath);
    const canonicalUrl = new URL(baseUrl.origin);
    canonicalUrl.pathname = `${buildProxyPrefix(name, key, {
      linkVariant: "main",
      entryMode: options.entryMode
    })}${safeProxyPath === "/" ? "/" : safeProxyPath}`;
    canonicalUrl.search = String(options.search || "");
    const nodeCacheRevision = String(options.nodeCacheRevision || "").trim();
    if (nodeCacheRevision) canonicalUrl.searchParams.set("__proxyrev", nodeCacheRevision);
    canonicalUrl.hash = "";
    return buildWorkerCacheKey(canonicalUrl);
  } catch {
    return null;
  }
}

function isTranscodingManifestUrl(url) {
  try {
    const normalizedUrl = url instanceof URL ? new URL(url.toString()) : new URL(String(url || ""));
    for (const [key, value] of normalizedUrl.searchParams.entries()) {
      const lowerKey = String(key || "").toLowerCase();
      const lowerValue = String(value || "").toLowerCase();
      if (lowerKey.includes("transcod") || lowerValue.includes("transcod")) return true;
    }
    return false;
  } catch {
    return true;
  }
}

function isWhitelistedMetadataManifestUrl(url) {
  try {
    const normalizedUrl = url instanceof URL ? new URL(url.toString()) : new URL(String(url || ""));
    const normalizedPath = normalizeMetadataCachePath(normalizedUrl.pathname || "");
    if (!STREAM_MANIFEST_EXTENSION_REGEX.test(normalizedPath)) return false;
    if (isTranscodingManifestUrl(normalizedUrl)) return false;
    if (!WORKER_METADATA_MANIFEST_ALLOWED_PATHS.some(rule => rule.test(normalizedPath))) return false;
    for (const [key] of normalizedUrl.searchParams.entries()) {
      if (shouldStripWorkerCacheQueryParam(key)) continue;
      if (!WORKER_METADATA_MANIFEST_ALLOWED_PARAMS.has(normalizeWorkerCacheParamName(key))) return false;
    }
    return true;
  } catch {
    return false;
  }
}

function shouldWorkerCacheMetadataUrl(url) {
  try {
    const normalizedUrl = url instanceof URL ? new URL(url.toString()) : new URL(String(url || ""));
    const pathname = normalizedUrl.pathname || "";
    if (EMBY_IMAGE_PATH_REGEX.test(pathname) || IMAGE_FILE_EXTENSION_REGEX.test(pathname)) return true;
    if (SUBTITLE_EXTENSION_REGEX.test(pathname)) return true;
    if (STREAM_MANIFEST_EXTENSION_REGEX.test(pathname)) return isWhitelistedMetadataManifestUrl(normalizedUrl);
    return false;
  } catch {
    return false;
  }
}

function isHeavyVideoBytePath(pathname = "") {
  const lowerPath = String(pathname || "").toLowerCase();
  if (!lowerPath) return false;
  if (/\.(?:mp4|m4v|mkv|mov|avi|wmv|flv|ts|m4s)(?:$|[?#])/.test(lowerPath)) return true;
  if (STREAM_MANIFEST_EXTENSION_REGEX.test(lowerPath) || SUBTITLE_EXTENSION_REGEX.test(lowerPath)) return false;
  return /\/videos\/[^/]+\/(?:stream|original|download|file)\b/.test(lowerPath) || /\/items\/[^/]+\/download\b/.test(lowerPath);
}

function collectMetadataUrlStrings(input, collector = new Set(), depth = 0) {
  if (input === null || input === undefined || depth > 5) return collector;
  if (typeof input === "string") {
    const value = input.trim();
    if (value && /^(?:https?:\/\/|\/)/i.test(value)) {
      const lowerValue = value.toLowerCase();
      const matchTarget = lowerValue.split(/[?#]/, 1)[0] || lowerValue;
      if (
        STREAM_MANIFEST_EXTENSION_REGEX.test(matchTarget) ||
        SUBTITLE_EXTENSION_REGEX.test(matchTarget) ||
        EMBY_IMAGE_PATH_REGEX.test(lowerValue) ||
        IMAGE_FILE_EXTENSION_REGEX.test(matchTarget)
      ) {
        collector.add(value);
      }
    }
    return collector;
  }
  if (Array.isArray(input)) {
    input.slice(0, 24).forEach(item => collectMetadataUrlStrings(item, collector, depth + 1));
    return collector;
  }
  if (typeof input === "object") {
    Object.values(input).slice(0, 32).forEach(value => collectMetadataUrlStrings(value, collector, depth + 1));
  }
  return collector;
}

function extractProxyItemId(proxyPath = "") {
  const match = /^\/Items\/([^/]+)(?:\/|$)/i.exec(String(proxyPath || ""));
  return match ? safeDecodeSegment(match[1]) : "";
}

function rankMetadataWarmPath(pathname = "") {
  const lowerPath = String(pathname || "").toLowerCase();
  if (EMBY_IMAGE_PATH_REGEX.test(lowerPath) || IMAGE_FILE_EXTENSION_REGEX.test(lowerPath)) return 0;
  if (STREAM_MANIFEST_EXTENSION_REGEX.test(lowerPath)) return 1;
  if (SUBTITLE_EXTENSION_REGEX.test(lowerPath)) return 2;
  return 3;
}

function normalizeNodeNameList(input) {
  const rawList = Array.isArray(input)
    ? input
    : String(input || "").split(/[\\r\\n,，;；|]+/);
  const seen = new Set();
  const result = [];
  for (const item of rawList) {
    const value = String(item || "").trim();
    if (!value) continue;
    const key = value.toLowerCase();
    if (seen.has(key)) continue;
    seen.add(key);
    result.push(value);
  }
  return result;
}

function hashStableText(input = "") {
  const text = String(input || "");
  let hash = 2166136261;
  for (let i = 0; i < text.length; i += 1) {
    hash ^= text.charCodeAt(i);
    hash = Math.imul(hash, 16777619);
  }
  return (hash >>> 0).toString(36);
}

function createDnsIpPoolSourceId(seed = "") {
  return `dns-ip-source-${hashStableText(seed || `${Date.now()}-${Math.random().toString(36).slice(2, 8)}`)}`;
}

function normalizeDnsIpSourceType(value = "") {
  return String(value || "").trim().toLowerCase() === "domain" ? "domain" : "url";
}

