const DNS_PREFERRED_IP_LINKS = Object.freeze([
  Object.freeze({ label: "VPS789 优选IP", url: "https://vps789.com/cfip/" }),
  Object.freeze({ label: "Wetest IPv4 优选", url: "https://www.wetest.vip/page/cloudflare/address_v4.html" })
]);

function normalizeDnsIpPoolSourceKind(value = "") {
  const normalized = String(value || "").trim().toLowerCase();
  if (normalized === "builtin") return "builtin";
  if (normalized === "preset") return "preset";
  return "custom";
}

function normalizeDnsIpPoolBuiltInSourceId(value = "") {
  const normalized = String(value || "").trim().toLowerCase();
  if (normalized === "preferred") return "preferred";
  return normalized === "all" ? "all" : "";
}

function normalizeDnsIpPoolPresetId(value = "") {
  return String(value || "").trim().toLowerCase().replace(/[^a-z0-9_:-]+/g, "_");
}

function findDnsIpPoolBuiltInSourceDef(value = "") {
  const normalizedId = normalizeDnsIpPoolBuiltInSourceId(value);
  return DNS_IP_POOL_BUILTIN_SOURCE_DEFS.find(item => item.id === normalizedId) || null;
}

function findDnsIpPoolPresetSourceDef(value = "") {
  const normalizedId = normalizeDnsIpPoolPresetId(value);
  if (!normalizedId) return null;
  return DNS_IP_POOL_PRESET_SOURCE_DEFS.find(item => item.id === normalizedId) || null;
}

function buildDnsIpPoolSourceResponseMeta() {
  return {
    builtInSourceOptions: DNS_IP_POOL_BUILTIN_SOURCE_DEFS.map(item => ({
      id: item.id,
      label: item.label,
      sourceType: item.sourceType,
      value: "domain" in item ? item.domain : item.url
    })),
    presetList: DNS_IP_POOL_PRESET_SOURCE_DEFS.map(item => ({
      id: item.id,
      label: item.label,
      sourceType: item.sourceType,
      value: "domain" in item ? item.domain : item.url
    })),
    preferredDomainLinks: DNS_PREFERRED_DOMAIN_LINKS.map(item => ({ ...item })),
    preferredIpLinks: DNS_PREFERRED_IP_LINKS.map(item => ({ ...item }))
  };
}

function normalizeDnsIpPoolLineLabel(value = "") {
  const normalized = String(value || "").trim().toLowerCase();
  if (normalized.includes("联通")) return "联通";
  if (normalized.includes("电信")) return "电信";
  if (normalized.includes("移动")) return "移动";
  if (normalized.includes("多线")) return "多线";
  if (normalized.includes("ipv6")) return "ipv6";
  return "";
}

function resolveDnsIpPoolSourceResolvedTarget(source = {}) {
  const sourceKind = normalizeDnsIpPoolSourceKind(source?.sourceKind || source?.source_kind || "");
  const builtinDef = sourceKind === "builtin"
    ? findDnsIpPoolBuiltInSourceDef(source?.builtinId || source?.builtin_id || source?.presetId || source?.preset_id || source?.name)
    : null;
  const presetDef = sourceKind === "preset"
    ? findDnsIpPoolPresetSourceDef(source?.presetId || source?.preset_id || source?.builtinId || source?.builtin_id || source?.name)
    : null;
  const resolved = builtinDef || presetDef || null;
  const sourceType = normalizeDnsIpSourceType(resolved?.sourceType || source?.sourceType || source?.source_type || "");
  const resolvedUrl = resolved && "url" in resolved ? resolved.url : "";
  const resolvedDomain = resolved && "domain" in resolved ? resolved.domain : "";
  const url = String(resolvedUrl || source?.url || "").trim();
  const domain = normalizeHostnameText(resolvedDomain || source?.domain || "");
  const name = String(source?.name || resolved?.label || "").trim();
  return {
    sourceKind,
    builtinId: builtinDef?.id || "",
    presetId: presetDef?.id || "",
    name,
    sourceType,
    url,
    domain,
    resolvedLabel: String(resolved?.label || "").trim()
  };
}

function getDnsIpPoolSourceTargetValue(source = {}) {
  const resolved = resolveDnsIpPoolSourceResolvedTarget(source);
  const sourceType = normalizeDnsIpSourceType(resolved.sourceType);
  return sourceType === "domain"
    ? normalizeHostnameText(resolved.domain || "")
    : String(resolved.url || "").trim();
}

function hasDnsIpPoolSourceTarget(source = {}) {
  return !!getDnsIpPoolSourceTargetValue(source);
}

function normalizeDnsIpPoolItemRecord(item = {}, options = {}) {
  const rawIp = String(item?.ip || item?.content || "").trim();
  const ipType = detectIpType(rawIp);
  if (!rawIp || !ipType) return null;
  const nowIso = String(options.updatedAt || new Date().toISOString());
  const sourceKind = String(item?.sourceKind || item?.source_kind || options.sourceKind || "manual").trim().toLowerCase() || "manual";
  const sourceLabel = String(item?.sourceLabel || item?.source_label || options.sourceLabel || "").trim();
  const lineLabel = normalizeDnsIpPoolLineLabel(item?.lineLabel || item?.line_label || options.lineLabel || "");
  const remark = String(item?.remark || "").trim();
  return {
    id: String(item?.id || `dns-ip-${hashStableText(rawIp.toLowerCase())}`),
    ip: rawIp,
    ipType,
    sourceKind,
    sourceLabel,
    lineLabel,
    remark,
    createdAt: String(item?.createdAt || item?.created_at || options.createdAt || nowIso),
    updatedAt: nowIso
  };
}

function normalizeDnsIpPoolSourceRecord(source = {}, index = 0) {
  const nowIso = new Date().toISOString();
  const resolvedTarget = resolveDnsIpPoolSourceResolvedTarget(source);
  const sourceKind = resolvedTarget.sourceKind;
  const sourceType = normalizeDnsIpSourceType(resolvedTarget.sourceType);
  const builtinId = String(resolvedTarget.builtinId || source?.builtinId || source?.builtin_id || "").trim();
  const presetId = String(resolvedTarget.presetId || source?.presetId || source?.preset_id || "").trim();
  const resolvedLabel = String(resolvedTarget.resolvedLabel || "").trim();
  const url = String(resolvedTarget.url || "").trim();
  const domain = normalizeHostnameText(resolvedTarget.domain || "");
  const targetValue = sourceType === "domain" ? domain : url;
  const name = String(source?.name || resolvedLabel || "").trim();
  const rawEnabled = source?.enabled;
  const enabled = rawEnabled === undefined || rawEnabled === null
    ? true
    : !(rawEnabled === false || rawEnabled === 0 || String(rawEnabled).trim() === "0");
  return {
    id: String(source?.id || createDnsIpPoolSourceId(`${sourceKind}|${builtinId}|${presetId}|${sourceType}|${targetValue}|${index}`)),
    name: name || resolvedLabel || `抓取源 ${Number(index) + 1}`,
    url,
    domain,
    sourceType,
    sourceKind,
    presetId,
    builtinId,
    enabled,
    sortOrder: Math.max(0, Number.parseInt(String(source?.sortOrder ?? source?.sort_order ?? index), 10) || 0),
    ipLimit: normalizeDnsIpSourceIpLimit(source?.ipLimit ?? source?.ip_limit),
    lastFetchAt: String(source?.lastFetchAt || source?.last_fetch_at || ""),
    lastFetchStatus: String(source?.lastFetchStatus || source?.last_fetch_status || ""),
    lastFetchCount: Math.max(0, Number(source?.lastFetchCount ?? source?.last_fetch_count) || 0),
    createdAt: String(source?.createdAt || source?.created_at || nowIso),
    updatedAt: String(source?.updatedAt || source?.updated_at || nowIso)
  };
}

function dedupeNormalizedDnsIpPoolItems(items = []) {
  const deduped = [];
  const seenIndex = new Map();
  for (const rawItem of Array.isArray(items) ? items : []) {
    const normalized = normalizeDnsIpPoolItemRecord(rawItem);
    if (!normalized) continue;
    const key = String(normalized.ip || "").trim().toLowerCase();
    if (!key) continue;
    const existingIndex = seenIndex.get(key);
    if (existingIndex === undefined) {
      seenIndex.set(key, deduped.length);
      deduped.push(normalized);
      continue;
    }
    const existing = deduped[existingIndex];
    if (existing && !normalizeDnsIpPoolLineLabel(existing.lineLabel) && normalizeDnsIpPoolLineLabel(normalized.lineLabel)) {
      deduped[existingIndex] = {
        ...existing,
        lineLabel: normalized.lineLabel
      };
    }
  }
  return deduped;
}

function createDnsIpRefreshDisplayItem(item = {}) {
  const normalized = normalizeDnsIpPoolItemRecord(item);
  if (!normalized) return null;
  return {
    ...normalized,
    probeStatus: "pending",
    latencyMs: null,
    cfRay: "",
    coloCode: "",
    cityName: "",
    countryCode: "UNKNOWN",
    countryName: "未知",
    probedAt: ""
  };
}

function buildDnsIpRefreshDisplayItems(items = []) {
  return dedupeNormalizedDnsIpPoolItems(items)
    .map(item => createDnsIpRefreshDisplayItem(item))
    .filter(Boolean);
}

function normalizeDnsIpSourceFetchStatus(value = "") {
  const normalized = String(value || "").trim().toLowerCase();
  if (normalized === "success") return "success";
  if (normalized === "failed") return "failed";
  return "empty";
}

function normalizeDnsIpSourceFetchResultForCache(result = {}, source = {}) {
  const normalizedSource = normalizeDnsIpPoolSourceRecord(source);
  const items = dedupeNormalizedDnsIpPoolItems(result?.items || []).slice(0, normalizeDnsIpSourceIpLimit(normalizedSource?.ipLimit));
  const status = normalizeDnsIpSourceFetchStatus(result?.status || (items.length ? "success" : "empty"));
  return {
    id: String(result?.id || normalizedSource?.id || ""),
    name: String(result?.name || normalizedSource?.name || ""),
    sourceType: normalizeDnsIpSourceType(result?.sourceType || normalizedSource?.sourceType || ""),
    status,
    count: Math.max(0, Number(result?.count) || items.length),
    items,
    error: status === "failed" ? String(result?.error || "") : "",
    lastFetchAt: String(result?.lastFetchAt || new Date().toISOString())
  };
}

function buildDnsIpRefreshSourceResults(sourceResults = []) {
  return (Array.isArray(sourceResults) ? sourceResults : []).map(result => {
    const normalized = normalizeDnsIpSourceFetchResultForCache(result, result);
    const displayItems = buildDnsIpRefreshDisplayItems(normalized?.items || []);
    return {
      id: String(normalized?.id || ""),
      name: String(normalized?.name || ""),
      sourceType: normalizeDnsIpSourceType(normalized?.sourceType || ""),
      status: normalizeDnsIpSourceFetchStatus(normalized?.status),
      count: Math.max(0, Number(normalized?.count) || displayItems.length),
      items: displayItems,
      error: String(normalized?.error || ""),
      lastFetchAt: String(normalized?.lastFetchAt || "")
    };
  });
}

function shouldPersistDnsIpPoolFetchAggregateCache(sourceResults = []) {
  const normalizedResults = Array.isArray(sourceResults) ? sourceResults : [];
  if (!normalizedResults.length) return true;
  return normalizedResults.some(result => normalizeDnsIpSourceFetchStatus(result?.status) !== "failed");
}

function toIsoFromTimestamp(timestamp) {
  const value = Number(timestamp) || 0;
  if (!Number.isFinite(value) || value <= 0) return "";
  return new Date(value).toISOString();
}

function buildDnsIpPoolFetchSignature(sourceList = [], maxBytes = Config.Defaults.DnsIpSourceFetchMaxBytes) {
  const normalizedMaxBytes = clampIntegerConfig(maxBytes, Config.Defaults.DnsIpSourceFetchMaxBytes, 1024, 8 * 1024 * 1024);
  const enabledSources = (Array.isArray(sourceList) ? sourceList : [])
    .map((source, index) => normalizeDnsIpPoolSourceRecord(source, index))
    .filter(source => source.enabled === true && hasDnsIpPoolSourceTarget(source))
    .map(source => ({
      id: String(source.id || ""),
      name: String(source.name || ""),
      sourceType: normalizeDnsIpSourceType(source.sourceType),
      target: getDnsIpPoolSourceTargetValue(source),
      ipLimit: normalizeDnsIpSourceIpLimit(source.ipLimit),
      enabled: source.enabled !== false
    }));
  return hashStableText(serializeConfigValue({
    maxBytes: normalizedMaxBytes,
    enabledSources
  }));
}

function normalizeDnsIpPoolDeleteTarget(value = "") {
  return String(value || "").trim().toLowerCase() === "shared_snapshot" ? "shared_snapshot" : "local_pool";
}

function normalizeDnsIpPoolDeleteIpEntries(ips = []) {
  const normalizedIps = [];
  const deleteKeySet = new Set();
  for (const rawItem of Array.isArray(ips) ? ips : []) {
    const ip = String(rawItem?.ip || rawItem || "").trim();
    if (!detectIpType(ip)) continue;
    const key = ip.toLowerCase();
    if (deleteKeySet.has(key)) continue;
    deleteKeySet.add(key);
    normalizedIps.push(ip);
  }
  return {
    normalizedIps,
    deleteKeySet
  };
}

function partitionDnsIpPoolItemsByDeleteSet(items = [], deleteKeySet = new Set()) {
  const keptItems = [];
  const removedItems = [];
  for (const item of dedupeNormalizedDnsIpPoolItems(items)) {
    const ip = String(item?.ip || "").trim();
    if (!ip) continue;
    if (deleteKeySet.has(ip.toLowerCase())) {
      removedItems.push(item);
      continue;
    }
    keptItems.push(item);
  }
  return {
    keptItems,
    removedItems
  };
}

function removeDnsIpPoolSharedSnapshotItemsFromCacheEntry(cacheEntry = {}, ips = []) {
  const { deleteKeySet } = normalizeDnsIpPoolDeleteIpEntries(ips);
  const initialItems = dedupeNormalizedDnsIpPoolItems(cacheEntry?.items || []);
  const initialSourceResults = Array.isArray(cacheEntry?.sourceResults) ? cacheEntry.sourceResults : [];
  if (!deleteKeySet.size) {
    return {
      deletedCount: 0,
      deletedIps: [],
      items: initialItems,
      sourceResults: initialSourceResults
    };
  }
  const { keptItems, removedItems } = partitionDnsIpPoolItemsByDeleteSet(initialItems, deleteKeySet);
  const deletedKeySet = new Set(removedItems.map(item => String(item?.ip || "").trim().toLowerCase()).filter(Boolean));
  const sourceResults = initialSourceResults.map(result => {
    const { keptItems: keptResultItems } = partitionDnsIpPoolItemsByDeleteSet(result?.items || [], deletedKeySet);
    const baseStatus = normalizeDnsIpSourceFetchStatus(result?.status);
    const status = baseStatus === "failed" ? "failed" : (keptResultItems.length ? "success" : "empty");
    return {
      id: String(result?.id || ""),
      name: String(result?.name || ""),
      sourceType: normalizeDnsIpSourceType(result?.sourceType || result?.source_type || ""),
      status,
      count: keptResultItems.length,
      items: keptResultItems,
      error: status === "failed" ? String(result?.error || "") : "",
      lastFetchAt: String(result?.lastFetchAt || new Date().toISOString())
    };
  });
  return {
    deletedCount: removedItems.length,
    deletedIps: removedItems.map(item => String(item?.ip || "").trim()).filter(Boolean),
    items: keptItems,
    sourceResults
  };
}

function normalizeDnsIpProbeStatus(value = "") {
  const normalized = String(value || "").trim().toLowerCase();
  if (normalized === "ok") return "ok";
  if (normalized === "pending") return "pending";
  if (normalized === "cf_header_missing") return "cf_header_missing";
  if (normalized === "non_cloudflare") return "non_cloudflare";
  if (normalized === "timeout") return "timeout";
  if (normalized === "network_error") return "network_error";
  return "network_error";
}

function summarizeDnsIpWorkspaceItems(items = []) {
  const rows = Array.isArray(items) ? items : [];
  const countrySet = new Set();
  const coloSet = new Set();
  let ipv4Count = 0;
  let ipv6Count = 0;
  for (const item of rows) {
    const type = normalizeIpType(item?.ipType || item?.ip_type || item?.type || "");
    if (type === "IPv6") ipv6Count += 1;
    else ipv4Count += 1;
    const countryCode = String(item?.countryCode || item?.country_code || "").trim().toUpperCase();
    const coloCode = String(item?.coloCode || item?.colo_code || "").trim().toUpperCase();
    if (countryCode) countrySet.add(countryCode);
    if (coloCode) coloSet.add(coloCode);
  }
  return {
    ipCount: rows.length,
    ipv4Count,
    ipv6Count,
    countryCount: countrySet.size,
    coloCount: coloSet.size
  };
}

function buildDnsIpWorkspaceSummary(currentHostItems = [], sharedPoolItems = []) {
  const sharedPool = summarizeDnsIpWorkspaceItems(sharedPoolItems);
  return {
    currentHost: summarizeDnsIpWorkspaceItems([]),
    sharedPool,
    combined: sharedPool
  };
}

function reconcileNamedNodeSelection(currentSelection = [], options = {}) {
  const renameMapInput = options.renameMap instanceof Map
    ? options.renameMap
    : new Map(Object.entries(options.renameMap && typeof options.renameMap === "object" ? options.renameMap : {}));
  const renameMap = new Map();
  for (const [fromName, toName] of renameMapInput.entries()) {
    const fromKey = String(fromName || "").trim().toLowerCase();
    const nextName = String(toName || "").trim();
    if (!fromKey || !nextName) continue;
    renameMap.set(fromKey, nextName);
  }
  const removedKeys = new Set(normalizeNodeNameList(options.removedNames || []).map(name => String(name || "").trim().toLowerCase()).filter(Boolean));
  /** @type {[string, string][] | null} */
  const allowedNameEntries = options.allowedNames === undefined
    ? null
    : normalizeNodeNameList(options.allowedNames || [])
        .map(name => {
          /** @type {[string, string]} */
          const entry = [String(name || "").trim().toLowerCase(), String(name || "").trim()];
          return entry;
        })
        .filter(([key, value]) => key && value);
  const allowedNameMap = allowedNameEntries ? new Map(allowedNameEntries) : null;
  const nextSelection = [];
  const seen = new Set();
  for (const rawName of normalizeNodeNameList(currentSelection)) {
    const currentKey = String(rawName || "").trim().toLowerCase();
    if (!currentKey || removedKeys.has(currentKey)) continue;
    const renamedName = renameMap.get(currentKey) || String(rawName || "").trim();
    const nextKey = renamedName.toLowerCase();
    if (!nextKey || removedKeys.has(nextKey)) continue;
    if (allowedNameMap && !allowedNameMap.has(nextKey)) continue;
    if (seen.has(nextKey)) continue;
    seen.add(nextKey);
    nextSelection.push(allowedNameMap?.get(nextKey) || renamedName);
  }
  return nextSelection;
}

function isNodeDirectSourceEnabled(node, currentConfig = null, nodeNameHint = "") {
  const proxyMode = String(node?.proxyMode || node?.mode || "").trim().toLowerCase();
  if (["direct", "source-direct", "origin-direct", "node-direct"].includes(proxyMode)) return true;
  if (node?.direct === true || node?.sourceDirect === true || node?.directSource === true || node?.direct2xx === true) return true;
  const explicitText = `${node?.tag || ""} ${node?.remark || ""}`;
  return /(?:^|[\s\[(【])(?:直连|source-direct|origin-direct|node-direct)(?:$|[\s\])】])/i.test(explicitText);
}

function isNodeVideoStreamDirectEnabled(node, currentConfig = null, nodeNameHint = "") {
  const mode = readNodeMainVideoStreamMode(node);
  if (mode === "direct") return true;
  if (mode === "proxy") return false;
  return isNodeDirectSourceEnabled(node, currentConfig, nodeNameHint);
}

function resolveRedirectTarget(location, baseUrl) {
  if (!location) return null;
  try {
    return new URL(location, baseUrl instanceof URL ? baseUrl : String(baseUrl || ""));
  } catch {
    return null;
  }
}

function normalizeRedirectMethod(status, method = "GET") {
  const upperMethod = String(method || "GET").toUpperCase();
  if (status === 303 && upperMethod !== "GET" && upperMethod !== "HEAD") return "GET";
  if ((status === 301 || status === 302) && upperMethod === "POST") return "GET";
  return upperMethod;
}

function normalizeRoutingDecisionMode(value = "") {
  return String(value || "").trim().toLowerCase() === "simplified" ? "simplified" : "legacy";
}

function normalizeProtocolStrategy(value = "") {
  const normalized = String(value || "").trim().toLowerCase();
  if (normalized === "balanced") return "balanced";
  if (normalized === "aggressive") return "aggressive";
  return "compat";
}

function resolveProtocolStrategyFromLegacyConfig(config = {}) {
  const enableH2 = config?.enableH2 === true;
  const enableH3 = config?.enableH3 === true;
  if (!enableH2 && !enableH3) return "compat";
  return config?.peakDowngrade === false ? "aggressive" : "balanced";
}

function resolveProtocolRuntimeProfile(config = {}, options = {}) {
  const strategy = normalizeProtocolStrategy(
    hasOwnConfigKey(config, "protocolStrategy")
      ? config?.protocolStrategy
      : resolveProtocolStrategyFromLegacyConfig(config)
  );
  const hourUtc8 = Number.isFinite(Number(options.hourUtc8))
    ? Number(options.hourUtc8)
    : ((new Date().getUTCHours() + 8) % 24);
  const isPeakHour = hourUtc8 >= 20 && hourUtc8 < 24;
  if (strategy === "aggressive") {
    return {
      strategy,
      enableH2: true,
      enableH3: true,
      peakDowngrade: false,
      forceH1: false,
      isPeakHour
    };
  }
  if (strategy === "balanced") {
    return {
      strategy,
      enableH2: true,
      enableH3: true,
      peakDowngrade: true,
      forceH1: isPeakHour,
      isPeakHour
    };
  }
  return {
    strategy: "compat",
    enableH2: false,
    enableH3: false,
    peakDowngrade: true,
    forceH1: true,
    isPeakHour
  };
}

function isPlaybackInfoPath(proxyPath = "") {
  return /\/playbackinfo(?:$|[/?])/i.test(String(proxyPath || ""));
}

function isPlaybackCriticalProxyPath(proxyPath = "") {
  const normalizedPath = sanitizeProxyPath(proxyPath);
  if (isPlaybackInfoPath(normalizedPath)) return true;
  if (isSmartStrmMediaProxyPath(normalizedPath)) return true;
  if (STREAM_MANIFEST_EXTENSION_REGEX.test(normalizedPath) || STREAM_SEGMENT_EXTENSION_REGEX.test(normalizedPath)) return true;
  return /\/videos\/[^/]+\/(?:stream|original|download|file)\b/i.test(normalizedPath)
    || /\/items\/[^/]+\/download\b/i.test(normalizedPath);
}

function isPlaybackSessionProgressPath(proxyPath = "") {
  return /\/sessions\/playing\/progress(?:$|[/?])/i.test(String(proxyPath || ""));
}

function isPlaybackSessionStoppedPath(proxyPath = "") {
  return /\/sessions\/playing\/stopped(?:$|[/?])/i.test(String(proxyPath || ""));
}

function isPlaybackSessionStartedPath(proxyPath = "") {
  const text = String(proxyPath || "");
  if (isPlaybackSessionProgressPath(text) || isPlaybackSessionStoppedPath(text)) return false;
  return /\/sessions\/playing(?:\/started)?(?:$|[/?])/i.test(text);
}

function decodeBufferedBodyText(buffer) {
  if (buffer === null || buffer === undefined) return "";
  try {
    if (buffer instanceof ArrayBuffer) return new TextDecoder().decode(new Uint8Array(buffer));
    if (ArrayBuffer.isView(buffer)) return new TextDecoder().decode(buffer);
    return String(buffer || "");
  } catch {
    return "";
  }
}

function normalizeCaseInsensitiveObject(input = {}) {
  const normalized = {};
  if (!input || typeof input !== "object" || Array.isArray(input)) return normalized;
  for (const [key, value] of Object.entries(input)) {
    const normalizedKey = String(key || "").trim().toLowerCase();
    if (!normalizedKey || normalized[normalizedKey] !== undefined) continue;
    normalized[normalizedKey] = value;
  }
  return normalized;
}

function getCaseInsensitivePayloadValue(payload = {}, names = []) {
  const normalizedPayload = normalizeCaseInsensitiveObject(payload);
  for (const name of Array.isArray(names) ? names : [names]) {
    const key = String(name || "").trim().toLowerCase();
    if (!key) continue;
    const value = normalizedPayload[key];
    if (value === undefined || value === null || value === "") continue;
    return value;
  }
  return "";
}

function hasOwnConfigKey(config = {}, key = "") {
  return !!config && typeof config === "object" && Object.prototype.hasOwnProperty.call(config, key);
}

const DAILY_TELEGRAM_REPORT_KIND_DEFINITIONS = Object.freeze([
  { kind: "summary", configKey: "tgDailyReportSummaryEnabled" },
  { kind: "kv", configKey: "tgDailyReportKvEnabled" },
  { kind: "d1", configKey: "tgDailyReportD1Enabled" }
]);

function normalizeDailyTelegramReportKind(value = "") {
  const normalized = String(value || "").trim().toLowerCase();
  return normalized === "summary" || normalized === "kv" || normalized === "d1" ? normalized : "";
}

function normalizeDailyTelegramReportKindList(values = []) {
  const result = [];
  const seen = new Set();
  for (const value of Array.isArray(values) ? values : [values]) {
    const normalizedKind = normalizeDailyTelegramReportKind(value);
    if (!normalizedKind || seen.has(normalizedKind)) continue;
    seen.add(normalizedKind);
    result.push(normalizedKind);
  }
  return result;
}

function hasExplicitDailyTelegramReportKindConfig(config = {}) {
  return DAILY_TELEGRAM_REPORT_KIND_DEFINITIONS.some(({ configKey }) => hasOwnConfigKey(config, configKey));
}

function shouldUseLegacyDailyTelegramSummaryFallback(config = {}, sourceConfig = config) {
  /** @type {DailyTelegramReportConfigLike} */
  const safeConfig = /** @type {DailyTelegramReportConfigLike} */ (config && typeof config === "object" ? config : {});
  /** @type {DailyTelegramReportConfigLike} */
  const safeSourceConfig = /** @type {DailyTelegramReportConfigLike} */ (sourceConfig && typeof sourceConfig === "object" ? sourceConfig : {});
  return safeConfig.tgDailyReportEnabled === true && !hasExplicitDailyTelegramReportKindConfig(safeSourceConfig);
}

function applyDailyTelegramReportKindCompat(config = {}, sourceConfig = {}) {
  /** @type {DailyTelegramReportConfigLike} */
  const safeConfig = /** @type {DailyTelegramReportConfigLike} */ (config && typeof config === "object" ? config : {});
  /** @type {DailyTelegramReportConfigLike} */
  const safeSourceConfig = /** @type {DailyTelegramReportConfigLike} */ (sourceConfig && typeof sourceConfig === "object" ? sourceConfig : {});
  if (shouldUseLegacyDailyTelegramSummaryFallback(safeConfig, safeSourceConfig)) {
    safeConfig.tgDailyReportSummaryEnabled = true;
    safeConfig.tgDailyReportKvEnabled = false;
    safeConfig.tgDailyReportD1Enabled = false;
    return safeConfig;
  }
  safeConfig.tgDailyReportSummaryEnabled = safeConfig.tgDailyReportSummaryEnabled === true;
  safeConfig.tgDailyReportKvEnabled = safeConfig.tgDailyReportKvEnabled === true;
  safeConfig.tgDailyReportD1Enabled = safeConfig.tgDailyReportD1Enabled === true;
  return safeConfig;
}

function resolveDailyTelegramReportKinds(config = {}, sourceConfig = config, options = {}) {
  const safeConfig = config && typeof config === "object" ? config : {};
  const explicitKinds = normalizeDailyTelegramReportKindList(options?.reportKinds);
  if (explicitKinds.length > 0) return explicitKinds;
  const selectedKinds = DAILY_TELEGRAM_REPORT_KIND_DEFINITIONS
    .filter(({ configKey }) => safeConfig[configKey] === true)
    .map(({ kind }) => kind);
  if (selectedKinds.length > 0) return selectedKinds;
  if (options?.fallbackAllWhenLegacy === true && shouldUseLegacyDailyTelegramSummaryFallback(safeConfig, sourceConfig)) {
    return ["summary"];
  }
  return [];
}

function resolveRoutingDecisionMode(config = {}) {
  return "simplified";
}

function normalizeNodeRoutingDecisionMode(value = "") {
  const normalized = String(value || "").trim().toLowerCase();
  if (normalized === "legacy" || normalized === "simplified") return normalized;
  return "inherit";
}

function resolveEffectiveRoutingDecisionMode(node = {}, currentConfig = {}) {
  return "simplified";
}

const CF_DASH_CACHE_VERSION = 8;
const CF_DASH_CACHE_DB_KEY_PREFIX = "cf_dashboard_cache:";
const LEGACY_CF_DASH_CACHE_KV_KEY_PREFIX = "sys:cf_dash_cache";

function makeCfDashCacheDbKey(zoneId, dateKey = "") {
  const safeZoneId = encodeURIComponent(String(zoneId || "default").trim() || "default");
  const safeDateKey = encodeURIComponent(String(dateKey || "current").trim() || "current");
  return `${CF_DASH_CACHE_DB_KEY_PREFIX}${safeZoneId}:${safeDateKey}`;
}

function makeLegacyCfDashCacheKvKey(zoneId, dateKey = "") {
  const safeZoneId = encodeURIComponent(String(zoneId || "default").trim() || "default");
  const safeDateKey = encodeURIComponent(String(dateKey || "current").trim() || "current");
  return `${LEGACY_CF_DASH_CACHE_KV_KEY_PREFIX}:${safeZoneId}:${safeDateKey}`;
}

function sanitizeDashboardRequestSourceText(value = "", requestSource = "") {
  const text = String(value || "").trim();
  if (!text) return "";
  if (String(requestSource || "").trim().toLowerCase() === "workers_usage" && text.includes("Cloudflare Workers Usage")) {
    return "今日请求量口径：Cloudflare Workers Usage";
  }
  return text;
}

function sanitizeDashboardCfAnalyticsStatus(value = "") {
  const text = String(value || "").trim();
  if (!text) return "";
  if (text.includes("请求数已对齐 Workers Usage")) return "Cloudflare 统计正常";
  return text;
}

function sanitizeDashboardCfAnalyticsDetail(value = "", requestSource = "") {
  const text = String(value || "").trim();
  if (!text) return "";
  const normalizedSource = String(requestSource || "").trim().toLowerCase();
  if (text.includes("已对齐脚本")) return "";
  if (normalizedSource === "workers_usage" && text.includes("脚本:")) return "";
  return text;
}

const DASHBOARD_D1_WRITE_HOTSPOT_DAYS = 7;
const DASHBOARD_D1_WRITE_HOTSPOT_WEEKDAY_LABELS = ["周日", "周一", "周二", "周三", "周四", "周五", "周六"];

function buildDashboardD1WriteHotspotHourLabels() {
  return Array.from({ length: 24 }, (_, hour) => String(hour).padStart(2, "0"));
}

function formatDashboardD1WriteHotspotDayLabel(dateKey = "") {
  const matched = /^(\d{4})-(\d{2})-(\d{2})$/.exec(String(dateKey || "").trim());
  if (!matched) return String(dateKey || "").trim() || "-";
  const weekday = DASHBOARD_D1_WRITE_HOTSPOT_WEEKDAY_LABELS[new Date(Date.UTC(
    Number(matched[1]),
    Number(matched[2]) - 1,
    Number(matched[3])
  )).getUTCDay()] || "";
  return `${matched[2]}-${matched[3]}${weekday ? ` ${weekday}` : ""}`;
}

function buildDashboardD1WriteHotspotCell(dateKey = "", hour = 0, rowsWritten = 0, writeQueries = 0, intensity = 0) {
  const safeHour = Math.max(0, Math.min(23, Number(hour) || 0));
  const safeRowsWritten = Math.max(0, Number(rowsWritten) || 0);
  const safeWriteQueries = Math.max(0, Number(writeQueries) || 0);
  const safeIntensity = Math.max(0, Math.min(1, Number(intensity) || 0));
  const hourLabel = `${String(safeHour).padStart(2, "0")}:00`;
  const alpha = safeRowsWritten > 0
    ? Math.min(0.88, Number((0.12 + safeIntensity * 0.68).toFixed(3)))
    : 0.04;
  return {
    key: `${dateKey}:${safeHour}`,
    hour: safeHour,
    hourLabel,
    rowsWritten: safeRowsWritten,
    writeQueries: safeWriteQueries,
    intensity: safeIntensity,
    className: safeRowsWritten > 0 ? "d1-heat-cell is-active" : "d1-heat-cell is-empty",
    style: `--d1-heat-alpha:${alpha}`,
    title: `${dateKey} ${hourLabel} · 写入 ${formatCount(safeRowsWritten)} 行 · SQL 写 ${formatCount(safeWriteQueries)} 次`
  };
}

function buildDashboardD1WriteHotspotPlaceholder(options = {}) {
  const utcOffsetMinutes = normalizeScheduleUtcOffsetMinutes(options.utcOffsetMinutes);
  const nowTimestamp = Math.max(0, Number(options.nowMs) || nowMs());
  const currentDayWindow = buildOffsetDayWindow(new Date(nowTimestamp), utcOffsetMinutes);
  const startTs = currentDayWindow.startTs - (DASHBOARD_D1_WRITE_HOTSPOT_DAYS - 1) * 24 * 60 * 60 * 1000;
  const rows = Array.from({ length: DASHBOARD_D1_WRITE_HOTSPOT_DAYS }, (_, dayIndex) => {
    const dayContext = buildOffsetClockParts(startTs + dayIndex * 24 * 60 * 60 * 1000, utcOffsetMinutes);
    return {
      key: dayContext.dateKey,
      dateKey: dayContext.dateKey,
      label: formatDashboardD1WriteHotspotDayLabel(dayContext.dateKey),
      cells: Array.from({ length: 24 }, (_, hour) => buildDashboardD1WriteHotspotCell(dayContext.dateKey, hour))
    };
  });
  return {
    title: "D1 写入热点图",
    status: String(options.status || "idle").trim().toLowerCase() || "idle",
    source: String(options.source || "").trim(),
    summary: String(options.summary || "D1 写入热点尚未加载").trim() || "D1 写入热点尚未加载",
    detail: String(options.detail || "").trim(),
    periodLabel: String(options.periodLabel || `最近 ${DASHBOARD_D1_WRITE_HOTSPOT_DAYS} 天 · ${formatUtcOffsetMinutesLabel(utcOffsetMinutes)}`).trim(),
    hourLabels: buildDashboardD1WriteHotspotHourLabels(),
    rows,
    available: false,
    totalRowsWritten: 0,
    totalWriteQueries: 0,
    peakLabel: "",
    legendMaxLabel: "0"
  };
}

function normalizeDashboardD1WriteHotspotPayload(raw = {}) {
  const data = raw && typeof raw === "object" ? { ...raw } : {};
  const fallback = buildDashboardD1WriteHotspotPlaceholder({ status: "idle" });
  return {
    ...fallback,
    ...data,
    title: String(data.title || fallback.title).trim() || fallback.title,
    status: String(data.status || fallback.status).trim().toLowerCase() || fallback.status,
    source: String(data.source || fallback.source).trim(),
    summary: String(data.summary || fallback.summary).trim() || fallback.summary,
    detail: String(data.detail || fallback.detail).trim(),
    periodLabel: String(data.periodLabel || fallback.periodLabel).trim() || fallback.periodLabel,
    hourLabels: Array.isArray(data.hourLabels) && data.hourLabels.length
      ? data.hourLabels.map(item => String(item || "").trim()).filter(Boolean)
      : fallback.hourLabels,
    rows: Array.isArray(data.rows) ? data.rows : fallback.rows,
    available: data.available === true,
    totalRowsWritten: Math.max(0, Number(data.totalRowsWritten) || 0),
    totalWriteQueries: Math.max(0, Number(data.totalWriteQueries) || 0),
    peakLabel: String(data.peakLabel || "").trim(),
    legendMaxLabel: String(data.legendMaxLabel || "0").trim() || "0"
  };
}

function sanitizeDashboardStatsPayload(raw = {}) {
  const data = raw && typeof raw === "object" ? { ...raw } : {};
  const requestSource = String(data.requestSource || "").trim().toLowerCase();
  data.requestSourceText = sanitizeDashboardRequestSourceText(data.requestSourceText, requestSource);
  data.cfAnalyticsStatus = sanitizeDashboardCfAnalyticsStatus(data.cfAnalyticsStatus);
  data.cfAnalyticsDetail = sanitizeDashboardCfAnalyticsDetail(data.cfAnalyticsDetail, requestSource);
  data.d1WriteHotspot = normalizeDashboardD1WriteHotspotPayload(data.d1WriteHotspot);
  return data;
}

function normalizeDashboardSnapshotCacheStatus(value = "") {
  const status = String(value || "").trim().toLowerCase();
  if (status === "cache" || status === "stale" || status === "live") return status;
  return "live";
}

function trimDashboardSnapshotErrorMessage(error, fallback = "dashboard_snapshot_failed") {
  const detail = trimCloudflareRuntimeErrorMessage(error, fallback);
  if (detail.length <= 220) return detail;
  return `${detail.slice(0, 217)}...`;
}

function buildDashboardSnapshotCacheMeta(options = {}) {
  const cacheStatus = normalizeDashboardSnapshotCacheStatus(options.cacheStatus || options.status);
  const cachedAt = Math.max(0, Number(options.cachedAt) || 0);
  const expiresAt = Math.max(cachedAt, Number(options.expiresAt) || cachedAt);
  const updatedAt = Math.max(cachedAt, Number(options.updatedAt) || cachedAt);
  return {
    cacheStatus,
    cachedAt,
    expiresAt,
    updatedAt,
    generatedAt: String(options.generatedAt || "").trim(),
    warning: String(options.warning || "").trim(),
    partial: options.partial === true || cacheStatus === "stale"
  };
}

function sanitizeDashboardSnapshotPayload(raw = {}) {
  const data = raw && typeof raw === "object" ? { ...raw } : {};
  const looksLikeLegacyStats = !isPlainObject(data.stats) && (
    Array.isArray(data.hourlySeries)
    || Object.prototype.hasOwnProperty.call(data, "todayRequests")
    || Object.prototype.hasOwnProperty.call(data, "todayTraffic")
  );
  const stats = sanitizeDashboardStatsPayload(looksLikeLegacyStats
    ? data
    : (isPlainObject(data.stats) ? data.stats : {}));
  const runtimeStatus = isPlainObject(data.runtimeStatus) ? { ...data.runtimeStatus } : {};
  const cacheMetaSource = isPlainObject(data.cacheMeta) ? data.cacheMeta : {};
  const cacheMeta = buildDashboardSnapshotCacheMeta({
    cacheStatus: cacheMetaSource.cacheStatus || stats.cacheStatus || "live",
    cachedAt: cacheMetaSource.cachedAt,
    expiresAt: cacheMetaSource.expiresAt,
    updatedAt: cacheMetaSource.updatedAt,
    generatedAt: cacheMetaSource.generatedAt || stats.generatedAt || "",
    warning: cacheMetaSource.warning,
    partial: cacheMetaSource.partial === true
  });
  stats.cacheStatus = normalizeDashboardSnapshotCacheStatus(stats.cacheStatus || cacheMeta.cacheStatus);
  return {
    stats,
    runtimeStatus,
    cacheMeta
  };
}

function withDashboardSnapshotCacheStatus(snapshot = {}, cacheStatus = "live", overrides = {}) {
  const base = sanitizeDashboardSnapshotPayload(snapshot);
  const normalizedCacheStatus = normalizeDashboardSnapshotCacheStatus(cacheStatus || base.cacheMeta.cacheStatus);
  return {
    stats: sanitizeDashboardStatsPayload({
      ...base.stats,
      cacheStatus: normalizedCacheStatus
    }),
    runtimeStatus: isPlainObject(base.runtimeStatus) ? { ...base.runtimeStatus } : {},
    cacheMeta: buildDashboardSnapshotCacheMeta({
      ...base.cacheMeta,
      ...overrides,
      cacheStatus: normalizedCacheStatus,
      generatedAt: String(overrides.generatedAt || base.cacheMeta.generatedAt || base.stats.generatedAt || "").trim()
    })
  };
}

function normalizeTidyMaintenanceMode(value = "", mode = "manual") {
  const normalizedMode = String(mode || "manual").trim().toLowerCase() === "scheduled" ? "scheduled" : "manual";
  const normalizedValue = String(value || "").trim().toLowerCase();
  if (normalizedMode !== "manual") return "smart";
  return normalizedValue === "full" ? "full" : "smart";
}

function isFullTidyMaintenanceMode(value = "", mode = "manual") {
  return normalizeTidyMaintenanceMode(value, mode) === "full";
}

function getVideoRequestWhereClause(column = "request_path") {
  return `(${column} LIKE '%/stream%' OR ${column} LIKE '%/master.m3u8%' OR ${column} LIKE '%/videos/%/original%' OR ${column} LIKE '%/videos/%/download%' OR ${column} LIKE '%/videos/%/file%' OR ${column} LIKE '%/items/%/download%' OR ${column} LIKE '%Static=true%' OR ${column} LIKE '%Download=true%')`;
}

function parseHostnameCandidate(rawHostname) {
  const host = String(rawHostname || "").trim().toLowerCase();
  if (!host) return null;
  const wildcard = host.includes("*");
  const cleaned = host.replace(/^\*\./, "").replace(/^\*+/, "").replace(/\*+$/g, "").replace(/^\.+|\.+$/g, "");
  if (!cleaned) return null;
  return { hostname: cleaned, wildcard };
}

function normalizeHostnameText(rawHostname) {
  return parseHostnameCandidate(rawHostname)?.hostname || "";
}

function resolveConfiguredHost(env) {
  return normalizeHostnameText(env?.HOST);
}

function resolveConfiguredLegacyHost(env) {
  return normalizeHostnameText(env?.LEGACY_HOST);
}

function getLegacyHostPrefixReservation(env) {
  const configuredHost = resolveConfiguredHost(env);
  const legacyHost = resolveConfiguredLegacyHost(env);
  const match = resolveHostPrefixMatch(legacyHost, configuredHost);
  if (!match?.prefix) return null;
  return {
    name: String(match.prefix || "").trim().toLowerCase(),
    reservedBy: legacyHost,
    reason: "legacy_host",
    legacyHost,
    host: configuredHost
  };
}

function isHostnameInsideZone(rawHostname, rawZoneName) {
  const hostname = normalizeHostnameText(rawHostname);
  const zoneName = normalizeHostnameText(rawZoneName);
  if (!hostname || !zoneName) return false;
  return hostname === zoneName || hostname.endsWith(`.${zoneName}`);
}

function isValidDnsLabelForHostPrefix(value = "") {
  const text = String(value || "").trim().toLowerCase();
  if (!text || text.length > 63) return false;
  return /^[a-z0-9](?:[a-z0-9-]{0,61}[a-z0-9])?$/.test(text);
}

function resolveHostPrefixMatch(rawHostname = "", rawHost = "") {
  const hostname = normalizeHostnameText(rawHostname);
  const host = normalizeHostnameText(rawHost);
  if (!hostname || !host || hostname === host) return null;
  const suffix = `.${host}`;
  if (!hostname.endsWith(suffix)) return null;
  const prefix = hostname.slice(0, -suffix.length);
  if (!prefix || prefix.includes(".") || !isValidDnsLabelForHostPrefix(prefix)) return null;
  return {
    hostname,
    host,
    prefix
  };
}

function extractRouteHostnameInfo(pattern) {
  const rawPattern = String(pattern || "").trim();
  if (!rawPattern) return null;
  const slashIndex = rawPattern.indexOf("/");
  const rawHost = slashIndex === -1 ? rawPattern : rawPattern.slice(0, slashIndex);
  const path = slashIndex === -1 ? "" : rawPattern.slice(slashIndex);
  const parsed = parseHostnameCandidate(rawHost);
  if (!parsed) return null;
  return { ...parsed, path, pattern: rawPattern };
}

function scoreHostnameCandidate(hostname, options = {}) {
  const path = String(options.path || "");
  let score = 0;
  if (!options.wildcard) score += 100;
  if (hostname.includes(".workers.dev")) score -= 20;
  if (path === "/" || path === "/*") score += 20;
  else if (path.endsWith("*")) score += 10;
  else if (path) score += 4;
  score += hostname.split(".").length * 4;
  score -= Math.min(path.length, 30);
  return score;
}

function extractCloudflareApiErrorMessage(payload = null, fallbackText = "") {
  const errors = Array.isArray(payload?.errors) ? payload.errors : [];
  const messages = errors
    .map(item => {
      const code = String(item?.code || "").trim();
      const message = String(item?.message || "").trim();
      if (code && message) return `${code}: ${message}`;
      return message || code;
    })
    .filter(Boolean);
  if (messages.length > 0) return messages.join("; ");
  const fallback = String(fallbackText || "").trim();
  if (!fallback) return "";
  return fallback.replace(/\s+/g, " ").slice(0, 300);
}

async function fetchCloudflareApiJson(url, apiToken, init = {}) {
  const normalizedInit = init && typeof init === "object" ? init : {};
  /** @type {any} */
  const extraInit = normalizedInit;
  let extraHeaders = {};
  const rawHeaders = extraInit?.headers;
  if (rawHeaders) {
    if (rawHeaders instanceof Headers) extraHeaders = Object.fromEntries(rawHeaders.entries());
    else if (typeof rawHeaders === "object") extraHeaders = rawHeaders;
  }
  const isFormDataBody = typeof FormData !== "undefined" && extraInit?.body instanceof FormData;
  const res = await fetch(url, {
    ...extraInit,
    headers: {
      "Authorization": `Bearer ${apiToken}`,
      ...(isFormDataBody ? {} : { "Content-Type": "application/json" }),
      ...extraHeaders
    }
  });
  let rawText = "";
  try {
    rawText = await res.text();
  } catch {}
  /** @type {JsonApiEnvelope|null} */
  let payload = null;
  if (rawText) {
    try {
      payload = JSON.parse(rawText);
    } catch {}
  }
  if (!res.ok) {
    const statusCode = Number(res.status) || 0;
    const detail = extractCloudflareApiErrorMessage(payload, rawText);
    /** @type {AppError} */
    const error = new Error(detail ? `cf_api_http_${statusCode}: ${detail}` : `cf_api_http_${statusCode}`);
    error.status = statusCode;
    throw error;
  }
  if (!payload || typeof payload !== "object") return {};
  if (payload?.success === false) {
    const msg = extractCloudflareApiErrorMessage(payload, rawText);
    throw new Error(msg || "cf_api_error");
  }
  return payload;
}

async function fetchCloudflareGraphQL(apiToken, query, variables) {
  const body = variables && typeof variables === "object"
    ? { query, variables }
    : { query };
  const cfRes = await fetch("https://api.cloudflare.com/client/v4/graphql", {
    method: "POST",
    headers: { "Authorization": `Bearer ${apiToken}`, "Content-Type": "application/json" },
    body: JSON.stringify(body)
  });
  if (!cfRes.ok) throw new Error(`cf_graphql_http_${cfRes.status}`);
  /** @type {JsonApiEnvelope} */
  const cfData = await cfRes.json();
  if (Array.isArray(cfData?.errors) && cfData.errors.length) {
    throw new Error(cfData.errors.map(item => item?.message).filter(Boolean).join("; ") || "cf_graphql_error");
  }
  return cfData;
}

async function fetchCloudflareGraphQLZone(zoneId, apiToken, query, variables) {
  const cfData = await fetchCloudflareGraphQL(apiToken, query, variables);
  return cfData?.data?.viewer?.zones?.[0] || null;
}

async function fetchCloudflareGraphQLAccount(accountId, apiToken, query, variables) {
  const cfData = await fetchCloudflareGraphQL(apiToken, query, variables);
  return cfData?.data?.viewer?.accounts?.[0] || null;
}

async function fetchCloudflareZoneDetails(zoneId, apiToken) {
  if (!zoneId || !apiToken) return null;
  const payload = await fetchCloudflareApiJson(`https://api.cloudflare.com/client/v4/zones/${encodeURIComponent(String(zoneId).trim())}`, apiToken);
  return payload?.result || null;
}

async function fetchCloudflareZoneDetailsSoft(zoneId, apiToken, options = {}) {
  const zoneIdText = String(zoneId || "").trim();
  return await withNonCriticalFallback(
    fetchCloudflareZoneDetails(zoneIdText, apiToken),
    String(options?.scope || "cloudflare.zone_lookup"),
    {
      zoneId: zoneIdText,
      ...(isPlainObject(options?.context) ? options.context : {})
    },
    null
  );
}

async function fetchCloudflareZoneDetailsRequired(zoneId, apiToken, options = {}) {
  const zone = await fetchCloudflareZoneDetails(zoneId, apiToken);
  const zoneName = String(zone?.name || "").trim();
  if (zone && zoneName) return zone;
  /** @type {AppError} */
  const error = new Error("cf_zone_context_missing");
  error.code = "CF_ZONE_CONTEXT_MISSING";
  error.status = 400;
  error.details = {
    zoneId: String(zoneId || "").trim(),
    scope: String(options?.scope || "").trim()
  };
  throw error;
}

async function fetchCloudflareAccountUsageModel(accountId, apiToken) {
  const normalizedAccountId = String(accountId || "").trim();
  const normalizedApiToken = String(apiToken || "").trim();
  if (!normalizedAccountId || !normalizedApiToken) return "";
  const payload = await fetchCloudflareApiJson(
    `https://api.cloudflare.com/client/v4/accounts/${encodeURIComponent(normalizedAccountId)}/workers/account-settings`,
    normalizedApiToken
  );
  return normalizeCloudflareUsageModel(payload?.result?.default_usage_model);
}

