async function fetchCloudflareKvQuotaMetrics({ accountId, apiToken, namespaceId, startIso, endIso }) {
  const normalizedAccountId = String(accountId || "").trim();
  const normalizedApiToken = String(apiToken || "").trim();
  const normalizedNamespaceId = String(namespaceId || "").trim();
  if (!normalizedAccountId || !normalizedApiToken || !normalizedNamespaceId) return null;
  const query = `
    query {
      viewer {
        accounts(filter: { accountTag: ${toGraphQLString(normalizedAccountId)} }) {
          kvOperationsAdaptiveGroups(
            limit: 1000
            filter: {
              namespaceId: ${toGraphQLString(normalizedNamespaceId)}
              datetime_geq: ${toGraphQLString(String(startIso || "").trim())}
              datetime_leq: ${toGraphQLString(String(endIso || "").trim())}
            }
          ) {
            dimensions { actionType }
            sum { requests }
          }
          kvStorageAdaptiveGroups(
            limit: 1000
            filter: {
              namespaceId: ${toGraphQLString(normalizedNamespaceId)}
              datetime_geq: ${toGraphQLString(String(startIso || "").trim())}
              datetime_leq: ${toGraphQLString(String(endIso || "").trim())}
            }
          ) {
            max { byteCount }
          }
        }
      }
    }`;
  const accountData = await fetchCloudflareGraphQLAccount(normalizedAccountId, normalizedApiToken, query);
  if (!accountData) throw new Error("cf_graphql_empty_account");
  const operationRows = Array.isArray(accountData?.kvOperationsAdaptiveGroups) ? accountData.kvOperationsAdaptiveGroups : [];
  const storageRows = Array.isArray(accountData?.kvStorageAdaptiveGroups) ? accountData.kvStorageAdaptiveGroups : [];
  const totals = {
    readCount: 0,
    writeCount: 0,
    deleteCount: 0,
    listCount: 0,
    storageBytes: 0
  };
  for (const row of operationRows) {
    const actionType = String(row?.dimensions?.actionType || "").trim().toLowerCase();
    const requestCount = Math.max(0, Number(row?.sum?.requests) || 0);
    if (actionType === "read") totals.readCount += requestCount;
    else if (actionType === "write") totals.writeCount += requestCount;
    else if (actionType === "delete") totals.deleteCount += requestCount;
    else if (actionType === "list") totals.listCount += requestCount;
  }
  for (const row of storageRows) {
    totals.storageBytes = Math.max(totals.storageBytes, Math.max(0, Number(row?.max?.byteCount) || 0));
  }
  return totals;
}

async function fetchCloudflareD1QuotaMetrics({ accountId, apiToken, databaseId, startIso, endIso }) {
  const normalizedAccountId = String(accountId || "").trim();
  const normalizedApiToken = String(apiToken || "").trim();
  const normalizedDatabaseId = String(databaseId || "").trim();
  if (!normalizedAccountId || !normalizedApiToken || !normalizedDatabaseId) return null;
  const query = `
    query {
      viewer {
        accounts(filter: { accountTag: ${toGraphQLString(normalizedAccountId)} }) {
          d1AnalyticsAdaptiveGroups(
            limit: 1000
            filter: {
              databaseId: ${toGraphQLString(normalizedDatabaseId)}
              datetime_geq: ${toGraphQLString(String(startIso || "").trim())}
              datetime_leq: ${toGraphQLString(String(endIso || "").trim())}
            }
          ) {
            sum { rowsRead rowsWritten readQueries writeQueries }
          }
        }
      }
    }`;
  const accountData = await fetchCloudflareGraphQLAccount(normalizedAccountId, normalizedApiToken, query);
  if (!accountData) throw new Error("cf_graphql_empty_account");
  const rows = Array.isArray(accountData?.d1AnalyticsAdaptiveGroups) ? accountData.d1AnalyticsAdaptiveGroups : [];
  return rows.reduce((accumulator, row) => ({
    rowsRead: accumulator.rowsRead + Math.max(0, Number(row?.sum?.rowsRead) || 0),
    rowsWritten: accumulator.rowsWritten + Math.max(0, Number(row?.sum?.rowsWritten) || 0),
    readQueries: accumulator.readQueries + Math.max(0, Number(row?.sum?.readQueries) || 0),
    writeQueries: accumulator.writeQueries + Math.max(0, Number(row?.sum?.writeQueries) || 0)
  }), {
    rowsRead: 0,
    rowsWritten: 0,
    readQueries: 0,
    writeQueries: 0
  });
}

async function fetchCloudflareD1WriteHotspotMetrics({ accountId, apiToken, databaseId, startIso, endIso, utcOffsetMinutes = Config.Defaults.ScheduleUtcOffsetMinutes }) {
  const normalizedAccountId = String(accountId || "").trim();
  const normalizedApiToken = String(apiToken || "").trim();
  const normalizedDatabaseId = String(databaseId || "").trim();
  if (!normalizedAccountId || !normalizedApiToken || !normalizedDatabaseId) return [];
  const query = `
    query {
      viewer {
        accounts(filter: { accountTag: ${toGraphQLString(normalizedAccountId)} }) {
          d1AnalyticsAdaptiveGroups(
            limit: 10000
            filter: {
              databaseId: ${toGraphQLString(normalizedDatabaseId)}
              datetime_geq: ${toGraphQLString(String(startIso || "").trim())}
              datetime_leq: ${toGraphQLString(String(endIso || "").trim())}
            }
          ) {
            dimensions { datetimeHour }
            sum { rowsWritten writeQueries }
          }
        }
      }
    }`;
  const accountData = await fetchCloudflareGraphQLAccount(normalizedAccountId, normalizedApiToken, query);
  if (!accountData) throw new Error("cf_graphql_empty_account");
  const rows = Array.isArray(accountData?.d1AnalyticsAdaptiveGroups) ? accountData.d1AnalyticsAdaptiveGroups : [];
  const bucketMap = new Map();
  for (const row of rows) {
    const rawHour = String(row?.dimensions?.datetimeHour || "").trim();
    if (!rawHour) continue;
    const timestamp = Date.parse(rawHour);
    if (!Number.isFinite(timestamp)) continue;
    const parts = buildOffsetClockParts(new Date(timestamp), utcOffsetMinutes);
    const bucketKey = `${parts.dateKey}:${parts.hour}`;
    const current = bucketMap.get(bucketKey) || {
      dateKey: parts.dateKey,
      hour: parts.hour,
      rowsWritten: 0,
      writeQueries: 0
    };
    current.rowsWritten += Math.max(0, Number(row?.sum?.rowsWritten) || 0);
    current.writeQueries += Math.max(0, Number(row?.sum?.writeQueries) || 0);
    bucketMap.set(bucketKey, current);
  }
  return [...bucketMap.values()].sort((left, right) => {
    if (left.dateKey !== right.dateKey) return String(left.dateKey).localeCompare(String(right.dateKey));
    return Number(left.hour) - Number(right.hour);
  });
}

async function fetchCloudflareDailyTrafficSummary({ cfZoneId, cfApiToken, scheduleUtcOffsetMinutes = Config.Defaults.ScheduleUtcOffsetMinutes, dayWindow = null }) {
  const zoneId = String(cfZoneId || "").trim();
  const apiToken = String(cfApiToken || "").trim();
  const window = dayWindow && typeof dayWindow === "object"
    ? dayWindow
    : buildOffsetDayWindow(new Date(), scheduleUtcOffsetMinutes);
  if (!zoneId || !apiToken) {
    return {
      todayTraffic: "未配置",
      zoneName: "",
      cfAnalyticsLoaded: false,
      cfAnalyticsStatus: "未配置 Cloudflare",
      cfAnalyticsError: "请在账号设置中填写并保存 Cloudflare Zone ID 与 API 令牌",
      cfAnalyticsDetail: ""
    };
  }

  const startIso = new Date(window.startTs).toISOString();
  const endIso = new Date(window.endTs).toISOString();
  const query = `
    query {
      viewer {
        zones(filter: { zoneTag: ${toGraphQLString(zoneId)} }) {
          series: httpRequestsAdaptiveGroups(limit: 10000, filter: { datetime_geq: ${toGraphQLString(startIso)}, datetime_leq: ${toGraphQLString(endIso)} }) {
            sum { edgeResponseBytes }
          }
        }
      }
    }`;
  let zoneName = "";

  try {
    const zone = await fetchCloudflareZoneDetailsSoft(zoneId, apiToken, {
      scope: "cloudflare.daily_traffic.zone_lookup",
      context: { feature: "daily_traffic_summary" }
    });
    zoneName = String(zone?.name || "").trim();
    const zoneData = await fetchCloudflareGraphQLZone(zoneId, apiToken, query);
    if (!zoneData) {
      return {
        todayTraffic: "CF 无统计数据",
        zoneName,
        cfAnalyticsLoaded: false,
        cfAnalyticsStatus: "Zone 未命中",
        cfAnalyticsError: "GraphQL 返回空；请检查 Zone ID 或权限",
        cfAnalyticsDetail: ""
      };
    }
    const seriesData = Array.isArray(zoneData.series) ? zoneData.series : [];
    const totalBytes = seriesData.reduce((sum, item) => sum + (Number(item?.sum?.edgeResponseBytes) || 0), 0);
    return {
      todayTraffic: formatBytes(totalBytes),
      zoneName,
      cfAnalyticsLoaded: true,
      cfAnalyticsStatus: "Cloudflare 统计正常",
      cfAnalyticsError: "",
      cfAnalyticsDetail: ""
    };
  } catch (e) {
    const cfDiag = classifyCloudflareAnalyticsError(e?.message || e, { zoneId });
    return {
      todayTraffic: "CF 查询失败",
      zoneName,
      cfAnalyticsLoaded: false,
      cfAnalyticsStatus: cfDiag.status,
      cfAnalyticsError: cfDiag.hint,
      cfAnalyticsDetail: cfDiag.detail
    };
  }
}

function isEditableDnsRecordType(value = "") {
  const upper = String(value || "").trim().toUpperCase();
  return upper === "A" || upper === "AAAA" || upper === "CNAME";
}

function normalizeDnsEditModeValue(value = "") {
  return String(value || "").trim().toLowerCase() === "a" ? "a" : "cname";
}

function getDnsContentValidationError(type, content, options = {}) {
  const nextType = String(type || "").trim().toUpperCase();
  const nextContent = String(content || "").trim();
  const allowCname = options.allowCname !== false;
  if (!isEditableDnsRecordType(nextType)) return "Type 仅允许 A / AAAA / CNAME";
  if (!allowCname && nextType === "CNAME") return "A 模式仅允许 A / AAAA";
  if (!nextContent) return "Content 不能为空";
  if (nextType === "A" && !isValidIpv4Address(nextContent)) return "A 记录 Content 必须是合法 IPv4 地址";
  if (nextType === "AAAA" && !isValidIpv6Address(nextContent)) return "AAAA 记录 Content 必须是合法 IPv6 地址";
  if (nextType === "CNAME") {
    if (/\s/.test(nextContent)) return "CNAME 记录 Content 不能包含空格";
    if (nextContent.length > 255) return "CNAME 记录 Content 过长";
  }
  return "";
}

function normalizeDnsFallbackCnameConfigValue(value = "") {
  const text = String(value || "").trim();
  if (!text) return "";
  return getDnsContentValidationError("CNAME", text) ? "" : text;
}

function normalizeEditableDnsRecord(record = {}) {
  return {
    id: String(record?.id || "").trim(),
    type: String(record?.type || "").trim().toUpperCase(),
    name: normalizeHostnameText(record?.name),
    content: String(record?.content || "").trim(),
    ttl: Number(record?.ttl) || 1,
    proxied: record?.proxied === true,
    comment: typeof record?.comment === "string" ? record.comment : undefined,
    tags: Array.isArray(record?.tags) ? record.tags.map(tag => String(tag)) : undefined
  };
}

async function listCloudflareDnsRecords(zoneId, apiToken, options = {}) {
  const records = [];
  let page = 1;
  let totalPages = 1;
  const perPage = 100;
  const nameExact = normalizeHostnameText(options?.nameExact || "");
  do {
    const url = new URL(`https://api.cloudflare.com/client/v4/zones/${encodeURIComponent(zoneId)}/dns_records`);
    url.searchParams.set("page", String(page));
    url.searchParams.set("per_page", String(perPage));
    if (nameExact) {
      url.searchParams.set("name.exact", nameExact);
    }
    const payload = await fetchCloudflareApiJson(url.toString(), apiToken);
    if (Array.isArray(payload?.result)) {
      records.push(...payload.result.map(item => normalizeEditableDnsRecord(item)).filter(item => item.id && item.name));
    }
    totalPages = Number(payload?.result_info?.total_pages || payload?.result_info?.totalPages || 1);
    page += 1;
  } while (page <= totalPages && page <= 20);
  return records;
}

function buildCloudflareDnsRecordBody(baseRecord = {}, options = {}) {
  const type = String(options.type || baseRecord?.type || "A").trim().toUpperCase();
  const host = normalizeHostnameText(options.host || baseRecord?.name);
  const content = String(options.content || "").trim();
  const body = {
    type,
    name: host,
    content,
    ttl: Number(baseRecord?.ttl) || 1,
    proxied: baseRecord?.proxied === true
  };
  if (typeof baseRecord?.comment === "string") body.comment = baseRecord.comment;
  if (Array.isArray(baseRecord?.tags)) body.tags = baseRecord.tags.map(tag => String(tag));
  return body;
}

function normalizeComparableDnsRecordContent(type = "", content = "") {
  const normalizedType = String(type || "").trim().toUpperCase();
  const text = String(content || "").trim();
  if (!text) return "";
  if (normalizedType === "A") return text;
  return text.toLowerCase();
}

function buildComparableDnsRecordKey(type = "", content = "") {
  const normalizedType = String(type || "").trim().toUpperCase();
  const normalizedContent = normalizeComparableDnsRecordContent(normalizedType, content);
  if (!normalizedType || !normalizedContent) return "";
  return `${normalizedType}|${normalizedContent}`;
}

function dedupeEditableDnsRecordSpecs(records = []) {
  const dedupedRecords = [];
  const seen = new Set();
  let duplicateCount = 0;
  for (const record of Array.isArray(records) ? records : []) {
    const type = String(record?.type || "").trim().toUpperCase();
    const content = String(record?.content || "").trim();
    const key = buildComparableDnsRecordKey(type, content);
    if (!key) continue;
    if (seen.has(key)) {
      duplicateCount += 1;
      continue;
    }
    seen.add(key);
    dedupedRecords.push({
      type,
      content,
      ttl: Number(record?.ttl) || 1,
      proxied: record?.proxied === true,
      comment: typeof record?.comment === "string" ? record.comment : undefined,
      tags: Array.isArray(record?.tags) ? record.tags.map(tag => String(tag)) : undefined
    });
  }
  return {
    records: dedupedRecords,
    duplicateCount
  };
}

function createDnsRecordSyncFamilySummary(type = "", desiredCount = 0) {
  return {
    type: String(type || "").trim().toUpperCase(),
    desiredCount: Math.max(0, Number(desiredCount) || 0),
    identicalCount: 0,
    updatedCount: 0,
    createdCount: 0,
    deletedCount: 0
  };
}

function finalizeDnsRecordSyncSummary(mode = "a", summaryByType = {}, options = {}) {
  const familySummaries = {};
  let desiredCount = 0;
  let identicalCount = 0;
  let updatedCount = 0;
  let createdCount = 0;
  let deletedCount = 0;
  for (const type of ["A", "AAAA", "CNAME"]) {
    const summary = summaryByType?.[type];
    if (!summary || typeof summary !== "object") continue;
    familySummaries[type] = {
      type,
      desiredCount: Math.max(0, Number(summary.desiredCount) || 0),
      identicalCount: Math.max(0, Number(summary.identicalCount) || 0),
      updatedCount: Math.max(0, Number(summary.updatedCount) || 0),
      createdCount: Math.max(0, Number(summary.createdCount) || 0),
      deletedCount: Math.max(0, Number(summary.deletedCount) || 0)
    };
    desiredCount += familySummaries[type].desiredCount;
    identicalCount += familySummaries[type].identicalCount;
    updatedCount += familySummaries[type].updatedCount;
    createdCount += familySummaries[type].createdCount;
    deletedCount += familySummaries[type].deletedCount;
  }
  const changedCount = updatedCount + createdCount + deletedCount;
  return {
    mode: String(mode || "a").trim().toLowerCase(),
    desiredCount,
    identicalCount,
    updatedCount,
    createdCount,
    deletedCount,
    changedCount,
    dedupedDesiredCount: Math.max(0, Number(options?.dedupedDesiredCount) || 0),
    familySummaries,
    unchangedOnly: changedCount === 0 && identicalCount > 0
  };
}

async function fetchCloudflareWorkerUsageMetrics({ cfAccountId, cfZoneId, cfApiToken, startIso, endIso, utcOffsetMinutes = Config.Defaults.ScheduleUtcOffsetMinutes }) {
  if (!cfAccountId || !cfApiToken) return null;
  const query = `
  query {
    viewer {
      accounts(filter: { accountTag: ${toGraphQLString(cfAccountId)} }) {
        workersInvocationsAdaptive(limit: 10000, filter: { datetime_geq: ${toGraphQLString(startIso)}, datetime_leq: ${toGraphQLString(endIso)} }) {
          dimensions { datetime scriptName status }
          sum { requests }
        }
      }
    }
  }`;

  const accountData = await fetchCloudflareGraphQLAccount(cfAccountId, cfApiToken, query);
  const records = Array.isArray(accountData?.workersInvocationsAdaptive) ? accountData.workersInvocationsAdaptive : [];
  const hourlySeries = Array.from({ length: 24 }, (_, hour) => ({ label: String(hour).padStart(2, "0") + ":00", total: 0 }));

  let totalRequests = 0;
  for (const item of records) {
    const req = Number(item?.sum?.requests) || 0;
    totalRequests += req;

    const dtRaw = item?.dimensions?.datetime;
    if (!dtRaw) continue;
    const dt = new Date(dtRaw);
    if (Number.isNaN(dt.getTime())) continue;
    const hour = buildOffsetClockParts(dt, utcOffsetMinutes).hour;
    if (hourlySeries[hour]) hourlySeries[hour].total += req;
  }

  return { totalRequests, hourlySeries };
}

async function resolveCloudflareBoundHostname({ cfAccountId, cfZoneId, cfApiToken, zoneNameFallback = "" }) {
  const candidates = [];
  const pushCandidate = (rawHostname, options = {}) => {
    const parsed = parseHostnameCandidate(rawHostname);
    if (!parsed) return;
    const wildcard = options.wildcard === true || parsed.wildcard === true;
    candidates.push({
      hostname: parsed.hostname,
      path: String(options.path || ""),
      wildcard,
      score: scoreHostnameCandidate(parsed.hostname, { wildcard, path: options.path || "" })
    });
  };

  if (cfAccountId && cfZoneId) {
    try {
      const url = `https://api.cloudflare.com/client/v4/accounts/${encodeURIComponent(String(cfAccountId).trim())}/workers/domains?zone_id=${encodeURIComponent(String(cfZoneId).trim())}`;
      const payload = await fetchCloudflareApiJson(url, cfApiToken);
      for (const item of payload?.result || []) {
        pushCandidate(item?.hostname);
      }
    } catch (e) {
      console.log("CF Workers domains lookup failed, will try routes", e);
    }
  }

  if (!candidates.length && cfZoneId) {
    try {
      let page = 1;
      let totalPages = 1;
      do {
        const url = `https://api.cloudflare.com/client/v4/zones/${encodeURIComponent(String(cfZoneId).trim())}/workers/routes?page=${page}&per_page=100`;
        const payload = await fetchCloudflareApiJson(url, cfApiToken);
        totalPages = Number(payload?.result_info?.total_pages || payload?.result_info?.totalPages || 1);
        for (const item of payload?.result || []) {
          const info = extractRouteHostnameInfo(item?.pattern);
          if (!info) continue;
          pushCandidate(info.hostname, { wildcard: info.wildcard, path: info.path });
        }
        page += 1;
      } while (page <= totalPages && page <= 5);
    } catch (e) {
      console.log("CF Workers routes lookup failed", e);
    }
  }

  if (candidates.length) {
    candidates.sort((a, b) => (b.score - a.score) || (a.hostname.length - b.hostname.length) || a.hostname.localeCompare(b.hostname));
    return candidates[0].hostname;
  }

  return zoneNameFallback || "未知域名 (请配置 CF 联动)";
}

function normalizeCloudflareWorkerScriptName(value = "") {
  const scriptName = String(value || "").trim();
  return /^[a-z0-9_][a-z0-9-_]*$/i.test(scriptName) ? scriptName : "";
}

function cloneJsonCompatibleValue(value) {
  if (value === undefined) return undefined;
  try {
    return JSON.parse(JSON.stringify(value));
  } catch {
    return null;
  }
}

function readCloudflareWorkerPlacementString(value, keys = [], options = {}) {
  if (typeof value === "string") return String(value).trim();
  if (!value || typeof value !== "object") return "";
  const normalizedKeys = Array.isArray(keys) ? keys : [];
  const fallbackKeys = ["id", "value", "name", "region", "provider", "providerId", "hostname", "host"];
  const exactKeys = normalizedKeys.length ? normalizedKeys : fallbackKeys;
  const allowFallback = options?.allowFallback !== false;
  const keyGroups = [exactKeys];
  if (allowFallback && normalizedKeys.length) keyGroups.push(fallbackKeys);
  const triedKeys = new Set();
  for (const group of keyGroups) {
    for (const key of group) {
      if (triedKeys.has(key)) continue;
      triedKeys.add(key);
      const candidate = value?.[key];
      if (typeof candidate === "string" && candidate.trim()) return candidate.trim();
      if (!candidate || typeof candidate !== "object") continue;
      for (const nestedKey of group) {
        const nestedValue = candidate?.[nestedKey];
        if (typeof nestedValue === "string" && nestedValue.trim()) return nestedValue.trim();
      }
    }
  }
  return "";
}

function formatCloudflareWorkerPlacementProviderLabel(providerId = "") {
  const normalizedProviderId = String(providerId || "").trim().toLowerCase();
  if (!normalizedProviderId) return "";
  if (normalizedProviderId === "aws") return "AWS";
  if (normalizedProviderId === "gcp" || normalizedProviderId === "google") return "GCP";
  if (normalizedProviderId === "azure") return "Azure";
  return normalizedProviderId.toUpperCase();
}

function inferCloudflareWorkerPlacementGeoMeta(regionId = "", providerId = "") {
  const normalizedRegionId = String(regionId || "").trim().toLowerCase().replace(/_/g, "-");
  const normalizedProviderId = String(providerId || "").trim().toLowerCase();
  const composite = `${normalizedProviderId}:${normalizedRegionId}`;
  if (!normalizedRegionId && !normalizedProviderId) {
    return { key: "other", label: "其他", sortOrder: 9 };
  }
  const includesAny = (candidates = []) => candidates.some(candidate => composite.includes(String(candidate || "").trim().toLowerCase()));
  if (includesAny([
    "wnam", "enam", "americas", "latam", "northamerica", "southamerica", "canada", "brazil", "mexico", "chile",
    "argentina", "eastus", "westus", "centralus", "northcentralus", "southcentralus", "us-east", "us-west",
    "us-central", "us-south", "ca-central", "ca-east", "sa-east", "na-", "sa-", "us-", "ca-"
  ])) {
    return { key: "americas", label: "美洲", sortOrder: 0 };
  }
  if (includesAny([
    "apac", "asia", "ap-", "australia", "japan", "korea", "singapore", "taiwan", "hongkong", "india", "jakarta",
    "sydney", "melbourne", "tokyo", "osaka", "seoul", "mumbai", "delhi", "perth", "newzealand"
  ])) {
    return { key: "asia-pacific", label: "亚太", sortOrder: 1 };
  }
  if (includesAny([
    "weur", "eeur", "europe", "eu-", "france", "germany", "italy", "spain", "poland", "sweden", "norway",
    "switzerland", "netherlands", "belgium", "ireland", "westeurope", "northeurope", "finland", "uk", "london"
  ])) {
    return { key: "europe", label: "欧洲", sortOrder: 2 };
  }
  if (includesAny([
    "mea", "middleeast", "me-", "af-", "africa", "uae", "qatar", "saudi", "israel", "bahrain", "kuwait",
    "southafrica", "johannesburg", "capetown", "doha", "telaviv"
  ])) {
    return { key: "middle-east-africa", label: "中东与非洲", sortOrder: 3 };
  }
  return { key: "other", label: "其他", sortOrder: 9 };
}

function normalizeCloudflareWorkerPlacementTargetEntries(value) {
  if (Array.isArray(value)) return value;
  if (value && typeof value === "object") return [value];
  if (typeof value === "string" && value.trim()) return [{ value }];
  return [];
}

function normalizeCloudflareWorkerPlacementRegionOptions(providers = []) {
  const options = [];
  const seenValues = new Set();
  for (const provider of Array.isArray(providers) ? providers : []) {
    const providerId = String(provider?.id || provider?.provider || provider?.providerId || "").trim().toLowerCase();
    if (!providerId) continue;
    const providerLabel = formatCloudflareWorkerPlacementProviderLabel(providerId);
    for (const region of Array.isArray(provider?.regions) ? provider.regions : []) {
      const regionId = String(region?.id || region?.region || region?.value || "").trim();
      if (!regionId) continue;
      const value = `${providerId}:${regionId}`;
      if (seenValues.has(value)) continue;
      seenValues.add(value);
      const geoMeta = inferCloudflareWorkerPlacementGeoMeta(regionId, providerId);
      options.push({
        provider: providerId,
        region: regionId,
        value,
        providerLabel,
        regionLabel: regionId,
        geoKey: geoMeta.key,
        geoLabel: geoMeta.label,
        geoSortOrder: geoMeta.sortOrder
      });
    }
  }
  return options.sort((left, right) => (
    String(left.providerLabel || left.provider || "").localeCompare(String(right.providerLabel || right.provider || ""))
    || Number(left.geoSortOrder || 0) - Number(right.geoSortOrder || 0)
    || String(left.regionLabel || left.region || "").localeCompare(String(right.regionLabel || right.region || ""))
    || String(left.value || "").localeCompare(String(right.value || ""))
  ));
}

/**
 * @param {unknown} value
 * @param {unknown} [provider]
 * @param {Array<{ region?: string, value?: string }>} [options]
 */
function normalizeCloudflareWorkerPlacementRegionValue(value, provider = "", options = []) {
  const rawValue = readCloudflareWorkerPlacementString(value, ["region", "value", "id"]);
  if (!rawValue) return "";
  if (rawValue.includes(":")) return rawValue;
  const providerId = readCloudflareWorkerPlacementString(provider, ["provider", "providerId", "id", "value"]).toLowerCase();
  if (providerId) return `${providerId}:${rawValue}`;
  const matches = (Array.isArray(options) ? options : []).filter(option => (
    String(option?.region || "").trim() === rawValue
    || String(option?.value || "").trim() === rawValue
  ));
  if (matches.length === 1) return String(matches[0]?.value || "").trim();
  return rawValue;
}

function normalizeCloudflareWorkerPlacementState(placement = {}, regionOptions = []) {
  const normalizedPlacement = /** @type {CloudflareWorkerPlacementLike} */ (
    placement && typeof placement === "object" ? placement : {}
  );
  const mode = String(normalizedPlacement?.mode || "").trim().toLowerCase();
  const targetEntries = normalizeCloudflareWorkerPlacementTargetEntries(normalizedPlacement?.target);
  const regionValue = normalizeCloudflareWorkerPlacementRegionValue(
    normalizedPlacement?.region,
    normalizedPlacement?.provider || normalizedPlacement?.providerId || "",
    regionOptions
  );
  const targetedRegionEntry = targetEntries.find(entry => (
    !!normalizeCloudflareWorkerPlacementRegionValue(
      readCloudflareWorkerPlacementString(entry, ["region", "value", "id"]),
      readCloudflareWorkerPlacementString(entry, ["provider", "providerId"]),
      regionOptions
    )
  ));
  const targetedRegionValue = targetedRegionEntry
    ? normalizeCloudflareWorkerPlacementRegionValue(
        readCloudflareWorkerPlacementString(targetedRegionEntry, ["region", "value", "id"]),
        readCloudflareWorkerPlacementString(targetedRegionEntry, ["provider", "providerId"]),
        regionOptions
      )
    : "";
  const hostnameValue = readCloudflareWorkerPlacementString(normalizedPlacement?.hostname, ["hostname"], { allowFallback: false })
    || readCloudflareWorkerPlacementString(normalizedPlacement, ["hostname"], { allowFallback: false });
  const targetedHostnameValue = readCloudflareWorkerPlacementString(
    targetEntries.find(entry => readCloudflareWorkerPlacementString(entry, ["hostname"], { allowFallback: false })),
    ["hostname"],
    { allowFallback: false }
  );
  const hostValue = readCloudflareWorkerPlacementString(normalizedPlacement?.host, ["host"], { allowFallback: false })
    || readCloudflareWorkerPlacementString(normalizedPlacement, ["host"], { allowFallback: false });
  const targetedHostValue = readCloudflareWorkerPlacementString(
    targetEntries.find(entry => readCloudflareWorkerPlacementString(entry, ["host"], { allowFallback: false })),
    ["host"],
    { allowFallback: false }
  );
  const targetedRawValue = readCloudflareWorkerPlacementString(targetEntries[0], ["value", "id"]);

  let currentMode = "default";
  let currentValue = "__default__";
  let currentTarget = "";
  let selectedMode = "default";
  let selectedRegion = "";

  if (mode === "smart") {
    currentMode = "smart";
    currentValue = "__smart__";
    selectedMode = "smart";
  } else if (mode === "targeted") {
    if (hostnameValue || targetedHostnameValue) {
      currentMode = "hostname";
      currentValue = "";
      currentTarget = hostnameValue || targetedHostnameValue;
      selectedMode = "";
    } else if (hostValue || targetedHostValue) {
      currentMode = "host";
      currentValue = "";
      currentTarget = hostValue || targetedHostValue;
      selectedMode = "";
    } else {
      currentMode = "targeted";
      currentValue = targetedRegionValue || regionValue || "";
      currentTarget = currentValue || targetedRawValue || "";
      selectedMode = "";
    }
  } else if (regionValue) {
    currentMode = "region";
    currentValue = regionValue;
    selectedMode = "region";
    selectedRegion = regionValue;
  } else if (hostnameValue) {
    currentMode = "hostname";
    currentValue = "";
    currentTarget = hostnameValue;
    selectedMode = "";
  } else if (hostValue) {
    currentMode = "host";
    currentValue = "";
    currentTarget = hostValue;
    selectedMode = "";
  } else if (targetedRegionValue || targetEntries.length > 0) {
    currentMode = "targeted";
    currentValue = targetedRegionValue || "";
    currentTarget = currentValue || targetedRawValue || "";
    selectedMode = "";
  }

  return {
    currentMode,
    currentValue,
    currentTarget,
    selectedMode,
    selectedRegion,
    isTargetedOverride: currentMode === "hostname" || currentMode === "host" || currentMode === "targeted"
  };
}

function buildCloudflareWorkerPlacementWarning(currentMode = "") {
  void currentMode;
  return "";
}

function formatCloudflareWorkerPlacementPermissionHintEntries(entries = []) {
  return (Array.isArray(entries) ? entries : [])
    .filter(entry => entry && typeof entry === "object")
    .map(entry => {
      const scope = String(entry.scope || "").trim();
      const permission = String(entry.permission || "").trim();
      const alternative = String(entry.alternative || "").trim();
      const note = String(entry.note || "").trim();
      const parts = [];
      if (scope) parts.push(`${scope}级`);
      if (permission) parts.push(`"${permission}"`);
      if (alternative) parts.push(`（若当前令牌仅授予写权限，可改用 "${alternative}"）`);
      if (note) parts.push(`：${note}`);
      return parts.join("");
    })
    .filter(Boolean);
}

function getCloudflareWorkerPlacementPermissionEntries(kind = "", options = {}) {
  const normalizedKind = String(kind || "").trim().toLowerCase();
  if (normalizedKind === "discovery") {
    const routeFallbackEnabled = options?.includeRouteFallback !== false;
    const entries = [{
      scope: "账号",
      permission: "Workers Scripts Read",
      alternative: "Workers Scripts Write",
      note: "用于读取 Workers Domains，按当前 host 自动识别脚本"
    }];
    if (routeFallbackEnabled) {
      entries.push({
        scope: "Zone",
        permission: "Workers Routes Read",
        alternative: "Workers Routes Write",
        note: "当 Domains 未命中时，允许继续从 Workers Routes 回退识别脚本"
      });
    }
    return entries;
  }
  if (normalizedKind === "settings_read") {
    return [{
      scope: "账号",
      permission: "Workers Scripts Read",
      alternative: "Workers Scripts Write",
      note: "用于读取 Worker Settings"
    }];
  }
  if (normalizedKind === "regions_read") {
    return [{
      scope: "账号",
      permission: "Workers Scripts Read",
      alternative: "Workers Scripts Write",
      note: "用于读取 Placement 区域列表"
    }];
  }
  if (normalizedKind === "settings_write") {
    return [{
      scope: "账号",
      permission: "Workers Scripts Write",
      alternative: "",
      note: "用于写入 Worker Settings / Placement"
    }];
  }
  return [];
}

function buildCloudflareWorkerPlacementPermissionMessage(kind = "", operation = "读取", options = {}) {
  const entries = formatCloudflareWorkerPlacementPermissionHintEntries(
    getCloudflareWorkerPlacementPermissionEntries(kind, options)
  );
  if (entries.length <= 0) {
    return `Cloudflare Worker 放置${operation}失败：API Token 权限不足`;
  }
  return `Cloudflare Worker 放置${operation}失败：API Token 权限不足。至少需要：${entries.join("；")}`;
}

function createCloudflareWorkerPlacementPermissionError(code = "WORKER_PLACEMENT_FORBIDDEN", kind = "", operation = "读取", options = {}) {
  return createStructuredConfigError(
    code,
    buildCloudflareWorkerPlacementPermissionMessage(kind, operation, options),
    403,
    {
      permissionKind: String(kind || "").trim(),
      requiredPermissions: getCloudflareWorkerPlacementPermissionEntries(kind, options)
    }
  );
}

function normalizeCloudflareWorkerScriptUploadFileName(fileName = "worker.js") {
  const basename = String(fileName || "")
    .trim()
    .split(/[\\/]+/)
    .pop() || "";
  return basename && /\.js$/i.test(basename) ? basename : "";
}

function detectCloudflareWorkerScriptUploadSyntax(scriptContent = "") {
  const text = String(scriptContent || "");
  if (!text) return "service-worker";
  if (/(^|\n)\s*export\s+/m.test(text)) return "module";
  if (/(^|\n)\s*import\s+(?:[\w*{]|["'])/m.test(text)) return "module";
  return "service-worker";
}

function buildCloudflareWorkerScriptUploadMetadata(fileName = "", syntax = "module") {
  const normalizedFileName = normalizeCloudflareWorkerScriptUploadFileName(fileName) || "worker.js";
  return syntax === "module"
    ? { main_module: normalizedFileName }
    : { body_part: normalizedFileName };
}

function buildCloudflareWorkerScriptUploadContentType(syntax = "module") {
  return syntax === "module" ? "application/javascript+module" : "application/javascript";
}

function getCloudflareWorkerScriptUpdatePermissionEntries() {
  return [{
    scope: "账号",
    permission: "Workers Scripts Write",
    alternative: "",
    note: "这是账号级 Worker 脚本编辑权限，用于上传 .js 文件并仅更新脚本代码，不修改 bindings 或 settings"
  }];
}

function buildCloudflareWorkerScriptUpdatePermissionMessage(operation = "更新") {
  const entries = formatCloudflareWorkerPlacementPermissionHintEntries(
    getCloudflareWorkerScriptUpdatePermissionEntries()
  );
  return entries.length > 0
    ? `Cloudflare Worker 脚本${operation}失败：API Token 权限不足。至少需要：${entries.join("；")}`
    : `Cloudflare Worker 脚本${operation}失败：API Token 权限不足`;
}

function createCloudflareWorkerScriptUpdatePermissionError(code = "WORKER_SCRIPT_UPDATE_FORBIDDEN", operation = "更新") {
  return createStructuredConfigError(
    code,
    buildCloudflareWorkerScriptUpdatePermissionMessage(operation),
    403,
    {
      requiredPermissions: getCloudflareWorkerScriptUpdatePermissionEntries()
    }
  );
}

async function updateCloudflareWorkerScriptContent(accountId, scriptName, apiToken, scriptContent, options = {}) {
  const normalizedAccountId = String(accountId || "").trim();
  const normalizedScriptName = normalizeCloudflareWorkerScriptName(scriptName);
  const normalizedApiToken = String(apiToken || "").trim();
  const normalizedFileName = normalizeCloudflareWorkerScriptUploadFileName(options?.fileName) || "worker.js";
  const normalizedScriptContent = String(scriptContent || "");
  const syntax = detectCloudflareWorkerScriptUploadSyntax(normalizedScriptContent);
  const formData = new FormData();
  formData.append(
    "metadata",
    new Blob([JSON.stringify(buildCloudflareWorkerScriptUploadMetadata(normalizedFileName, syntax))], {
      type: "application/json"
    }),
    "metadata.json"
  );
  formData.append(
    "files",
    new Blob([normalizedScriptContent], {
      type: buildCloudflareWorkerScriptUploadContentType(syntax)
    }),
    normalizedFileName
  );
  let payload = null;
  try {
    payload = await fetchCloudflareApiJson(
      `https://api.cloudflare.com/client/v4/accounts/${encodeURIComponent(normalizedAccountId)}/workers/scripts/${encodeURIComponent(normalizedScriptName)}/content`,
      normalizedApiToken,
      {
        method: "PUT",
        body: formData
      }
    );
  } catch (error) {
    if (Number(error?.status) === 403) {
      throw createCloudflareWorkerScriptUpdatePermissionError(
        "WORKER_SCRIPT_UPDATE_FORBIDDEN",
        "更新"
      );
    }
    throw error;
  }
  return {
    syntax,
    fileName: normalizedFileName,
    result: isPlainObject(payload?.result) ? payload.result : {}
  };
}

function normalizeCloudflareWorkerScriptUpdateErrorMessage(error) {
  const message = String(error?.message || error || "").trim() || "Worker 脚本更新失败";
  const status = Number(error?.status) || Number(/cf_api_http_(\d+)/i.exec(message)?.[1] || 0);
  const errorCode = String(error?.code || "").trim().toUpperCase();
  if (errorCode === "WORKER_SCRIPT_UPDATE_FORBIDDEN" && String(error?.message || "").trim()) {
    return error.message;
  }
  if (errorCode === "WORKER_PLACEMENT_SCRIPT_DISCOVERY_FORBIDDEN") {
    return String(error?.message || "")
      .replace("Cloudflare Worker 放置读取失败", "Cloudflare Worker 脚本定位失败")
      .trim();
  }
  if (
    errorCode === "WORKER_PLACEMENT_SCRIPT_UNRESOLVED"
    || errorCode === "WORKER_PLACEMENT_HOST_INVALID"
    || errorCode === "WORKER_PLACEMENT_CONFIG_REQUIRED"
  ) {
    return message;
  }
  if (status === 401) return "Cloudflare Worker 快捷更新失败：API Token 无效";
  if (status === 403) return buildCloudflareWorkerScriptUpdatePermissionMessage("更新");
  if (status === 404) return "Cloudflare Worker 快捷更新失败：未找到目标 Worker 脚本";
  return message;
}

function createWorkerPlacementStatusPayload(overrides = {}) {
  const normalizedOverrides = /** @type {WorkerPlacementStatusPayloadOverrides} */ (
    overrides && typeof overrides === "object" && !Array.isArray(overrides) ? overrides : {}
  );
  const hasCurrentValue = Object.prototype.hasOwnProperty.call(normalizedOverrides, "currentValue");
  const hasSelectedMode = Object.prototype.hasOwnProperty.call(normalizedOverrides, "selectedMode");
  return {
    configured: normalizedOverrides.configured === true,
    scriptName: String(normalizedOverrides.scriptName || "").trim(),
    requestHost: normalizeHostnameText(normalizedOverrides.requestHost || ""),
    currentMode: String(normalizedOverrides.currentMode || "default").trim().toLowerCase() || "default",
    currentValue: hasCurrentValue
      ? String(normalizedOverrides.currentValue ?? "").trim()
      : "__default__",
    currentTarget: String(normalizedOverrides.currentTarget || "").trim(),
    selectedMode: hasSelectedMode
      ? String(normalizedOverrides.selectedMode ?? "").trim().toLowerCase()
      : "default",
    selectedRegion: String(normalizedOverrides.selectedRegion || "").trim(),
    options: Array.isArray(normalizedOverrides.options) ? normalizedOverrides.options : [],
    warning: String(normalizedOverrides.warning || "").trim(),
    error: String(normalizedOverrides.error || "").trim()
  };
}

function matchesCloudflareWorkerHostnameCandidate(requestHost = "", candidateHostname = "", wildcard = false) {
  const normalizedRequestHost = normalizeHostnameText(requestHost);
  const normalizedCandidateHostname = normalizeHostnameText(candidateHostname);
  if (!normalizedRequestHost || !normalizedCandidateHostname) return false;
  if (!wildcard) return normalizedRequestHost === normalizedCandidateHostname;
  return normalizedRequestHost === normalizedCandidateHostname
    || normalizedRequestHost.endsWith(`.${normalizedCandidateHostname}`);
}

function matchesCloudflareWorkerRoutePath(routePath = "", requestPath = "/") {
  const normalizedRoutePath = String(routePath || "").trim();
  const normalizedRequestPath = String(requestPath || "/").trim() || "/";
  if (!normalizedRoutePath || normalizedRoutePath === "/" || normalizedRoutePath === "/*") return true;
  if (normalizedRoutePath.endsWith("*")) return normalizedRequestPath.startsWith(normalizedRoutePath.slice(0, -1));
  return normalizedRequestPath === normalizedRoutePath;
}

function buildCloudflareWorkerDomainScriptCandidate(item = {}) {
  const hostname = normalizeHostnameText(item?.hostname || "");
  const scriptName = normalizeCloudflareWorkerScriptName(item?.service || item?.script || item?.name || "");
  if (!hostname || !scriptName) return null;
  return {
    source: "domains",
    hostname,
    wildcard: false,
    path: "/",
    scriptName,
    score: scoreHostnameCandidate(hostname, { wildcard: false, path: "/" })
  };
}

function buildCloudflareWorkerRouteScriptCandidate(item = {}) {
  const info = extractRouteHostnameInfo(item?.pattern);
  const scriptName = normalizeCloudflareWorkerScriptName(item?.script || item?.service || item?.name || "");
  if (!info || !scriptName) return null;
  return {
    source: "routes",
    hostname: info.hostname,
    wildcard: info.wildcard === true,
    path: info.path || "/",
    pattern: info.pattern,
    scriptName,
    score: scoreHostnameCandidate(info.hostname, { wildcard: info.wildcard === true, path: info.path || "/" })
  };
}

function pickCloudflareWorkerScriptCandidate(candidates = [], requestHost = "", requestPath = "/") {
  const normalizedRequestHost = normalizeHostnameText(requestHost);
  const normalizedRequestPath = String(requestPath || "/").trim() || "/";
  const filteredCandidates = [];
  for (const candidate of Array.isArray(candidates) ? candidates : []) {
    if (!candidate?.scriptName || !candidate?.hostname) continue;
    const hostnameMatched = matchesCloudflareWorkerHostnameCandidate(
      normalizedRequestHost,
      candidate.hostname,
      candidate.wildcard === true
    );
    if (!hostnameMatched) continue;
    if (!matchesCloudflareWorkerRoutePath(candidate.path || "/", normalizedRequestPath)) continue;
    filteredCandidates.push({
      ...candidate,
      exactHostname: normalizedRequestHost === normalizeHostnameText(candidate.hostname),
      exactPath: String(candidate.path || "/") === normalizedRequestPath
    });
  }
  if (filteredCandidates.length > 0) {
    filteredCandidates.sort((left, right) => (
      Number(right.exactHostname) - Number(left.exactHostname)
      || Number(right.exactPath) - Number(left.exactPath)
      || Number(right.score || 0) - Number(left.score || 0)
      || String(left.hostname || "").length - String(right.hostname || "").length
      || String(left.scriptName || "").localeCompare(String(right.scriptName || ""))
    ));
    return filteredCandidates[0];
  }
  const uniqueScriptNames = [...new Set((Array.isArray(candidates) ? candidates : []).map(candidate => String(candidate?.scriptName || "").trim()).filter(Boolean))];
  if (uniqueScriptNames.length === 1) {
    return (Array.isArray(candidates) ? candidates : []).find(candidate => String(candidate?.scriptName || "").trim() === uniqueScriptNames[0]) || null;
  }
  return null;
}

async function listCloudflareWorkerPlacementRegions(accountId, apiToken) {
  const normalizedAccountId = String(accountId || "").trim();
  const normalizedApiToken = String(apiToken || "").trim();
  if (!normalizedAccountId || !normalizedApiToken) return [];
  let payload = null;
  try {
    payload = await fetchCloudflareApiJson(
      `https://api.cloudflare.com/client/v4/accounts/${encodeURIComponent(normalizedAccountId)}/workers/placement/regions`,
      normalizedApiToken
    );
  } catch (error) {
    if (Number(error?.status) === 403) {
      throw createCloudflareWorkerPlacementPermissionError(
        "WORKER_PLACEMENT_REGIONS_FORBIDDEN",
        "regions_read",
        "读取"
      );
    }
    throw error;
  }
  return normalizeCloudflareWorkerPlacementRegionOptions(payload?.result?.providers);
}

async function listCloudflareWorkerDomains(accountId, apiToken, options = {}) {
  const normalizedAccountId = String(accountId || "").trim();
  const normalizedApiToken = String(apiToken || "").trim();
  if (!normalizedAccountId || !normalizedApiToken) return [];
  const url = new URL(`https://api.cloudflare.com/client/v4/accounts/${encodeURIComponent(normalizedAccountId)}/workers/domains`);
  const zoneId = String(options?.zoneId || "").trim();
  const hostname = normalizeHostnameText(options?.hostname || "");
  const service = normalizeCloudflareWorkerScriptName(options?.service || "");
  if (zoneId) url.searchParams.set("zone_id", zoneId);
  if (hostname) url.searchParams.set("hostname", hostname);
  if (service) url.searchParams.set("service", service);
  const payload = await fetchCloudflareApiJson(url.toString(), normalizedApiToken);
  return Array.isArray(payload?.result) ? payload.result : [];
}

async function listCloudflareWorkerRoutes(zoneId, apiToken) {
  const normalizedZoneId = String(zoneId || "").trim();
  const normalizedApiToken = String(apiToken || "").trim();
  if (!normalizedZoneId || !normalizedApiToken) return [];
  const routes = [];
  let page = 1;
  let totalPages = 1;
  do {
    const payload = await fetchCloudflareApiJson(
      `https://api.cloudflare.com/client/v4/zones/${encodeURIComponent(normalizedZoneId)}/workers/routes?page=${page}&per_page=100`,
      normalizedApiToken
    );
    if (Array.isArray(payload?.result)) routes.push(...payload.result);
    totalPages = Number(payload?.result_info?.total_pages || payload?.result_info?.totalPages || 1);
    page += 1;
  } while (page <= totalPages && page <= 10);
  return routes;
}

async function resolveCloudflareWorkerScriptContext({ cfAccountId, cfZoneId, cfApiToken, request }) {
  const requestUrl = new URL(request?.url || "https://invalid.local/");
  const requestHost = normalizeHostnameText(requestUrl.hostname);
  const requestPath = String(requestUrl.pathname || "/").trim() || "/";
  if (!requestHost) {
    throw createStructuredConfigError(
      "WORKER_PLACEMENT_HOST_INVALID",
      "当前请求 host 无效，无法识别 Worker 脚本",
      400
    );
  }

  const domainCandidates = [];
  const domainCandidateSignatures = new Set();
  let lastLookupError = null;
  let domainsForbidden = false;
  let routesForbidden = false;
  const domainQueries = [
    { zoneId: cfZoneId, hostname: requestHost },
    { hostname: requestHost },
    { zoneId: cfZoneId }
  ];
  for (const query of domainQueries) {
    const querySignature = JSON.stringify({
      zoneId: String(query?.zoneId || "").trim(),
      hostname: normalizeHostnameText(query?.hostname || "")
    });
    if (domainCandidateSignatures.has(`query:${querySignature}`)) continue;
    domainCandidateSignatures.add(`query:${querySignature}`);
    try {
      const result = await listCloudflareWorkerDomains(cfAccountId, cfApiToken, query);
      for (const item of result) {
        const candidate = buildCloudflareWorkerDomainScriptCandidate(item);
        if (!candidate) continue;
        const signature = `${candidate.source}|${candidate.scriptName}|${candidate.hostname}|${candidate.path}`;
        if (domainCandidateSignatures.has(signature)) continue;
        domainCandidateSignatures.add(signature);
        domainCandidates.push(candidate);
      }
      const matchedCandidate = pickCloudflareWorkerScriptCandidate(domainCandidates, requestHost, requestPath);
      if (matchedCandidate?.scriptName) {
        return {
          requestHost,
          requestPath,
          scriptName: matchedCandidate.scriptName,
          resolvedBy: matchedCandidate.source
        };
      }
    } catch (error) {
      lastLookupError = error;
      if (Number(error?.status) === 403) domainsForbidden = true;
      console.warn("[worker_placement.resolve_script.domains_failed]", {
        requestHost,
        zoneId: String(query?.zoneId || "").trim(),
        hostname: normalizeHostnameText(query?.hostname || ""),
        reason: getErrorMessage(error)
      });
    }
  }

  try {
    const routeCandidates = listCloudflareWorkerRoutes(cfZoneId, cfApiToken)
      .then(result => result.map(item => buildCloudflareWorkerRouteScriptCandidate(item)).filter(Boolean));
    const matchedRouteCandidate = pickCloudflareWorkerScriptCandidate(await routeCandidates, requestHost, requestPath);
    if (matchedRouteCandidate?.scriptName) {
      return {
        requestHost,
        requestPath,
        scriptName: matchedRouteCandidate.scriptName,
        resolvedBy: matchedRouteCandidate.source
      };
    }
  } catch (error) {
    lastLookupError = error;
    if (Number(error?.status) === 403) routesForbidden = true;
    console.warn("[worker_placement.resolve_script.routes_failed]", {
      requestHost,
      zoneId: String(cfZoneId || "").trim(),
      reason: getErrorMessage(error)
    });
  }

  if (domainsForbidden || routesForbidden) {
    throw createCloudflareWorkerPlacementPermissionError(
      "WORKER_PLACEMENT_SCRIPT_DISCOVERY_FORBIDDEN",
      "discovery",
      "读取",
      { includeRouteFallback: routesForbidden }
    );
  }
  if (lastLookupError) throw lastLookupError;
  throw createStructuredConfigError(
    "WORKER_PLACEMENT_SCRIPT_UNRESOLVED",
    "未能根据当前站点自动识别 Worker 脚本，请确认当前 host 已绑定到该 Zone 的 Workers Domain 或 Workers Route",
    400,
    { requestHost }
  );
}

async function fetchCloudflareWorkerSettings(accountId, scriptName, apiToken) {
  let payload = null;
  try {
    payload = await fetchCloudflareApiJson(
      `https://api.cloudflare.com/client/v4/accounts/${encodeURIComponent(String(accountId || "").trim())}/workers/scripts/${encodeURIComponent(String(scriptName || "").trim())}/settings`,
      String(apiToken || "").trim()
    );
  } catch (error) {
    if (Number(error?.status) === 403) {
      throw createCloudflareWorkerPlacementPermissionError(
        "WORKER_PLACEMENT_SETTINGS_READ_FORBIDDEN",
        "settings_read",
        "读取"
      );
    }
    throw error;
  }
  return isPlainObject(payload?.result) ? payload.result : {};
}

async function patchCloudflareWorkerSettings(accountId, scriptName, apiToken, settingsPatch = {}) {
  const formData = new FormData();
  formData.append(
    "settings",
    new Blob([JSON.stringify(settingsPatch && typeof settingsPatch === "object" ? settingsPatch : {})], {
      type: "application/json"
    }),
    "settings.json"
  );
  let payload = null;
  try {
    payload = await fetchCloudflareApiJson(
      `https://api.cloudflare.com/client/v4/accounts/${encodeURIComponent(String(accountId || "").trim())}/workers/scripts/${encodeURIComponent(String(scriptName || "").trim())}/settings`,
      String(apiToken || "").trim(),
      {
        method: "PATCH",
        body: formData
      }
    );
  } catch (error) {
    if (Number(error?.status) === 403) {
      throw createCloudflareWorkerPlacementPermissionError(
        "WORKER_PLACEMENT_SETTINGS_WRITE_FORBIDDEN",
        "settings_write",
        "保存"
      );
    }
    throw error;
  }
  return isPlainObject(payload?.result) ? payload.result : {};
}

function normalizeCloudflareWorkerPlacementErrorMessage(error, operation = "read") {
  const actionText = operation === "write" ? "保存" : operation === "default" ? "恢复默认" : "读取";
  const message = String(error?.message || error || "").trim() || `Worker 放置${actionText}失败`;
  const status = Number(error?.status) || Number(/cf_api_http_(\d+)/i.exec(message)?.[1] || 0);
  const errorCode = String(error?.code || "").trim().toUpperCase();
  if (errorCode.startsWith("WORKER_PLACEMENT_") && String(error?.message || "").trim()) return error.message;
  if (status === 401) return `Cloudflare Worker 放置${actionText}失败：API Token 无效`;
  if (status === 403) return `Cloudflare Worker 放置${actionText}失败：API Token 权限不足`;
  if (status === 404 && operation !== "read") return "Cloudflare Worker 放置保存失败：未找到目标 Worker 脚本";
  if (status === 404) return "Cloudflare Worker 放置读取失败：未找到目标 Worker 脚本";
  if (errorCode === "WORKER_PLACEMENT_SCRIPT_UNRESOLVED") return error.message;
  if (errorCode === "WORKER_PLACEMENT_HOST_INVALID") return error.message;
  if (errorCode === "WORKER_PLACEMENT_CONFIG_REQUIRED") return error.message;
  return message;
}

function assertCloudflareWorkerPlacementConfig(config = {}) {
  const cfAccountId = String(config?.cfAccountId || "").trim();
  const cfZoneId = String(config?.cfZoneId || "").trim();
  const cfApiToken = String(config?.cfApiToken || "").trim();
  const missingFields = [];
  if (!cfAccountId) missingFields.push("cfAccountId");
  if (!cfZoneId) missingFields.push("cfZoneId");
  if (!cfApiToken) missingFields.push("cfApiToken");
  if (missingFields.length <= 0) {
    return { cfAccountId, cfZoneId, cfApiToken };
  }
  throw createStructuredConfigError(
    "WORKER_PLACEMENT_CONFIG_REQUIRED",
    "请先在账号设置中填写并保存 Cloudflare Account ID、Zone ID 与 API Token",
    400,
    { missingFields }
  );
}

function getWorkerPlacementRegionOverrideKey(scriptName = "") {
  const normalizedScriptName = normalizeCloudflareWorkerScriptName(scriptName);
  return normalizedScriptName ? `${Database.WORKER_PLACEMENT_REGION_OVERRIDE_PREFIX}${normalizedScriptName}` : "";
}

function createWorkerPlacementKvMutationError(code = "WORKER_PLACEMENT_KV_FAILED", message = "Worker 放置 KV 持久化失败", details = null) {
  return createStructuredConfigError(code, message, 503, details);
}

function isWorkerPlacementKvMutationError(error) {
  return isStructuredAppError(error)
    && String(error?.code || "").trim().toUpperCase().startsWith("WORKER_PLACEMENT_")
    && String(error?.details?.dependency || "").trim().toUpperCase() === "KV";
}

function normalizeWorkerPlacementRegionOverrideRecord(value = {}, scriptName = "") {
  const normalizedScriptName = normalizeCloudflareWorkerScriptName(scriptName);
  if (!normalizedScriptName || !isPlainObject(value)) return null;
  const normalizedRegion = normalizeCloudflareWorkerPlacementRegionValue(
    value?.region,
    value?.provider || value?.providerId || "",
    []
  );
  if (!normalizedRegion) return null;
  return {
    scriptName: normalizedScriptName,
    region: normalizedRegion,
    updatedAt: String(value?.updatedAt || "").trim()
  };
}

async function readWorkerPlacementRegionOverride(kv, scriptName = "") {
  if (!kv) return null;
  const key = getWorkerPlacementRegionOverrideKey(scriptName);
  if (!key) return null;
  const stored = await kvGetStrict(kv, key, { type: "json" });
  return normalizeWorkerPlacementRegionOverrideRecord(stored, scriptName);
}

async function writeWorkerPlacementRegionOverride(kv, scriptName = "", region = "") {
  if (!kv) {
    throw createWorkerPlacementKvMutationError(
      "WORKER_PLACEMENT_REGION_OVERRIDE_WRITE_FAILED",
      "Worker 放置 Region 持久化失败：KV 未配置",
      { dependency: "KV", operation: "put", reason: "kv_not_configured" }
    );
  }
  const key = getWorkerPlacementRegionOverrideKey(scriptName);
  const normalizedScriptName = normalizeCloudflareWorkerScriptName(scriptName);
  const normalizedRegion = normalizeCloudflareWorkerPlacementRegionValue(region, "", []);
  if (!key || !normalizedScriptName || !normalizedRegion) {
    throw createWorkerPlacementKvMutationError(
      "WORKER_PLACEMENT_REGION_OVERRIDE_WRITE_FAILED",
      "Worker 放置 Region 持久化失败：Region 数据无效",
      {
        dependency: "KV",
        operation: "put",
        key,
        scriptName: normalizedScriptName,
        region: normalizedRegion,
        reason: "invalid_region_override"
      }
    );
  }
  const payload = {
    scriptName: normalizedScriptName,
    region: normalizedRegion,
    updatedAt: new Date().toISOString()
  };
  try {
    await kv.put(key, JSON.stringify(payload));
  } catch (error) {
    throw createWorkerPlacementKvMutationError(
      "WORKER_PLACEMENT_REGION_OVERRIDE_WRITE_FAILED",
      "Worker 放置 Region 持久化失败：KV 写入异常",
      {
        dependency: "KV",
        operation: "put",
        key,
        scriptName: normalizedScriptName,
        region: normalizedRegion,
        reason: getErrorMessage(error)
      }
    );
  }
  return payload;
}

async function deleteWorkerPlacementRegionOverride(kv, scriptName = "") {
  if (!kv) {
    throw createWorkerPlacementKvMutationError(
      "WORKER_PLACEMENT_REGION_OVERRIDE_DELETE_FAILED",
      "Worker 放置 Region 清理失败：KV 未配置",
      { dependency: "KV", operation: "delete", reason: "kv_not_configured" }
    );
  }
  const key = getWorkerPlacementRegionOverrideKey(scriptName);
  const normalizedScriptName = normalizeCloudflareWorkerScriptName(scriptName);
  if (!key || !normalizedScriptName) return false;
  try {
    await kv.delete(key);
  } catch (error) {
    throw createWorkerPlacementKvMutationError(
      "WORKER_PLACEMENT_REGION_OVERRIDE_DELETE_FAILED",
      "Worker 放置 Region 清理失败：KV 删除异常",
      {
        dependency: "KV",
        operation: "delete",
        key,
        scriptName: normalizedScriptName,
        reason: getErrorMessage(error)
      }
    );
  }
  return true;
}

function buildWorkerPlacementRegionOverrideMissingOptionMessage(region = "") {
  const normalizedRegion = String(region || "").trim();
  return normalizedRegion
    ? `当前已保存的 Worker Placement Region（${normalizedRegion}）已不在 Cloudflare 可选区域列表中，请重新选择并保存`
    : "当前已保存的 Worker Placement Region 已不在 Cloudflare 可选区域列表中，请重新选择并保存";
}

function buildWorkerPlacementRegionStatusPayload(scriptName = "", requestHost = "", region = "", regionOptions = [], options = {}) {
  const normalizedRegion = normalizeCloudflareWorkerPlacementRegionValue(region, "", regionOptions);
  const normalizedOptions = Array.isArray(regionOptions) ? regionOptions : [];
  const regionOption = normalizedOptions.find(option => String(option?.value || "").trim() === normalizedRegion) || null;
  const regionError = options?.regionError || null;
  const explicitError = String(options?.error || "").trim();
  let errorMessage = explicitError;
  if (!errorMessage && regionError) {
    errorMessage = normalizeCloudflareWorkerPlacementErrorMessage(regionError, "read");
  } else if (!errorMessage && normalizedRegion && normalizedOptions.length > 0 && !regionOption) {
    errorMessage = buildWorkerPlacementRegionOverrideMissingOptionMessage(normalizedRegion);
  }
  return createWorkerPlacementStatusPayload({
    configured: options?.configured !== false,
    scriptName,
    requestHost,
    currentMode: "region",
    currentValue: normalizedRegion,
    currentTarget: "",
    selectedMode: "region",
    selectedRegion: normalizedRegion,
    options: normalizedOptions,
    warning: "",
    error: errorMessage
  });
}

async function rollbackWorkerPlacementAfterKvMutationFailure(accountId, scriptName, apiToken, options = {}) {
  let rollbackAttempted = false;
  let rollbackSucceeded = false;
  let rollbackError = "";
  try {
    const previousOverride = normalizeWorkerPlacementRegionOverrideRecord(options?.previousOverride, scriptName);
    const originalState = options?.originalState && typeof options.originalState === "object"
      ? options.originalState
      : normalizeCloudflareWorkerPlacementState(options?.originalPlacement, options?.regionOptions);
    if (previousOverride?.region) {
      rollbackAttempted = true;
      await patchCloudflareWorkerSettings(accountId, scriptName, apiToken, {
        placement: { region: previousOverride.region }
      });
      rollbackSucceeded = true;
      return { rollbackAttempted, rollbackSucceeded, rollbackError };
    }
    rollbackAttempted = true;
    if (String(originalState?.currentMode || "").trim().toLowerCase() === "default") {
      await clearCloudflareWorkerPlacementToDefault(accountId, scriptName, apiToken, options?.regionOptions);
    } else {
      await patchCloudflareWorkerSettings(accountId, scriptName, apiToken, {
        placement: cloneJsonCompatibleValue(options?.originalPlacement)
      });
    }
    rollbackSucceeded = true;
  } catch (error) {
    rollbackSucceeded = false;
    rollbackError = getErrorMessage(error);
  }
  return { rollbackAttempted, rollbackSucceeded, rollbackError };
}

async function buildCloudflareWorkerPlacementStatusPayload(config = {}, request, options = {}) {
  let scriptName = "";
  let requestHost = "";
  try {
    const authContext = assertCloudflareWorkerPlacementConfig(config);
    const scriptContext = await resolveCloudflareWorkerScriptContext({
      ...authContext,
      request
    });
    scriptName = scriptContext.scriptName;
    requestHost = scriptContext.requestHost;
    const regionOverride = await readWorkerPlacementRegionOverride(options?.kv, scriptContext.scriptName);
    let regionOptions = [];
    let regionError = null;
    try {
      regionOptions = await listCloudflareWorkerPlacementRegions(authContext.cfAccountId, authContext.cfApiToken);
    } catch (error) {
      regionError = error;
    }
    if (regionOverride?.region) {
      return buildWorkerPlacementRegionStatusPayload(
        scriptContext.scriptName,
        scriptContext.requestHost,
        regionOverride.region,
        regionOptions,
        {
          configured: !regionError,
          regionError
        }
      );
    }
    const settings = await fetchCloudflareWorkerSettings(authContext.cfAccountId, scriptContext.scriptName, authContext.cfApiToken);
    const placementSettings = cloneJsonCompatibleValue(settings?.placement);
    const placementState = normalizeCloudflareWorkerPlacementState(placementSettings, regionOptions);
    if (placementState.currentMode === "region" && placementState.currentValue) {
      await writeWorkerPlacementRegionOverride(options?.kv, scriptContext.scriptName, placementState.currentValue);
      return buildWorkerPlacementRegionStatusPayload(
        scriptContext.scriptName,
        scriptContext.requestHost,
        placementState.currentValue,
        regionOptions,
        {
          configured: !regionError,
          regionError
        }
      );
    }
    return createWorkerPlacementStatusPayload({
      configured: !regionError,
      scriptName: scriptContext.scriptName,
      requestHost: scriptContext.requestHost,
      currentMode: placementState.currentMode,
      currentValue: placementState.currentValue,
      currentTarget: placementState.currentTarget,
      selectedMode: placementState.selectedMode,
      selectedRegion: placementState.selectedRegion,
      options: regionOptions,
      warning: "",
      error: regionError ? normalizeCloudflareWorkerPlacementErrorMessage(regionError, "read") : ""
    });
  } catch (error) {
    if (isStructuredKvReadError(error) || isWorkerPlacementKvMutationError(error)) throw error;
    if (options?.softFail !== true) throw error;
    return createWorkerPlacementStatusPayload({
      configured: false,
      scriptName,
      requestHost,
      selectedMode: "",
      currentMode: "default",
      currentValue: "__default__",
      error: normalizeCloudflareWorkerPlacementErrorMessage(error, "read")
    });
  }
}

async function clearCloudflareWorkerPlacementToDefault(accountId, scriptName, apiToken, regionOptions = []) {
  const originalSettings = await fetchCloudflareWorkerSettings(accountId, scriptName, apiToken);
  const originalPlacement = cloneJsonCompatibleValue(originalSettings?.placement);
  const originalState = normalizeCloudflareWorkerPlacementState(originalPlacement, regionOptions);
  if (originalState.currentMode === "default") {
    return {
      settings: originalSettings,
      placementState: originalState,
      clearedBy: "already_default"
    };
  }

  const attempts = [
    { tag: "empty_object", patch: { placement: {} } },
    { tag: "null", patch: { placement: null } }
  ];
  for (const attempt of attempts) {
    await patchCloudflareWorkerSettings(accountId, scriptName, apiToken, attempt.patch);
    const nextSettings = await fetchCloudflareWorkerSettings(accountId, scriptName, apiToken);
    const nextState = normalizeCloudflareWorkerPlacementState(nextSettings?.placement, regionOptions);
    if (nextState.currentMode === "default") {
      return {
        settings: nextSettings,
        placementState: nextState,
        clearedBy: attempt.tag
      };
    }
  }

  let rollbackAttempted = false;
  let rollbackSucceeded = false;
  let rollbackError = "";
  if (originalPlacement !== undefined) {
    rollbackAttempted = true;
    try {
      await patchCloudflareWorkerSettings(accountId, scriptName, apiToken, { placement: originalPlacement });
      rollbackSucceeded = true;
    } catch (error) {
      rollbackSucceeded = false;
      rollbackError = getErrorMessage(error);
    }
  }

  throw createStructuredConfigError(
    "WORKER_PLACEMENT_DEFAULT_BLOCKED",
    "Cloudflare 当前接口未验证出可安全恢复 Default Placement；本次已停止，未使用近似映射",
    409,
    {
      scriptName,
      rollbackAttempted,
      rollbackSucceeded,
      rollbackError
    }
  );
}

function migrateRuntimeConfigLegacyAliases(input = {}) {
  const rawConfig = /** @type {Record<string, any>} */ (
    input && typeof input === "object" && !Array.isArray(input) ? input : {}
  );
  const migratedConfig = { ...rawConfig };
  let migrated = false;
  const legacyKeysPresent = [];
  const migratedConfigKeys = [];
  const migratedKeyMap = {};

  for (const legacyKey of CONFIG_LEGACY_MIGRATION_SOURCE_FIELDS) {
    if (!Object.prototype.hasOwnProperty.call(rawConfig, legacyKey)) continue;
    legacyKeysPresent.push(legacyKey);
  }

  const pushMigratedKey = (sourceKey, targetKey) => {
    const normalizedSource = String(sourceKey || "").trim();
    const normalizedTarget = String(targetKey || "").trim();
    if (!normalizedSource || !normalizedTarget) return;
    migratedConfigKeys.push(normalizedTarget);
    if (!migratedKeyMap[normalizedSource]) migratedKeyMap[normalizedSource] = [];
    migratedKeyMap[normalizedSource].push(normalizedTarget);
  };

  if (!Object.prototype.hasOwnProperty.call(migratedConfig, "sourceDirectNodes")) {
    for (const sourceKey of CONFIG_SOURCE_DIRECT_NODE_ALIAS_FIELDS) {
      if (!Object.prototype.hasOwnProperty.call(rawConfig, sourceKey)) continue;
      migratedConfig.sourceDirectNodes = normalizeNodeNameList(rawConfig[sourceKey]);
      migrated = true;
      pushMigratedKey(sourceKey, "sourceDirectNodes");
      break;
    }
  }

  if (!Object.prototype.hasOwnProperty.call(migratedConfig, "logWriteClientIp") && Reflect.get(rawConfig, "logIncludeClientIp") !== undefined) {
    migratedConfig.logWriteClientIp = rawConfig.logIncludeClientIp !== false;
    migrated = true;
    pushMigratedKey("logIncludeClientIp", "logWriteClientIp");
  }
  if (!Object.prototype.hasOwnProperty.call(migratedConfig, "logDisplayClientIp") && Reflect.get(rawConfig, "logIncludeClientIp") !== undefined) {
    migratedConfig.logDisplayClientIp = rawConfig.logIncludeClientIp !== false;
    migrated = true;
    pushMigratedKey("logIncludeClientIp", "logDisplayClientIp");
  }
  if (!Object.prototype.hasOwnProperty.call(migratedConfig, "logWriteColo") && Reflect.get(rawConfig, "logIncludeColo") !== undefined) {
    migratedConfig.logWriteColo = rawConfig.logIncludeColo !== false;
    migrated = true;
    pushMigratedKey("logIncludeColo", "logWriteColo");
  }
  if (!Object.prototype.hasOwnProperty.call(migratedConfig, "logDisplayColo") && Reflect.get(rawConfig, "logIncludeColo") !== undefined) {
    migratedConfig.logDisplayColo = rawConfig.logIncludeColo !== false;
    migrated = true;
    pushMigratedKey("logIncludeColo", "logDisplayColo");
  }
  if (!Object.prototype.hasOwnProperty.call(migratedConfig, "logWriteUa") && Reflect.get(rawConfig, "logIncludeUa") !== undefined) {
    migratedConfig.logWriteUa = rawConfig.logIncludeUa !== false;
    migrated = true;
    pushMigratedKey("logIncludeUa", "logWriteUa");
  }
  if (!Object.prototype.hasOwnProperty.call(migratedConfig, "logDisplayUa") && Reflect.get(rawConfig, "logIncludeUa") !== undefined) {
    migratedConfig.logDisplayUa = rawConfig.logIncludeUa !== false;
    migrated = true;
    pushMigratedKey("logIncludeUa", "logDisplayUa");
  }

  if (!Object.prototype.hasOwnProperty.call(migratedConfig, "protocolStrategy")) {
    let usedLegacyProtocolStrategy = false;
    for (const sourceKey of CONFIG_PROTOCOL_STRATEGY_LEGACY_FIELDS) {
      if (!Object.prototype.hasOwnProperty.call(rawConfig, sourceKey)) continue;
      pushMigratedKey(sourceKey, "protocolStrategy");
      usedLegacyProtocolStrategy = true;
    }
    if (usedLegacyProtocolStrategy) {
      migratedConfig.protocolStrategy = resolveProtocolStrategyFromLegacyConfig(rawConfig);
      migrated = true;
    }
  }

  if (!Object.prototype.hasOwnProperty.call(migratedConfig, "defaultPlaybackInfoMode")) {
    if (Reflect.get(rawConfig, "playbackInfoAutoProxy") !== undefined) {
      migratedConfig.defaultPlaybackInfoMode = resolveDefaultPlaybackInfoModeFromLegacyConfig(rawConfig);
      migrated = true;
      pushMigratedKey("playbackInfoAutoProxy", "defaultPlaybackInfoMode");
    } else if (Reflect.get(rawConfig, "playbackInfoBlockWangpanProxy") !== undefined) {
      migratedConfig.defaultPlaybackInfoMode = resolveDefaultPlaybackInfoModeFromLegacyConfig(rawConfig);
      migrated = true;
      pushMigratedKey("playbackInfoBlockWangpanProxy", "defaultPlaybackInfoMode");
    }
  }

  if (!Object.prototype.hasOwnProperty.call(migratedConfig, "tgDailyReportClockTimes")) {
    migratedConfig.tgDailyReportClockTimes = normalizeScheduleClockTimeList(
      Object.prototype.hasOwnProperty.call(rawConfig, "tgDailyReportTime")
        ? rawConfig.tgDailyReportTime
        : rawConfig.tgDailyReportClockTimes,
      Config.Defaults.TgDailyReportClockTimes
    );
    if (Object.prototype.hasOwnProperty.call(rawConfig, "tgDailyReportTime")) {
      migrated = true;
      pushMigratedKey("tgDailyReportTime", "tgDailyReportClockTimes");
    }
  }

  for (const legacyKey of CONFIG_LEGACY_MIGRATION_SOURCE_FIELDS) {
    if (!Object.prototype.hasOwnProperty.call(migratedConfig, legacyKey)) continue;
    delete migratedConfig[legacyKey];
    migrated = true;
  }

  return {
    config: migratedConfig,
    migrated,
    legacyKeysPresent: normalizeDistinctConfigKeyList(legacyKeysPresent),
    deletedLegacyFieldCount: normalizeDistinctConfigKeyList(legacyKeysPresent).length,
    migratedConfigKeys: normalizeDistinctConfigKeyList(migratedConfigKeys),
    migratedKeyMap: Object.fromEntries(
      Object.entries(migratedKeyMap).map(([key, targets]) => [key, normalizeDistinctConfigKeyList(targets)])
    )
  };
}

function sanitizeRuntimeConfig(input = {}) {
  const rawConfig = input && typeof input === "object" && !Array.isArray(input) ? input : {};
  const { config: migratedRawConfig } = migrateRuntimeConfigLegacyAliases(rawConfig);
  const sanitized = sanitizeConfigWithRules({
    ...migratedRawConfig,
    defaultPlaybackInfoMode: hasOwnConfigKey(migratedRawConfig, "defaultPlaybackInfoMode")
      ? Reflect.get(migratedRawConfig, "defaultPlaybackInfoMode")
      : resolveDefaultPlaybackInfoModeFromLegacyConfig(migratedRawConfig),
    protocolStrategy: hasOwnConfigKey(migratedRawConfig, "protocolStrategy")
      ? Reflect.get(migratedRawConfig, "protocolStrategy")
      : resolveProtocolStrategyFromLegacyConfig(migratedRawConfig)
  }, CONFIG_SANITIZE_RULES, { normalizeNodeNameList });
  for (const legacyKey of CONFIG_LEGACY_MIGRATION_SOURCE_FIELDS) {
    delete sanitized[legacyKey];
  }
  sanitized.prewarmDepth = normalizePrewarmDepth(sanitized.prewarmDepth);
  sanitized.hedgeProbePath = normalizeHedgeProbePath(sanitized.hedgeProbePath, DEFAULT_HEDGE_PROBE_PATH);
  sanitized.dnsDefaultFallbackCname = normalizeDnsFallbackCnameConfigValue(sanitized.dnsDefaultFallbackCname);
  sanitized.settingsExperienceMode = String(sanitized.settingsExperienceMode || '').trim().toLowerCase() === 'expert' ? 'expert' : 'novice';
  sanitized.cfQuotaPlanOverride = normalizeCloudflareQuotaPlanOverride(sanitized.cfQuotaPlanOverride);
  sanitized.logSearchMode = normalizeLogSearchMode(sanitized.logSearchMode);
  sanitized.logWriteMode = normalizeLogWriteMode(sanitized.logWriteMode);
  sanitized.routingDecisionMode = normalizeRoutingDecisionMode(sanitized.routingDecisionMode);
  sanitized.protocolStrategy = normalizeProtocolStrategy(sanitized.protocolStrategy);
  sanitized.defaultPlaybackInfoMode = normalizeDefaultPlaybackInfoMode(sanitized.defaultPlaybackInfoMode);
  sanitized.defaultRealClientIpMode = normalizeDefaultRealClientIpMode(sanitized.defaultRealClientIpMode);
  sanitized.defaultMediaAuthMode = normalizeDefaultMediaAuthMode(sanitized.defaultMediaAuthMode);
  sanitized.scheduleUtcOffsetMinutes = normalizeScheduleUtcOffsetMinutes(sanitized.scheduleUtcOffsetMinutes);
  sanitized.tgDailyReportClockTimes = normalizeScheduleClockTimeList(sanitized.tgDailyReportClockTimes, Config.Defaults.TgDailyReportClockTimes);
  applyDailyTelegramReportKindCompat(sanitized, migratedRawConfig);
  delete sanitized.tgDailyReportTime;
  return sanitized;
}

function normalizeDistinctConfigKeyList(values = []) {
  const list = Array.isArray(values) ? values : [values];
  const result = [];
  const seen = new Set();
  for (const value of list) {
    const key = String(value || "").trim();
    if (!key || seen.has(key)) continue;
    seen.add(key);
    result.push(key);
  }
  return result;
}

function collectLegacyRuntimeConfigState(input = {}) {
  const migrationState = migrateRuntimeConfigLegacyAliases(input);
  return {
    legacyKeysPresent: migrationState.legacyKeysPresent,
    deletedLegacyFieldCount: migrationState.deletedLegacyFieldCount,
    migratedConfigKeys: migrationState.migratedConfigKeys,
    migratedKeyMap: migrationState.migratedKeyMap
  };
}

function migrateLegacyRuntimeConfig(input = {}) {
  const migrationState = migrateRuntimeConfigLegacyAliases(input);
  return {
    cleanedConfig: sanitizeRuntimeConfig(migrationState.config),
    legacyKeysPresent: migrationState.legacyKeysPresent,
    deletedLegacyFieldCount: migrationState.deletedLegacyFieldCount,
    migratedConfigKeys: migrationState.migratedConfigKeys,
    migratedKeyMap: migrationState.migratedKeyMap
  };
}

function normalizeConfigSnapshotChangedKeys(changedKeys = []) {
  const normalizedChangedKeys = [];
  const removedLegacyKeys = [];
  const seen = new Set();
  for (const rawKey of Array.isArray(changedKeys) ? changedKeys : []) {
    const key = String(rawKey || "").trim();
    if (!key) continue;
    const mappedKeys = CONFIG_SNAPSHOT_CHANGED_KEY_MIGRATIONS[key];
    if (Array.isArray(mappedKeys) && mappedKeys.length) {
      removedLegacyKeys.push(key);
      for (const mappedKey of mappedKeys) {
        if (!mappedKey || seen.has(mappedKey)) continue;
        seen.add(mappedKey);
        normalizedChangedKeys.push(mappedKey);
      }
      continue;
    }
    if (CONFIG_LEGACY_SNAPSHOT_DROP_KEY_SET.has(key)) {
      removedLegacyKeys.push(key);
      continue;
    }
    if (seen.has(key)) continue;
    seen.add(key);
    normalizedChangedKeys.push(key);
  }
  return {
    changedKeys: normalizedChangedKeys,
    removedLegacyKeys: normalizeDistinctConfigKeyList(removedLegacyKeys)
  };
}

function rewriteConfigSnapshotToCurrentSchema(snapshot) {
  if (!snapshot || typeof snapshot !== "object" || Array.isArray(snapshot)) {
    return {
      snapshot,
      rewritten: false,
      deletedLegacyFieldCount: 0,
      migratedConfigKeys: []
    };
  }
  const snapshotConfig = snapshot.config && typeof snapshot.config === "object" && !Array.isArray(snapshot.config) ? snapshot.config : {};
  const configMigration = migrateLegacyRuntimeConfig(snapshotConfig);
  const changedKeyMigration = normalizeConfigSnapshotChangedKeys(snapshot.changedKeys);
  const nextSnapshot = {
    ...snapshot,
    changedKeys: changedKeyMigration.changedKeys,
    changeCount: changedKeyMigration.changedKeys.length,
    config: configMigration.cleanedConfig
  };
  const previousChangedKeys = Array.isArray(snapshot.changedKeys) ? snapshot.changedKeys : [];
  const previousChangeCount = Number(snapshot.changeCount) || previousChangedKeys.length || 0;
  const rewritten = serializeConfigValue(snapshot.config || {}) !== serializeConfigValue(nextSnapshot.config)
    || serializeConfigValue(previousChangedKeys) !== serializeConfigValue(nextSnapshot.changedKeys)
    || previousChangeCount !== nextSnapshot.changeCount;
  return {
    snapshot: nextSnapshot,
    rewritten,
    deletedLegacyFieldCount: configMigration.deletedLegacyFieldCount + changedKeyMigration.removedLegacyKeys.length,
    migratedConfigKeys: configMigration.migratedConfigKeys
  };
}

function classifyLogResourceScope(requestPath = "", category = "") {
  const path = String(requestPath || "").trim().toLowerCase();
  const normalizedCategory = String(category || "").trim().toLowerCase();
  if (normalizedCategory === "image" || path.includes("/images/") || path.includes("/emby/covers/") || /\.(jpe?g|png|webp|gif)(?:$|[?#])/.test(path)) {
    return "image_poster";
  }
  if (path.includes("/sessions/playing") || path.includes("/playbackinfo")) return "playback_info";
  if (path.includes("/users/authenticate")) return "auth";
  if (path.includes("/items/") || path.includes("/shows/") || path.includes("/movies/") || path.includes("/users/")) {
    return "media_metadata";
  }
  return normalizedCategory || "api";
}

function isPlaybackInfoLogRequest(requestPath = "", category = "") {
  return classifyLogResourceScope(requestPath, category) === "playback_info";
}

function isVideoStreamLogRequest(requestPath = "", category = "") {
  const path = String(requestPath || "").trim().toLowerCase();
  const normalizedCategory = String(category || "").trim().toLowerCase();
  if (normalizedCategory === "stream" || normalizedCategory === "segment" || normalizedCategory === "manifest") return true;
  return /\/stream(?:$|[/?])/.test(path)
    || path.includes("/master.m3u8")
    || /\/videos\/[^/]+\/(?:original|download|file)(?:$|[/?])/.test(path)
    || /\/items\/[^/]+\/download(?:$|[/?])/.test(path)
    || path.includes("static=true")
    || path.includes("download=true");
}

function serializeConfigValue(value) {
  if (Array.isArray(value)) return JSON.stringify(value);
  if (isPlainObject(value)) return JSON.stringify(value);
  if (value === undefined) return "";
  return JSON.stringify(value);
}

function buildRevisionValue(hash = "", updatedAt = "") {
  const safeHash = String(hash || "").trim() || "empty";
  const safeUpdatedAt = String(updatedAt || "").trim() || new Date().toISOString();
  return `${safeUpdatedAt}.${safeHash}`;
}

function buildHashedMetaPayload(payload, extra = {}) {
  const serialized = serializeConfigValue(payload);
  const hash = hashStableText(serialized);
  const updatedAt = String(extra.updatedAt || "").trim() || new Date().toISOString();
  return {
    ...extra,
    hash,
    updatedAt,
    revision: buildRevisionValue(hash, updatedAt)
  };
}

function getConfigDiffEntries(prevConfig = {}, nextConfig = {}) {
  const prev = sanitizeRuntimeConfig(prevConfig);
  const next = sanitizeRuntimeConfig(nextConfig);
  const keys = [...new Set([...Object.keys(prev), ...Object.keys(next)])].sort();
  const entries = [];
  for (const key of keys) {
    if (serializeConfigValue(prev[key]) === serializeConfigValue(next[key])) continue;
    entries.push({
      key,
      previousValue: prev[key],
      nextValue: next[key]
    });
  }
  return entries;
}

function collectPreviewSampleStrings(values = [], limit = 20) {
  const maxItems = Math.max(1, Number(limit) || 20);
  return [...new Set((Array.isArray(values) ? values : [values])
    .map(value => String(value ?? "").trim())
    .filter(Boolean))].slice(0, maxItems);
}

function createTidyPreviewGroup(key = "", label = "", values = [], options = {}) {
  const samples = collectPreviewSampleStrings(values, options.limit);
  const rawCount = Number(options.count);
  const count = Number.isFinite(rawCount)
    ? Math.max(0, Math.floor(rawCount))
    : samples.length;
  const note = String(options.note || "").trim();
  return {
    key: String(key || "").trim(),
    label: String(label || "").trim(),
    count,
    samples,
    truncated: count > samples.length,
    note
  };
}

function pushTidyPreviewGroup(groups, enabled, key = "", label = "", values = [], count = 0, note = "") {
  if (!enabled) return groups;
  groups.push(createTidyPreviewGroup(key, label, values, { count, note }));
  return groups;
}

function buildKvTidyFieldGroups(payload = {}) {
  const fieldGroups = [];
  const configFieldTargets = normalizeDistinctConfigKeyList(payload.configFieldTargets || []);
  if (configFieldTargets.length > 0) {
    const configNoteParts = [];
    if (payload.sourceDirectNodesFromLegacyNodes === true) {
      configNoteParts.push("包含节点遗留直连标记折叠进 sourceDirectNodes");
    }
    if (Number(payload.rewrittenSnapshotCount) > 0) {
      configNoteParts.push(`会同步迁移 ${Math.max(0, Math.floor(Number(payload.rewrittenSnapshotCount) || 0))} 份旧快照中的相关配置字段`);
    }
    fieldGroups.push(createTidyPreviewGroup("config_current_fields", "全局设置当前字段", configFieldTargets, {
      count: configFieldTargets.length,
      note: configNoteParts.join("；") || "会把旧版配置别名收敛到当前 schema。"
    }));
  }

  const migratedTopLevelPortNodeCount = Math.max(0, Math.floor(Number(payload.migratedTopLevelPortNodeCount) || 0));
  const migratedLinePortCount = Math.max(0, Math.floor(Number(payload.migratedLinePortCount) || 0));
  const migratedDefaultPortNodeCount = Math.max(0, Math.floor(Number(payload.migratedDefaultPortNodeCount) || 0));
  const migratedDefaultPortLineCount = Math.max(0, Math.floor(Number(payload.migratedDefaultPortLineCount) || 0));
  if (migratedTopLevelPortNodeCount > 0 || migratedLinePortCount > 0 || migratedDefaultPortNodeCount > 0 || migratedDefaultPortLineCount > 0) {
    const nodeNoteParts = [];
    if (migratedTopLevelPortNodeCount > 0) nodeNoteParts.push(`旧版顶层 node.port 节点 ${migratedTopLevelPortNodeCount} 个`);
    if (migratedLinePortCount > 0) nodeNoteParts.push(`旧版 lines[].port 线路 ${migratedLinePortCount} 条`);
    if (migratedDefaultPortNodeCount > 0) nodeNoteParts.push(`隐式默认端口节点 ${migratedDefaultPortNodeCount} 个`);
    if (migratedDefaultPortLineCount > 0) nodeNoteParts.push(`按协议补齐默认端口线路 ${migratedDefaultPortLineCount} 条`);
    fieldGroups.push(createTidyPreviewGroup("node_current_fields", "节点当前字段", ["lines[].target"], {
      count: 1,
      note: `会把端口统一收敛到当前字段。${nodeNoteParts.join("，")}。`
    }));
  }

  return fieldGroups;
}

function collectTidyPreviewNames(values = []) {
  return (Array.isArray(values) ? values : []).map(value => value?.name || value?.id);
}

function classifyCloudflareAnalyticsError(message, options = {}) {
  const raw = String(message || "").trim();
  const lower = raw.toLowerCase();
  const zoneId = String(options.zoneId || "").trim();
  const result = {
    status: "CF 查询失败",
    hint: "Cloudflare 查询失败，请检查 Zone ID、API 令牌与资源范围",
    detail: raw || (zoneId ? `当前查询的 Zone ID: ${zoneId}` : "")
  };
  if (!raw) return result;
  if (lower.includes("unknown field") || lower.includes("unknown enum") || lower.includes("error parsing args")) {
    return {
      status: "Schema 不兼容",
      hint: "当前账号可用的 GraphQL schema 与脚本查询字段不一致",
      detail: raw
    };
  }
  if (lower.includes("cf_graphql_http_429") || lower.includes("rate limit") || lower.includes("too many requests")) {
    return {
      status: "请求过于频繁",
      hint: "Cloudflare GraphQL 已限流，请稍后再试",
      detail: raw
    };
  }
  if (lower.includes("invalid token") || lower.includes("authentication") || lower.includes("cf_graphql_http_401")) {
    return {
      status: "令牌无效",
      hint: "Cloudflare API 令牌无效，或未启用 GraphQL Analytics 访问",
      detail: raw
    };
  }
  if (lower.includes("not authorized") || lower.includes("permission") || lower.includes("forbidden") || lower.includes("unauthorized") || lower.includes("cf_graphql_http_403")) {
    return {
      status: "权限或范围不匹配",
      hint: "令牌权限不足，或 Account / Zone Resources 未覆盖当前查询",
      detail: raw + (zoneId ? ` | Zone ID: ${zoneId}` : "")
    };
  }
  if (lower.includes("zone") && (lower.includes("not found") || lower.includes("invalid") || lower.includes("unknown"))) {
    return {
      status: "Zone ID 无效",
      hint: "Zone ID 无效，或当前令牌无法访问这个 Zone",
      detail: raw + (zoneId ? ` | Zone ID: ${zoneId}` : "")
    };
  }
  if (lower.includes("cf_graphql_http_400")) {
    return {
      status: "请求参数无效",
      hint: "GraphQL 请求参数无效，请检查 Zone ID 与筛选条件",
      detail: raw + (zoneId ? ` | Zone ID: ${zoneId}` : "")
    };
  }
  return result;
}

async function getRuntimeConfig(env) {
  const kv = Auth.getKV(env);
  if (!kv) return {};
  const now = nowMs();
  const cacheNamespace = String(
    env?.__CONFIG_CACHE_NAMESPACE
    || env?.__WORKER_CACHE_SCOPE
    || (env?.ENI_KV ? "ENI_KV" : "")
    || (env?.KV ? "KV" : "")
    || (env?.EMBY_KV ? "EMBY_KV" : "")
    || (env?.EMBY_PROXY ? "EMBY_PROXY" : "")
    || "default"
  );
  const cachedConfig = GLOBALS.ConfigCache && GLOBALS.ConfigCache.namespace === cacheNamespace
    ? GLOBALS.ConfigCache.data
    : null;
  if (GLOBALS.ConfigCache && GLOBALS.ConfigCache.exp > now && GLOBALS.ConfigCache.data && GLOBALS.ConfigCache.namespace === cacheNamespace) return GLOBALS.ConfigCache.data;
  let config = cachedConfig && typeof cachedConfig === "object" ? cachedConfig : {};
  try {
    const rawConfig = await kv.get(Database.CONFIG_KEY, { type: "json" }) || {};
    const migrationState = migrateRuntimeConfigLegacyAliases(rawConfig);
    config = sanitizeRuntimeConfig(migrationState.config);
    if (migrationState.migrated === true) {
      await withNonCriticalFallback(
        kv.put(Database.CONFIG_KEY, JSON.stringify(config)),
        "runtime_config.persist_migration",
        { cacheNamespace, configKey: Database.CONFIG_KEY },
        null
      );
    }
  } catch (error) {
    const hasCachedConfig = cachedConfig && typeof cachedConfig === "object";
    logRuntimeFailure("runtime_config.load_failed", error, {
      cacheNamespace,
      configKey: Database.CONFIG_KEY,
      usedCachedConfig: hasCachedConfig === true
    });
    config = hasCachedConfig ? cachedConfig : sanitizeRuntimeConfig({});
  }
  GLOBALS.ConfigCache = { data: config, exp: now + 60000, namespace: cacheNamespace };
  return config;
}

async function getRuntimeConfigStrict(env) {
  const kv = Auth.getKV(env);
  if (!kv) return {};
  const rawConfig = await kvGetStrict(kv, Database.CONFIG_KEY, { type: "json" }) || {};
  const migrationState = migrateRuntimeConfigLegacyAliases(rawConfig);
  return sanitizeRuntimeConfig(migrationState.config);
}

function parseCookieHeader(cookieHeader) {
  const map = new Map();
  if (!cookieHeader || typeof cookieHeader !== "string") return map;
  for (const rawPart of cookieHeader.split(";")) {
    const part = rawPart.trim();
    if (!part) continue;
    const eqIndex = part.indexOf("=");
    const key = (eqIndex === -1 ? part : part.slice(0, eqIndex)).trim();
    const value = eqIndex === -1 ? "" : part.slice(eqIndex + 1).trim();
    if (!key) continue;
    map.set(key, value);
  }
  return map;
}

function serializeCookieMap(cookieMap) {
  const parts = [];
  for (const [key, value] of cookieMap.entries()) {
    parts.push(value === "" ? key : `${key}=${value}`);
  }
  return parts.join("; ");
}

function stripCookieHeaderNames(cookieHeader, blockedCookieNames = []) {
  const blocked = new Set((Array.isArray(blockedCookieNames) ? blockedCookieNames : [blockedCookieNames])
    .map(name => String(name || "").trim().toLowerCase())
    .filter(Boolean));
  const cookieMap = parseCookieHeader(cookieHeader);
  if (blocked.size > 0) {
    for (const key of [...cookieMap.keys()]) {
      if (blocked.has(String(key).trim().toLowerCase())) cookieMap.delete(key);
    }
  }
  const result = serializeCookieMap(cookieMap);
  return result || null;
}

function mergeAndSanitizeCookieHeaders(baseCookieHeader, extraCookieHeader, blockedCookieNames = ["auth_token"]) {
  const blocked = new Set(blockedCookieNames.map(name => String(name || "").trim().toLowerCase()).filter(Boolean));
  const merged = parseCookieHeader(baseCookieHeader);
  for (const key of [...merged.keys()]) {
    if (blocked.has(String(key).trim().toLowerCase())) merged.delete(key);
  }
  const extra = parseCookieHeader(extraCookieHeader);
  for (const [key, value] of extra.entries()) {
    if (blocked.has(String(key).trim().toLowerCase())) continue;
    merged.set(key, value);
  }
  const result = serializeCookieMap(merged);
  return result || null;
}

function isLegacyProxyContextFallbackPath(pathname = "") {
  const normalizedPathname = sanitizeProxyPath(pathname);
  const segments = normalizedPathname.split("/").filter(Boolean);
  if (segments.length === 0) return false;
  const topLevel = safeDecodeSegment(segments[0]).toLowerCase();
  return LEGACY_PROXY_CONTEXT_FALLBACK_ROOTS.has(topLevel);
}

async function buildLegacyProxyContextCookieValue(nodeName = "", requestHost = "", env = null, options = {}) {
  const normalizedNodeName = String(nodeName || "").trim().toLowerCase();
  const normalizedRequestHost = normalizeHostnameText(requestHost);
  const jwtSecret = String(env?.JWT_SECRET || "").trim();
  if (!normalizedNodeName || !normalizedRequestHost || !jwtSecret) return "";
  const issuedAt = Math.max(0, Math.floor(Number(options.nowMs ?? nowMs()) / 1000));
  const maxAgeSec = Math.max(1, Math.trunc(Number(options.maxAgeSec) || LEGACY_PROXY_CONTEXT_COOKIE_MAX_AGE_SEC));
  const payloadPart = encodeBase64UrlUtf8(JSON.stringify({
    v: LEGACY_PROXY_CONTEXT_COOKIE_VERSION,
    node: normalizedNodeName,
    host: normalizedRequestHost,
    iat: issuedAt,
    exp: issuedAt + maxAgeSec
  }));
  if (!payloadPart) return "";
  const signature = await Auth.sign(jwtSecret, payloadPart);
  if (!signature) return "";
  return `${payloadPart}.${signature}`;
}

async function parseLegacyProxyContextCookieValue(cookieValue = "", env = null, options = {}) {
  const rawCookieValue = String(cookieValue || "").trim();
  const jwtSecret = String(env?.JWT_SECRET || "").trim();
  if (!rawCookieValue) return { ok: false, reason: "missing_cookie" };
  if (!jwtSecret) return { ok: false, reason: "missing_secret" };
  const dotIndex = rawCookieValue.indexOf(".");
  if (dotIndex <= 0 || dotIndex === rawCookieValue.length - 1) {
    return { ok: false, reason: "malformed_cookie" };
  }
  const payloadPart = rawCookieValue.slice(0, dotIndex);
  const signaturePart = rawCookieValue.slice(dotIndex + 1);
  const expectedSignature = await Auth.sign(jwtSecret, payloadPart);
  if (!expectedSignature || signaturePart !== expectedSignature) {
    return { ok: false, reason: "bad_signature" };
  }
  let parsedPayload = null;
  try {
    parsedPayload = JSON.parse(decodeBase64UrlUtf8(payloadPart));
  } catch {
    return { ok: false, reason: "malformed_payload" };
  }
  const payload = {
    v: Number(parsedPayload?.v) || 0,
    node: String(parsedPayload?.node || "").trim().toLowerCase(),
    host: normalizeHostnameText(parsedPayload?.host || ""),
    iat: Math.max(0, Math.floor(Number(parsedPayload?.iat) || 0)),
    exp: Math.max(0, Math.floor(Number(parsedPayload?.exp) || 0))
  };
  if (payload.v !== LEGACY_PROXY_CONTEXT_COOKIE_VERSION || !payload.node || !payload.host || !payload.iat || !payload.exp || payload.exp <= payload.iat) {
    return { ok: false, reason: "invalid_payload", payload };
  }
  const requestHost = normalizeHostnameText(options.requestHost || "");
  if (requestHost && payload.host !== requestHost) {
    return { ok: false, reason: "host_mismatch", payload };
  }
  const nowSeconds = Math.max(0, Math.floor(Number(options.nowMs ?? nowMs()) / 1000));
  if (payload.exp <= nowSeconds) {
    return { ok: false, reason: "expired", payload };
  }
  return { ok: true, payload };
}

function buildLegacyProxyContextSetCookie(cookieValue = "") {
  const normalizedCookieValue = String(cookieValue || "").trim();
  if (!normalizedCookieValue) return buildLegacyProxyContextClearCookie();
  return `${LEGACY_PROXY_CONTEXT_COOKIE_NAME}=${normalizedCookieValue}; Path=/; HttpOnly; Secure; SameSite=Lax; Max-Age=${LEGACY_PROXY_CONTEXT_COOKIE_MAX_AGE_SEC}`;
}

function buildLegacyProxyContextClearCookie() {
  return `${LEGACY_PROXY_CONTEXT_COOKIE_NAME}=; Path=/; HttpOnly; Secure; SameSite=Lax; Max-Age=0; Expires=Thu, 01 Jan 1970 00:00:00 GMT`;
}

function hasEmbyWebBypassCookie(cookieHeader = "") {
  return String(parseCookieHeader(cookieHeader).get(EMBY_WEB_BYPASS_COOKIE_NAME) || "").trim() === "1";
}

function buildEmbyWebBypassSetCookie() {
  return `${EMBY_WEB_BYPASS_COOKIE_NAME}=1; Path=/; HttpOnly; Secure; SameSite=Lax; Max-Age=${EMBY_WEB_BYPASS_COOKIE_MAX_AGE_SEC}`;
}

function buildWebAccessGuideResponse(requestUrl, requestMethod = "GET", dynamicCors = null) {
  const currentUrl = requestUrl instanceof URL ? new URL(requestUrl.toString()) : new URL(String(requestUrl || ""));
  const backupUrl = new URL(currentUrl.toString());
  const homeUrl = new URL("/", currentUrl);
  backupUrl.searchParams.set(EMBY_WEB_BYPASS_QUERY_PARAM, "1");
  const html = `<!DOCTYPE html><html lang="zh-CN"><head><meta charset="UTF-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>Emby Web 备用模式</title><style>:root{color-scheme:dark}*{box-sizing:border-box}body{margin:0;min-height:100vh;display:flex;align-items:center;justify-content:center;padding:24px;background:radial-gradient(circle at top,#1e293b 0,#0f172a 45%,#020617 100%);color:#e2e8f0;font-family:system-ui,-apple-system,BlinkMacSystemFont,"Segoe UI",sans-serif}.panel{width:min(100%,440px);background:rgba(15,23,42,.88);border:1px solid rgba(148,163,184,.2);border-radius:24px;padding:32px;box-shadow:0 24px 80px rgba(15,23,42,.45)}h1{margin:0 0 14px;font-size:24px;line-height:1.3}p{margin:0 0 14px;color:#cbd5e1;line-height:1.7}.muted{font-size:13px;color:#94a3b8}.actions{display:flex;flex-direction:column;gap:12px;margin-top:28px}.btn{display:inline-flex;align-items:center;justify-content:center;width:100%;padding:12px 18px;border-radius:14px;text-decoration:none;font-weight:700;transition:transform .15s ease,filter .15s ease}.btn:hover{transform:translateY(-1px);filter:brightness(1.05)}.btn-primary{background:#22c55e;color:#052e16}.btn-secondary{border:1px solid rgba(148,163,184,.25);color:#e2e8f0;background:rgba(30,41,59,.55)}code{word-break:break-all;background:rgba(15,23,42,.92);padding:2px 6px;border-radius:8px;color:#93c5fd}@media (max-width:520px){body{padding:16px}.panel{padding:24px}}</style></head><body><main class="panel"><h1>Emby Web 默认处于 API 优先模式</h1><p>当前代理默认优先面向客户端 API 与媒体请求，Web 页面首次访问需要额外确认后才会放行。</p><p>点击下方按钮后，Worker 会为当前浏览器写入 24 小时的 Web 临时授权 Cookie，并立即返回原始页面。</p><p class="muted">当前地址：<code>${escapeHtml(currentUrl.toString())}</code></p><div class="actions"><a class="btn btn-primary" href="${escapeHtml(backupUrl.toString())}">启用 Web 备用模式（24 小时）</a><a class="btn btn-secondary" href="${escapeHtml(homeUrl.toString())}">返回站点首页</a></div></main></body></html>`;
  const headers = dynamicCors ? new Headers(dynamicCors) : new Headers();
  headers.set("Content-Type", "text/html;charset=UTF-8");
  headers.set("Cache-Control", "no-store, max-age=0");
  applySecurityHeaders(headers);
  if (headers.get("Access-Control-Allow-Origin") !== "*") mergeVaryHeader(headers, "Origin");
  return new Response(requestMethod === "HEAD" ? null : html, { status: 403, headers });
}

function buildEmbyWebBypassRedirectResponse(requestUrl, dynamicCors = null) {
  const cleanUrl = requestUrl instanceof URL ? new URL(requestUrl.toString()) : new URL(String(requestUrl || ""));
  while (cleanUrl.searchParams.has(EMBY_WEB_BYPASS_QUERY_PARAM)) {
    cleanUrl.searchParams.delete(EMBY_WEB_BYPASS_QUERY_PARAM);
  }
  const headers = dynamicCors ? new Headers(dynamicCors) : new Headers();
  headers.set("Location", cleanUrl.toString());
  headers.set("Cache-Control", "no-store, max-age=0");
  headers.append("Set-Cookie", buildEmbyWebBypassSetCookie());
  applySecurityHeaders(headers);
  if (headers.get("Access-Control-Allow-Origin") !== "*") mergeVaryHeader(headers, "Origin");
  return new Response(null, { status: 302, headers });
}

function jsonHeaders(extra = {}) {
  return { ...SECURITY_RESPONSE_HEADERS, ...corsHeaders, "Content-Type": "application/json; charset=utf-8", "Cache-Control": "no-store, max-age=0", ...extra };
}

function jsonResponse(payload, status = 200, extraHeaders = {}) {
  return new Response(JSON.stringify(payload), { status, headers: jsonHeaders(extraHeaders) });
}

function jsonError(code, message, status = 400, details = null, extraHeaders = {}) {
  const body = { ok: false, error: { code, message } };
  if (details !== null && details !== undefined) body.error.details = details;
  return jsonResponse(body, status, extraHeaders);
}

function isPlainObject(value) {
  return !!value && typeof value === "object" && !Array.isArray(value);
}

function getErrorMessage(error, fallback = "unknown_error") {
  const message = String(error?.message || "").trim();
  if (message) return message;
  const text = String(error || "").trim();
  return text || fallback;
}

function normalizeErrorStatus(status, fallback = 500) {
  const value = Number(status);
  if (Number.isFinite(value) && value >= 400 && value <= 599) return Math.floor(value);
  const fallbackValue = Number(fallback);
  return Number.isFinite(fallbackValue) && fallbackValue >= 400 && fallbackValue <= 599
    ? Math.floor(fallbackValue)
    : 500;
}

function isStructuredAppError(error) {
  if (!error || typeof error !== "object") return false;
  const code = String(error?.code || "").trim();
  const status = Number(error?.status);
  return !!code || (Number.isFinite(status) && status >= 400 && status <= 599);
}

function normalizeAppErrorForResponse(error, fallback = {}) {
  const fallbackStatus = normalizeErrorStatus(fallback?.status, 500);
  const fallbackCode = String(fallback?.code || "INTERNAL_ERROR").trim().toUpperCase() || "INTERNAL_ERROR";
  const fallbackMessage = String(fallback?.message || "Server Error").trim() || "Server Error";
  const structured = isStructuredAppError(error);
  const status = structured ? normalizeErrorStatus(error?.status, fallbackStatus) : fallbackStatus;
  const code = structured
    ? (String(error?.code || fallbackCode).trim().toUpperCase() || fallbackCode)
    : fallbackCode;
  const message = structured
    ? (String(error?.message || fallbackMessage).trim() || fallbackMessage)
    : fallbackMessage;
  const details = structured && error?.details !== undefined
    ? error.details
    : (fallback?.details !== undefined ? fallback.details : null);
  return { status, code, message, details };
}

function createStructuredKvReadError(operation = "get", target = {}, reason = "unknown_error") {
  const normalizedTarget = isPlainObject(target) ? target : {};
  const normalizedOperation = String(operation || "").trim().toLowerCase() === "list" ? "list" : "get";
  const details = {
    dependency: "KV",
    operation: normalizedOperation,
    reason: String(reason || "unknown_error").trim() || "unknown_error"
  };
  const key = String(normalizedTarget.key || "").trim();
  const prefix = String(normalizedTarget.prefix || "").trim();
  if (key) details.key = key;
  if (prefix) details.prefix = prefix;
  return createStructuredConfigError("KV_READ_FAILED", "KV 读取异常", 503, details);
}

function isStructuredKvReadError(error) {
  return isStructuredAppError(error)
    && String(error?.code || "").trim().toUpperCase() === "KV_READ_FAILED"
    && String(error?.details?.dependency || "").trim().toUpperCase() === "KV";
}

function remapStructuredKvReadError(error, code = "INTERNAL_ERROR", message = "Server Error", scope = "admin.read.kv_read_failed") {
  if (!isStructuredKvReadError(error)) return error;
  const mappedError = createStructuredConfigError(code, message, 503, {
    ...(isPlainObject(error?.details) ? error.details : {})
  });
  logRuntimeFailure(scope, mappedError, mappedError.details);
  return mappedError;
}

function remapAdminReadKvError(error, code, message, scopeBase = "admin.read") {
  if (!isStructuredKvReadError(error)) return error;
  const operation = String(error?.details?.operation || "").trim().toLowerCase() === "list" ? "list" : "get";
  const normalizedScopeBase = String(scopeBase || "admin.read").trim() || "admin.read";
  return remapStructuredKvReadError(error, code, message, `${normalizedScopeBase}.kv_${operation}_failed`);
}

function createConfigSnapshotsWriteError(code = "CONFIG_SNAPSHOTS_CLEAR_FAILED", message = "设置快照清理失败：KV 写入异常", details = null) {
  return createStructuredConfigError(code, message, 503, details);
}

async function kvGetStrict(kv, key, options = {}) {
  if (!kv) return null;
  const normalizedKey = String(key || "").trim();
  const readOptions = isPlainObject(options) ? options : {};
  try {
    if (Object.prototype.hasOwnProperty.call(readOptions, "type")) {
      return await kv.get(normalizedKey, { type: readOptions.type });
    }
    return await kv.get(normalizedKey);
  } catch (error) {
    throw createStructuredKvReadError("get", { key: normalizedKey }, getErrorMessage(error));
  }
}

async function kvListStrict(kv, options = {}) {
  if (!kv || typeof kv.list !== "function") return { keys: [], list_complete: true, cursor: "" };
  const listOptions = isPlainObject(options) ? options : {};
  const prefix = String(listOptions.prefix || "").trim();
  const cursor = String(listOptions.cursor || "").trim();
  try {
    return cursor
      ? await kv.list({ prefix, cursor })
      : await kv.list({ prefix });
  } catch (error) {
    throw createStructuredKvReadError("list", { prefix }, getErrorMessage(error));
  }
}

function logRuntimeFailure(scope, error, context = null, level = "warn") {
  const logLevel = level === "error" ? "error" : "warn";
  const normalizedScope = String(scope || "runtime_failure").trim() || "runtime_failure";
  const meta = isPlainObject(context) ? { ...context } : {};
  const errorCode = String(error?.code || "").trim();
  const errorStatus = Number(error?.status);
  if (errorCode) meta.errorCode = errorCode;
  if (Number.isFinite(errorStatus)) meta.errorStatus = Math.floor(errorStatus);
  if (Object.keys(meta).length > 0) console[logLevel](`[${normalizedScope}] ${getErrorMessage(error)}`, meta);
  else console[logLevel](`[${normalizedScope}] ${getErrorMessage(error)}`);
}

async function withNonCriticalFallback(promise, scope, context = null, fallbackValue = null) {
  try {
    return await promise;
  } catch (error) {
    logRuntimeFailure(scope, error, context);
    return fallbackValue;
  }
}

function mergeStatusPatch(base, patch) {
  const source = isPlainObject(base) ? base : {};
  const delta = isPlainObject(patch) ? patch : {};
  const merged = { ...source };
  for (const [key, value] of Object.entries(delta)) {
    if (value === undefined) continue;
    if (isPlainObject(value) && isPlainObject(source[key])) merged[key] = mergeStatusPatch(source[key], value);
    else if (isPlainObject(value)) merged[key] = mergeStatusPatch({}, value);
    else merged[key] = value;
  }
  return merged;
}

async function normalizeJsonApiResponse(response) {
  const headers = new Headers(response.headers || {});
  headers.set("Content-Type", "application/json; charset=utf-8");
  headers.set("Cache-Control", "no-store, max-age=0");
  Object.entries(corsHeaders).forEach(([k, v]) => headers.set(k, v));
  applySecurityHeaders(headers);
  if (response.ok) return new Response(response.body, { status: response.status, headers });
  let payload = null, fallbackText = "";
  try { payload = await response.clone().json(); } catch { fallbackText = await response.text().catch(() => ""); }
  const code = payload?.error?.code || (typeof payload?.error === "string" ? payload.error.toUpperCase() : `HTTP_${response.status}`);
  const message = payload?.error?.message || payload?.message || (typeof payload?.error === "string" ? payload.error : fallbackText || response.statusText || "request_failed");
  const details = payload?.error?.details ?? payload?.details ?? null;
  return jsonError(code, message, response.status || 500, details);
}

const nowMs = () => Date.now();
const sleepMs = (ms) => new Promise(resolve => setTimeout(resolve, Math.max(0, Number(ms) || 0)));

function isAbortLikeError(error) {
  if (!error) return false;
  if (error.name === "AbortError") return true;
  return String(error.message || "").toLowerCase().includes("abort");
}

function createLifecycleAbortError(reason, detail = "") {
  const normalizedReason = String(reason || "request_aborted").trim() || "request_aborted";
  /** @type {AppError} */
  const error = new Error(detail ? `${normalizedReason}_${detail}` : normalizedReason);
  if (normalizedReason === "client_aborted") error.code = "CLIENT_ABORTED";
  else if (normalizedReason === "downstream_cancelled") error.code = "DOWNSTREAM_CANCELLED";
  else if (normalizedReason === "stream_idle_timeout") error.code = "STREAM_IDLE_TIMEOUT";
  else error.code = "REQUEST_ABORTED";
  return error;
}

function createProxyRequestLifecycle(requestSignal) {
  const controller = new AbortController();
  let abortReason = "";
  let requestAbortCleanup = null;
  let activeFetchController = null;
  let activeFetchCleanup = null;
  const abortListeners = new Set();

  const notifyAbortListeners = (reason) => {
    if (!abortListeners.size) return;
    for (const listener of [...abortListeners]) {
      try { listener(reason); } catch {}
    }
  };

  const abort = (reason = "request_aborted") => {
    const normalizedReason = String(reason || "request_aborted").trim() || "request_aborted";
    if (!abortReason) abortReason = normalizedReason;
    if (activeFetchController && !activeFetchController.signal.aborted) {
      try { activeFetchController.abort(abortReason); } catch {}
    }
    if (!controller.signal.aborted) {
      try { controller.abort(abortReason); } catch {}
    }
    notifyAbortListeners(abortReason);
  };

  if (requestSignal && typeof requestSignal.addEventListener === "function") {
    const onRequestAbort = () => abort("client_aborted");
    if (requestSignal.aborted) onRequestAbort();
    else {
      requestSignal.addEventListener("abort", onRequestAbort, { once: true });
      requestAbortCleanup = () => requestSignal.removeEventListener("abort", onRequestAbort);
    }
  }

  return {
    signal: controller.signal,
    abort,
    isAborted() {
      return controller.signal.aborted === true || !!abortReason;
    },
    getAbortReason() {
      return abortReason;
    },
    onAbort(listener) {
      if (typeof listener !== "function") return () => {};
      if (abortReason || controller.signal.aborted) {
        try { listener(abortReason || "request_aborted"); } catch {}
        return () => {};
      }
      abortListeners.add(listener);
      return () => abortListeners.delete(listener);
    },
    setActiveFetchController(fetchController) {
      if (activeFetchCleanup) {
        activeFetchCleanup();
        activeFetchCleanup = null;
      }
      activeFetchController = fetchController || null;
      if (!fetchController) return () => {};

      const relayAbort = () => {
        try { fetchController.abort(abortReason || "request_aborted"); } catch {}
      };

      if (abortReason || controller.signal.aborted) relayAbort();
      else controller.signal.addEventListener("abort", relayAbort, { once: true });

      activeFetchCleanup = () => {
        controller.signal.removeEventListener("abort", relayAbort);
        if (activeFetchController === fetchController) activeFetchController = null;
      };

      return () => {
        if (!activeFetchCleanup) return;
        const cleanup = activeFetchCleanup;
        activeFetchCleanup = null;
        cleanup();
      };
    },
    dispose() {
      if (requestAbortCleanup) {
        requestAbortCleanup();
        requestAbortCleanup = null;
      }
      if (activeFetchCleanup) {
        const cleanup = activeFetchCleanup;
        activeFetchCleanup = null;
        cleanup();
      } else {
        activeFetchController = null;
      }
      abortListeners.clear();
    }
  };
}

function createLinkedAbortController(signals = []) {
  const controller = new AbortController();
  const cleanups = [];
  const relayAbort = (reason = "linked_abort") => {
    if (controller.signal.aborted) return;
    try { controller.abort(reason); } catch {}
  };
  for (const signal of Array.isArray(signals) ? signals : [signals]) {
    if (!signal || typeof signal.addEventListener !== "function") continue;
    const onAbort = () => relayAbort(signal.reason || "linked_abort");
    if (signal.aborted) {
      onAbort();
      continue;
    }
    signal.addEventListener("abort", onAbort, { once: true });
    cleanups.push(() => signal.removeEventListener("abort", onAbort));
  }
  return {
    signal: controller.signal,
    abort(reason = "linked_abort") {
      relayAbort(reason);
    },
    dispose() {
      for (const cleanup of cleanups.splice(0)) {
        try { cleanup(); } catch {}
      }
    }
  };
}

async function waitForPromiseWithinTimeout(promise, timeoutMs, requestLifecycle = null) {
  return await new Promise((resolve, reject) => {
    let settled = false;
    let timeoutId = null;
    let removeAbortListener = () => {};
    const settle = (result) => {
      if (settled) return;
      settled = true;
      if (timeoutId !== null) clearTimeout(timeoutId);
      try { removeAbortListener(); } catch {}
      resolve(result);
    };
    const fail = (error) => {
      if (settled) return;
      settled = true;
      if (timeoutId !== null) clearTimeout(timeoutId);
      try { removeAbortListener(); } catch {}
      reject(error);
    };
    if (requestLifecycle?.onAbort) {
      removeAbortListener = requestLifecycle.onAbort((reason) => fail(createLifecycleAbortError(reason)));
    }
    if (Number(timeoutMs) > 0) {
      timeoutId = setTimeout(() => settle({ timedOut: true, value: null }), Math.max(0, Number(timeoutMs) || 0));
    }
    Promise.resolve(promise).then(
      value => settle({ timedOut: false, value }),
      fail
    );
  });
}

async function sleepWithRequestLifecycle(ms, requestLifecycle = null) {
  const delayMs = Math.max(0, Number(ms) || 0);
  if (delayMs <= 0) return;
  return await new Promise((resolve, reject) => {
    let settled = false;
    let removeAbortListener = () => {};
    const timerId = setTimeout(() => {
      if (settled) return;
      settled = true;
      try { removeAbortListener(); } catch {}
      resolve();
    }, delayMs);
    if (requestLifecycle?.onAbort) {
      removeAbortListener = requestLifecycle.onAbort((reason) => {
        if (settled) return;
        settled = true;
        clearTimeout(timerId);
        reject(createLifecycleAbortError(reason));
      });
    }
  });
}

function setBoundedMapEntry(map, key, value, maxSize) {
  if (map.has(key)) map.delete(key);
  map.set(key, value);
  const limit = Math.floor(Number(maxSize));
  if (!Number.isFinite(limit) || limit < 1) return;
  while (map.size > limit) {
    const oldestKey = map.keys().next().value;
    if (oldestKey === undefined) break;
    map.delete(oldestKey);
  }
}

function touchMapEntry(map, key) {
  if (!map.has(key)) return undefined;
  const value = map.get(key);
  map.delete(key);
  map.set(key, value);
  return value;
}

function clampIntegerConfig(value, fallback, min, max) {
  let num;
  if (typeof value === "number") num = value;
  else if (typeof value === "string") {
    const normalized = value.trim();
    if (!/^-?\d+$/.test(normalized)) return fallback;
    num = Number(normalized);
  } else {
    return fallback;
  }
  if (!Number.isFinite(num)) return fallback;
  return Math.min(max, Math.max(min, Math.floor(num)));
}

function clampNumberConfig(value, fallback, min, max) {
  const num = Number(value);
  if (!Number.isFinite(num)) return fallback;
  return Math.min(max, Math.max(min, num));
}

