      action: "PROXY",
      dataPlaneMode: "worker_proxy_follow",
      nextMethod,
      nextBodyMode,
      isSameOriginRedirect,
      preserveWorkerProxy: false,
      reason: "proxy_follow",
      traceAction: "proxy",
      redirectStatus: options.redirectStatus || policy.currentStatus,
