      probeWinnerTargetKey: String(entry.lastProbeResult?.status || "") === "ok"
        ? String(entry.lastProbeResult?.winnerTargetKey || "").trim()
        : "",
      lastProbeResult: entry.lastProbeResult && typeof entry.lastProbeResult === "object"
        ? { ...entry.lastProbeResult }
        : null,
      inFlightProbe: entry.inFlightProbe
